window.ASBAB_NUZUL_CACHE["5"] = {"asbab_nuzul":{"6":[{"ar":"عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ ﷺ قَالَتْ: خَرَجْنَا مَعَ رَسُولِ اللّهِ ﷺ فِي بَعْضِ أَسْفَارِهِ، حَتَّى إِذَا كُنَّا بِالْبَيْدَاءِ أَوْ بِذَاتِ الْجَيْشِ انْقَطَعَ عِقْدٌ لِي، فَأَقَامَ رَسُولُ اللّهِ ﷺ عَلَى الْتِمَاسِهِ، وَأَقَامَ النَّاسُ مَعَهُ، وَلَيْسُوا عَلَى مَاءٍ، فَأَتَى النَّاسُ إِلَى أَبِي بَكْرٍ الصِّدِّيقِ، فَقَالُوا: أَلَا تَرَى مَا صَنَعَتْ عَائِشَةُ؟! أَقَامَتْ بِرَسُولِ اللهِ ﷺ وَالنَّاسِ، وَلَيْسُوا عَلَى مَاءٍ، وَلَيْسَ مَعَهُمْ مَاءٌ!!\n\nفَجَاءَ أَبُو بَكْرٍ وَرَسُولُ اللهِ ﷺ وَاضِعٌ رَأْسَهُ عَلَى فَخِذِي قَدْ نَامَ، فَقَالَ: حَبَسْتِ رَسُولَ اللهِ ﷺ وَالنَّاسَ، وَلَيْسُوا عَلَى مَاءٍ، وَلَيْسَ مَعَهُمْ مَاءٌ! فَقَالَتْ عَائِشَةُ: فَعَاتَبَنِي أَبُو بَكْرٍ، وَقَالَ مَا شَاءَ اللَّهُ أَنْ يَقُولَ، وَجَعَلَ يَطْعُنُنِي بِيَدِهِ فِي خَاصِرَتِي، فَلَا يَمْنَعُنِي مِنْ التَّحَرُّكِ إِلَّا مَكَانُ رَسُولِ اللهِ ﷺ عَلَى فَخِذِي، فَقَامَ رَسُولُ اللهِ ﷺ حِينَ أَصْبَحَ عَلَى غَيْرِ مَاءٍ، فَأَنْزَلَ اللهُ آية التَّيَمُّمِ فَتَيَمَّمُوا، فَقَالَ: أُسَيْدُ بْنُ الْحُضَيْرِ: مَا هِيَ بِأَوَّلِ بَرَكَتِكُمْ يَا آلَ أَبِي بَكْرٍ. قَالَتْ: فَبَعَثْنَا الْبَعِيرَ الَّذِي كُنْتُ عَلَيْهِ، فَأَصَبْنَا الْعِقْدَ تَحْتَه. واللفظ للبخاري.\n\nوجاء عَن ابْنِ عَبَّاسٍ عَنْ عَمَّارِ بْنِ يَاسِرِ شبيهاً به.","id":""}],"33":[{"ar":"عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه: أَنَّ قَوْماً مِنْ عُكْلٍ - أَوْ قَالَ: مِنْ عُرَيْنَةَ - قَدِمُوا عَلَى رَسُولِ اللهِ ﷺ فَاجْتَوَواْ الْمَدِينَةَ، فَأَمَرَ لَهُمْ رَسُولُ اللهِ ﷺ بِلِقَاحٍ وَأَمَرَهُمْ أَنْ يَشْرَبُوا مِنْ أَبْوَالِهَا وَأَلْبَانِهَا، فَانْطَلَقُوا، فَلَمَّا صَحُّوا قَتَلُوا رَاعِيَ رَسُولِ اللهِ ﷺ، وَاسْتَاقُوا النَّعمَ، فَبَلَغَ النَّبِيَّ ﷺ خَبَرُهُمْ مِنْ أَوَّلِ النَّهَارِ، فَأَرْسَلَ النَّبِيُّ ﷺ فِي آثَارِهِمْ، فَمَا ارْتَفع النَّهَارُ حَتَّى جِيءَ بِهِمْ فَأَمَرَ بِهِمْ، فَقُطِعَتْ أَيْدِيهِمْ وَأَرْجُلُهُمْ، وَسُمَرَ أَعْيُنُهُمْ، وَأُلْقُوا فِي الْحَرَّةِ يَسْتَسْقُونَ فَلَا يُسْقَوْنَ، قَالَ أَبُو قِلَابَةَ: فَهَؤُلَاءِ قَوْمٌ سَرَقُوا وَقَتَلُوا، وَكَفَرُوا بَعْدَ أَيْمَانِهِمْ، وَحَارَبُوا اللهَ وَرَسُولَهُ.\n\nوَعَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ بِهَذَا الْحَدِيثِ، قَالَ فِيهِ: فَبَعَثَ رَسُولُ اللهِ ﷺ فِي طَلَبِهِمْ قَافَ��ً، فَأُتِيَ بِهِمْ، قَالَ: فَأَنْزَلَ اللهُ تَبَارَكَ وَتَعَالَى فِي ذَلِكَ: { إِنَّمَا جَزَٰٓؤُا۟ ٱلَّذِينَ يُحَارِبُونَ ٱللَّهَ وَرَسُولَهُۥ وَيَسْعَوْنَ فِى ٱلْأَرْضِ فَسَادًا } الْآيَةَ. واللفظ لأبي داود، وأصل القصة في الصحيحين.","id":""}],"41":[{"ar":"عَنِ الْبَرَاءِ بْنِ عَازِبٍ رضي الله عنهما قَالَ: مُرَّ عَلَى النَّبِيِّ ﷺ بِيَهُودِيٍّ مُحَمَّماً مَجْلُوداً، فَدَعَاهُمْ ﷺ فَقَالَ: « هَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ؟ » قَالُوا: نَعَمْ. فَدَعَا رَجُلًا مِنْ عُلَمَائِهِمْ، فَقَالَ: « أَنْشُدُكَ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى، أَهَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ؟ » قَالَ: لَا، وَلَوْلَا أَنَّكَ نَشَدْتَنِي بِهَذَا لَمْ أُخْبِرْكَ، نَجِدُهُ الرَّجْمَ، وَلَكِنَّهُ كَثُرَ فِي أَشْرَافِنَا، فَكُنَّا إِذَا أَخَذْنَا الشَّرِيفَ تَرَكْنَاهُ، وَإِذَا أَخَذْنَا الضَّعِيفَ أَقَمْنَا عَلَيْهِ الْحَدَّ، قُلْنَا: تَعَالَوْا فَلْنَجْتَمِعْ عَلَى شَيْءٍ نُقِيمُهُ عَلَى الشَّرِيفِ وَالْوَضِيعِ، فَجَعَلْنَا التَّحْمِيمَ وَالْجَلْدَ مَكَانَ الرَّجْمِ، فَقَالَ رَسُولُ اللهِ ﷺ: « اللَّهُمَّ إِنِّي أَوَّلُ مَنْ أَحْيَا أَمْرَكَ إِذْ أَمَاتُوهُ »فَأَمَرَ بِهِ فَرُجِمَ، فَأَنْزَلَ اللهُ عَز و جل: { يَٰٓأَيُّهَا ٱلرَّسُولُ لَا يَحْزُنكَ ٱلَّذِينَ يُسَـٰرِعُونَ فِى ٱلْكُفْرِ } إِلَى قَوْلِهِ { إِنْ أُوتِيتُمْ هَـٰذَا فَخُذُوهُ... } واللفظ لأبي داود.","id":""},{"ar":"عَنْ أَبِي هُرَيْرَةَ رضي اللهِ عنه قَالَ: زَنَى رَجُلٌ مِنْ الْيَهُودِ وَامْرَأَةٌ، فَقَالَ بَعْضُهُمْ لِبَعْضٍ: اذْهَبُوا بِنَا إِلَى هَذَا النَّبِيِّ، فَإِنَّهُ نَبِيٌّ بُعِثَ بِالتَّخْفِيفِ، فَإِنْ أَفْتَانَا بِفُتْيَا دُونَ الرَّجْم قَبِلْنَاهَا وَاحْتَجَجْنَا بِهَا عِنْدَ اللهِ، قُلْنَا: فُتْيَا نَبِيٍّ  مِنْ أَنْبِيَائِكَ، قَالَ: فَأَتَوْا النَّبِيَّ ﷺ وَهُوَ جَالِسٌ فِي الْمَسْجِدِ فِي أَصْحَابِهِ، فَقَالُوا: يَا أَبَا الْقَاسِمِ، مَا تَرَى فِي رَجُلٍ وَامْرَأَةٍ زَنَيَا؟ فَلَمْ يُكَلِّمُهُمْ كَلِمَةً حَتَّى أَتَى بَيْتَ مِدْرَاسِهِمْ، فَقَامَ عَلَى الْبَابِ فَقَالَ: « أَنْشُدُكُمْ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى، مَا تَجِدُونَ فِي التَّوْرَاةِ عَلَى مَنْ زَنَى إِذَا أَحْصَنَ؟ » قَالُوا: يُحَمَّمُ وَيُجَبَّهُ وَيُجْلَدُ، وَالتَّجْبِيةُ أَنْ يُحْمَلَ الزَّانِيَانِ عَلَى حِمَارٍ وَتُقَابَلُ أَقْفِيَتُهُمَا وَيُطَافُ بِهِمَا، قَالَ: وَسَكَتَ شَابٌ مِنْهُمْ فَلَمَّا، رَآهُ النَّبِيُّ ﷺ سَكَتَ أَلَظَّ بِهِ النِّشْدَةَ، فَقَالَ: اللَّهُمَّ إِذْ نَشَدْتَنَا فَإِنَّا نَجِدُ فِي التَّوْرَاةِ الرَّجْمَ. فَقَالَ النَّبِيُّ ﷺ: «فَمَا أَوَّلُ مَا ارْتَخَصْتُمْ أَمْرَ اللهِ»، قَالَ: زَنَى ذُو قَرَابَةٍ مِنْ مَلِكٍ مِنْ مُلُوكِنَا فَأَخَّرَ عَنْهُ الرَّجْمَ، ثُمَّ زَنَى رَجُلٌ فِي أُسْرَةٍ مِنْ النَّاسِ فَأَرَادَ رَجْمَهُ فَحَالَ قَوْمُهُ دُونَهُ، وَقَالُوا: لَا يُرْجَمُ صَاحِبُنَا حَتَّى تَجِيءَ بِصَاحِبِكَ فَتَرْجُمَهُ، فَاصْطَلَحُوا عَلَى هَذِهِ الْعُقُوبَةِ بَيْنَهُمْ، فَقَالَ النَّبِيُّ ﷺ: « فَإِنِّي أَحْكُمُ بِمَا فِي التَّوْرَاةِ »، فَأَمَرَ بِهِمَا فَرُجِمَا. قَالَ الزُّهْرِيُّ: فَبَلَغَنَا أَنَّ هَذِهِ الآيَةَ نَزَلَتْ فِيهِمْ { إِنَّآ أَنزَلْنَا ٱلتَّوْرَىٰةَ فِيهَا هُدًى وَنُورٌ ۚ يَحْكُمُ بِهَا ٱلنَّبِيُّونَ ٱلَّذِينَ أَسْلَمُوا۟ } كَانَ النَّبِيُّ ﷺ مِنْهُمْ. واللفظ لأبي داود.","id":""}],"42":[{"ar":"عن جابر بن عبد الله رضي الله عنهما قال: زنی رجل من أهل فدك، فكتب أهل فدك إلى ناس من اليهود بالمدينة، أن سلوا محمداً عن ذلك، فإن أمركم بالجلد فخذوه عنه، وإن أمركم بالرجم فلا تأخذوه عنه، فسألوه عن ذلك، فقال: « أرسلوا إلي أعلم رجلين فيكم »، فجاؤوا برجل أعور يقال له: ابن صوريا، وآخر، فقال لهما النبي ﷺ: « أنتما أعلم من قبلكما؟ »، فقالا: قد دعانا قومنا لذلك، فقال النبي ﷺ لهما: « أليس عندكم التوراة فيها حكم الله؟ » قالا: بلى، فقال النبي ﷺ: « أنشدكم بالذي فلق البحر لبني إسرائيل، وظلل عليكم الغمام، وأنجاكم من آل فرعون، وأنزل المن والسلوى على بني إسرائيل، ما تجدون في التوراة في شأن الرجم؟ » فقال أحدهما للآخر: ما نشدت بمثله قط، ثم قالا: نجد ترداد النظر زنية، والاعتناق زنية والتقبيل زنية، فإذا شهد أربعة أنهم رأوه يبدىء ويعيد كما يدخل الميل في المكحلة فقد وجب الرجم، فقال النبي ﷺ: « هو ذاك » فأمر به فرجم فنزلت { فَإِن جَآءُوكَ فَٱحْكُم بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ ۖ وَإِن تُعْرِضْ عَنْهُمْ فَلَن يَضُرُّوكَ شَيْـًٔا ۖ وَإِنْ حَكَمْتَ فَٱحْكُم بَيْنَهُم بِٱلْقِسْطِ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُقْسِطِينَ }.","id":""},{"ar":"وهناك سبب ثان لنزول الآية: عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: كَانَ قُرَيْظَةُ وَالنَّضِيرُ، وَكَانَ النَّضِيرُ أَشْرَفَ مِنْ قُرَيْظَةَ، فَكَانَ إِذَا قَتَلَ رَجُلٌ مِنْ قُرَيْظَةَ رَجُلًا مِنْ النَّضِيرِ قُتِلَ بِهِ، وَإِذَا قَتَلَ رَجُلٌ مِنْ النَّضِير رَجُلًا مِنْ قُرَيْظَةَ فُودِيَ بِمِائَةِ وَسْقٍ مِنْ تَمْرٍ، فَلَمَّا بُعِثَ النَّبِيُّ ﷺ قَتَلَ رَجُلٌ مِنْ النَّضِيرِ رَجُلًا مِنْ قُرَيْظَةَ، فَقَالُوا: ادْفَعُوهُ إِلَيْنَا نَقْتُلُهُ، فَقَالُوا: بَيْنَنَا وَبَيْنَكُمُ النَّبِيُّ ﷺ فَأَتَوْهُ، فَنَزَلَتْ { وَإِنْ حَكَمْتَ فَٱحْكُم بَيْنَهُم بِٱلْقِسْطِ ۚ } والقسط النفس بالنفس، واللفظ لأبي داود.","id":""}],"44":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: إِنَّ اللَّهَ عز و جل أَنْزَلَ { فَأُو۟لَٰٓئِكَ هُمُ ٱلْكَـٰفِرُونَ }، { فَأُو۟لَٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ }، { فَأُو۟لَٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ } قَالَ: قَالَ ابْنُ عَبَّاسٍ: أَنْزَلَهَا اللهُ فِي الطَّائِفَتَينِ مِنْ الْيَهُودِ، وَكَانَتْ إِحْدَاهُمَا قَدْ قَهَرَت الْأُخْرَى فِي الْجَاهِلِيَّةِ، حَتَّى ارْتَضَوْا أَوْ اصْطَلَحُوا عَلَى أَنَّ كُلَّ قَتِيلٍ قَتَلَهُ الْعَزِيزَةُ مِنْ الذَّلِيلَةِ فَدِيَتُهُ خَمْسُونَ وَسْقاً، وَكُلَّ قَتِيلٍ قَتَلَهُ الذَّلِيلَةُ مِنْ الْعَزِيزَةِ فَدِيَتُهُ مِائَةُ وَسْقٍ، فَكَانُوا عَلَى ذَلِكَ حَتَّى قَدِمَ النَّبِيُّ ﷺ الْمَدِينَةَ، فَذَلَّتِ الطَّائِفَتَانِ كِلْتَاهُمَا لِمَقْدَمِ رَسُولِ اللهِ ﷺ، وَيَوْمَئِذٍ لَمْ يَظْهَرْ، وَلَمْ يُوطِئِهُمَا عَلَيْهِ، وَهُوَ فِي الصُّلْحِ، فَقَتَلَتِ الذَّلِيلَةُ مِنَ العَزِيْزَةَ قَتِيْلاً، فَأَرْسَلَتِ العَزِيْزَةُ إِلَى الذَّلِيلَةِ: أَنِ ابْعَثُوا إِلَيْنَا بِمِائَةِ وَسْقٍ، فَقَالَتِ الذَّلِيْلَةُ: وَهَلْ كَانَ هَذَا فِي حَيَّيْنِ قَطُّ دِينُهُمَا وَاحِدٌ، وَنَسَبُهُمَا وَاحِدٌ، وَبَلَدُهُمَا وَاحِدٌ، دِيَةُ بَعْضِهِمْ نِصْفُ دِيةِ بَعْضٍ، إِنَّا إِنَّمَا أَعْطَيْنَاكُمْ هَذَا ضَيْمًا مِنْكُمْ لَنَا، وَفَرَقاً مِنْكُمْ، فَأَمَّا إِذْ قَدِمَ مُحَمَّدٌ فَلَا نُعْطِيكُمْ ذَلِكَ.\nفَكَادَتِ الْحَرْبُ تَهِيجُ بَيْنَهُمَا، ثُمَّ ارْتَضَوْا عَلَى أَنْ يَجْعَلُوا رَسُولَ اللهِ ﷺ بَيْنَهُمْ، ثُمَّ ذَكَرَتِ الْعَزِيزَةُ فَقَالَتْ: وَاللهِ مَا مُحَمَّدٌ بِمُعْطِيكُمْ مِنْهُمْ ضِعْفَ مَا يُعْطِيهِمْ مِنْكُمْ، وَلَقَدْ صَدَقُوا، مَا أَعْطَوْنَا هَذَا إِلَّا ضَيْماً مِنَّا، وَقَهْرَاً لَهُمْ، فَدُسُّوا إِلَى مُحَمَّدٍ مَنْ يَخْبُر لَكُمْ رَأْيَهُ، إِنْ أَعْطَاكُمْ مَا تُرِيدُونَ حَكَمْتُمُوهُ، وَإِنْ لَمْ يُعْطِكُمْ حَذِرْتُمْ فَلَمْ تُحَكِّمُوهُ، فَدَسُّوا إِلَى رَسُولِ اللهِ ﷺ، فَلَمَّا جَاءَ رَسُولَ اللهِ ﷺ، أَخْبَرَ اللهُ رَسُولَهُ بِأَمْرِهِمْ كُلِّهِ، وَمَا أَرَادُوا، فَأَنْزَلَ اللَّهُ عز و جل: { يَـٰٓأَيُّهَا ٱلرَّسُولُ لَا يَحْزُنكَ ٱلَّذِينَ يُسَـٰرِعُونَ فِى ٱلْكُفْرِ مِنَ ٱلَّذِينَ قَالُوٓا۟ ءَامَنَّا } إِلَى قَوْلِهِ: { وَمَن لَّمْ يَحْكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ }، ثُمَّ قَالَ: فِيهِمَا وَاللَّهِ نَزَلَتْ، وَإِيَّاهُمَا عَنَى اللَّهُ عز و جل. واللفظ لأحمد.","id":""}],"45":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: إِنَّ اللَّهَ عز و جل أَنْزَلَ { فَأُو۟لَٰٓئِكَ هُمُ ٱلْكَـٰفِرُونَ }، { فَأُو۟لَٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ }، { فَأُو۟لَٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ } قَالَ: قَالَ ابْنُ عَبَّاسٍ: أَنْزَلَهَا اللهُ فِي الطَّائِفَتَينِ مِنْ الْيَهُودِ، وَكَانَتْ إِحْدَاهُمَا قَدْ قَهَرَت الْأُخْرَى فِي الْجَاهِلِيَّةِ، حَتَّى ارْتَضَوْا أَوْ اصْطَلَحُوا عَلَى أَنَّ كُلَّ قَتِيلٍ قَتَلَهُ الْعَزِيزَةُ مِنْ الذَّلِيلَةِ فَدِيَتُهُ خَمْسُونَ وَسْقاً، وَكُلَّ قَتِيلٍ قَتَلَهُ الذَّلِيلَةُ مِنْ الْعَزِيزَةِ فَدِيَتُهُ مِائَةُ وَسْقٍ، فَكَانُوا عَلَى ذَلِكَ حَتَّى قَدِمَ النَّبِيُّ ﷺ الْمَدِينَةَ، فَذَلَّتِ الطَّائِفَتَانِ كِلْتَاهُمَا لِمَقْدَمِ رَسُولِ اللهِ ﷺ، وَيَوْمَئِذٍ لَمْ يَظْهَرْ، وَلَمْ يُوطِئِهُمَا عَلَيْهِ، وَهُوَ فِي الصُّلْحِ، فَقَتَلَتِ الذَّلِيلَةُ مِنَ العَزِيْزَةَ قَتِيْلاً، فَأَرْسَلَتِ العَزِيْزَةُ إِلَى الذَّلِيلَةِ: أَنِ ابْعَثُوا إِلَيْنَا بِمِائَةِ وَسْقٍ، فَقَالَتِ الذَّلِيْلَةُ: وَهَلْ كَانَ هَذَا فِي حَيَّيْنِ قَطُّ دِينُهُمَا وَاحِدٌ، وَنَسَبُهُمَا وَاحِدٌ، وَبَلَدُهُمَا وَاحِدٌ، دِيَةُ بَعْضِهِمْ نِصْفُ دِيةِ بَعْضٍ، إِنَّا إِنَّمَا أَعْطَيْنَاكُمْ هَذَا ضَيْمًا مِنْكُمْ لَنَا، وَفَرَقاً مِنْكُمْ، فَأَمَّا إِذْ قَدِمَ مُحَمَّدٌ فَلَا نُعْطِيكُمْ ذَلِكَ.\nفَكَادَتِ الْحَرْبُ تَهِيجُ بَيْنَهُمَا، ثُمَّ ارْتَضَوْا عَلَى أَنْ يَجْعَلُوا رَسُولَ اللهِ ﷺ بَيْنَهُمْ، ثُمَّ ذَكَرَتِ الْعَزِيزَةُ فَقَالَتْ: وَاللهِ مَا مُحَمَّدٌ بِمُعْطِيكُمْ مِنْهُمْ ضِعْفَ مَا يُعْطِيهِمْ مِنْكُمْ، وَلَقَدْ صَدَقُوا، مَا أَعْطَوْنَا هَذَا إِلَّا ضَيْماً مِنَّا، وَقَهْرَاً لَهُمْ، فَدُسُّوا إِلَى مُحَمَّدٍ مَنْ يَخْبُر لَكُمْ رَأْيَهُ، إِنْ أَعْطَاكُمْ مَا تُرِيدُونَ حَكَمْتُمُوهُ، وَإِنْ لَمْ يُعْطِكُمْ حَذِرْتُمْ فَلَمْ تُحَكِّمُوهُ، فَدَسُّوا إِلَى رَسُولِ اللهِ ﷺ، فَلَمَّا جَاءَ رَسُولَ اللهِ ﷺ، أَخْبَرَ اللهُ رَسُولَهُ بِأَمْرِهِمْ كُلِّهِ، وَمَا أَرَادُوا، فَأَنْزَلَ اللَّهُ عز و جل: { يَـٰٓأَيُّهَا ٱلرَّسُولُ لَا يَحْزُنكَ ٱلَّذِينَ يُسَـٰرِعُونَ فِى ٱلْكُفْرِ مِنَ ٱلَّذِينَ قَالُوٓا۟ ءَامَنَّا } إِلَى قَوْلِهِ: { وَمَن لَّمْ يَحْكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ }، ثُمَّ قَالَ: فِيهِمَا وَاللَّهِ نَزَلَتْ، وَإِيَّاهُمَا عَنَى اللَّهُ عز و جل. واللفظ لأحمد.","id":""}],"47":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: إِنَّ اللَّهَ عز و جل أَنْزَلَ { فَأُو۟لَٰٓئِكَ هُمُ ٱلْكَـٰفِرُونَ }، { فَأُو۟لَٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ }، { فَأُو۟لَٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ } قَالَ: قَالَ ابْنُ عَبَّاسٍ: أَنْزَلَهَا اللهُ فِي الطَّائِفَتَينِ مِنْ الْيَهُودِ، وَكَانَتْ إِحْدَاهُمَا قَدْ قَهَرَت الْأُخْرَى فِي الْجَاهِلِيَّةِ، حَتَّى ارْتَضَوْا أَوْ اصْطَلَحُوا عَلَى أَنَّ كُلَّ قَتِيلٍ قَتَلَهُ الْعَزِيزَةُ مِنْ الذَّلِيلَةِ فَدِيَتُهُ خَمْسُونَ وَسْقاً، وَكُلَّ قَتِيلٍ قَتَلَهُ الذَّلِيلَةُ مِنْ الْعَزِيزَةِ فَدِيَتُهُ مِائَةُ وَسْقٍ، فَكَانُوا عَلَى ذَلِكَ حَتَّى قَدِمَ النَّبِيُّ ﷺ الْمَدِينَةَ، فَذَلَّتِ الطَّائِفَتَانِ كِلْتَاهُمَا لِمَقْدَمِ رَسُولِ اللهِ ﷺ، وَيَوْمَئِذٍ لَمْ يَظْهَرْ، وَلَمْ يُوطِئِهُمَا عَلَيْهِ، وَهُوَ فِي الصُّلْحِ، فَقَتَلَتِ الذَّلِيلَةُ مِنَ العَزِيْزَةَ قَتِيْلاً، فَأَرْسَلَتِ العَزِيْزَةُ إِلَى الذَّلِيلَةِ: أَنِ ابْعَثُوا إِلَيْنَا بِمِائَةِ وَسْقٍ، فَقَالَتِ الذَّلِيْلَةُ: وَهَلْ كَانَ هَذَا فِي حَيَّيْنِ قَطُّ دِينُهُمَا وَاحِدٌ، وَنَسَبُهُمَا وَاحِدٌ، وَبَلَدُهُمَا وَاحِدٌ، دِيَةُ بَعْضِهِمْ نِصْفُ دِيةِ بَعْضٍ، إِنَّا إِنَّمَا أَعْطَيْنَاكُمْ هَذَا ضَيْمًا مِنْكُمْ لَنَا، وَفَرَقاً مِنْكُمْ، فَأَمَّا إِذْ قَدِمَ مُحَمَّدٌ فَلَا نُعْطِيكُمْ ذَلِكَ.\nفَكَادَتِ الْحَرْبُ تَهِيجُ بَيْنَهُمَا، ثُمَّ ارْتَضَوْا عَلَى أَنْ يَجْعَلُوا رَسُولَ اللهِ ﷺ بَيْنَهُمْ، ثُمَّ ذَكَرَتِ الْعَزِيزَةُ فَقَالَتْ: وَاللهِ مَا مُحَمَّدٌ بِمُعْطِيكُمْ مِنْهُمْ ضِعْفَ مَا يُعْطِيهِمْ مِنْكُمْ، وَلَقَدْ صَدَقُوا، مَا أَعْطَوْنَا هَذَا إِلَّا ضَيْماً مِنَّا، وَقَهْرَاً لَهُمْ، فَدُسُّوا إِلَى مُحَمَّدٍ مَنْ يَخْبُر لَكُمْ رَأْيَهُ، إِنْ أَعْطَاكُمْ مَا تُرِيدُونَ حَكَمْتُمُوهُ، وَإِنْ لَمْ يُعْطِكُمْ حَذِرْتُمْ فَلَمْ تُحَكِّمُوهُ، فَدَسُّوا إِلَى رَسُولِ اللهِ ﷺ، فَلَمَّا جَاءَ رَسُولَ اللهِ ﷺ، أَخْبَرَ اللهُ رَسُولَهُ بِأَمْرِهِمْ كُلِّهِ، وَمَا أَرَادُوا، فَأَنْزَلَ اللَّهُ عز و جل: { يَـٰٓأَيُّهَا ٱلرَّسُولُ لَا يَحْزُنكَ ٱلَّذِينَ يُسَـٰرِعُونَ فِى ٱلْكُفْرِ مِنَ ٱلَّذِينَ قَالُوٓا۟ ءَامَنَّا } إِلَى قَوْلِهِ: { وَمَن لَّمْ يَحْكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ }، ثُمَّ قَالَ: فِيهِمَا وَاللَّهِ نَزَلَتْ، وَإِيَّاهُمَا عَنَى اللَّهُ عز و جل. واللفظ لأحمد.","id":""}],"51":[{"ar":"قال محمد بن إسحاق: فحدثني أبي إسحاق بن يسار، عن عبادة بن الوليد بن عبادة بن الصامت قال: لما حاربت بنو قينقاع رسول الله ﷺ، تشبث بأمرهم عبد الله بن أُبيِّ وقام دونهم، ومشى عبادة بن الصامت إلى رسول الله ﷺ، وكان أحد بني عوف بن الخزرج له من حلفهم مثل الذي لعبد الله بن أُبيٍّ، فجعلهم إلى رسول الله ﷺ، وتبرأ إلى الله ورسوله من حلفهم، وقال: يا رسول الله، أبرأ إلى الله وإلى رسوله من حلفهم، وأتولى الله ورسوله والمؤمنين، وأبرأ من حِلْفِ الكفار وولايتهم. ففيه وفي عبد الله بن أُبَيٍّ نزلت الآيات في المائدة: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ ٱلْيَهُودَ وَٱلنَّصَـٰرَىٰٓ أَوْلِيَآءَ ۘ بَعْضُهُمْ } الي قوله { وَمَن يَتَوَلَّ ٱللَّهَ وَرَسُولَهُۥ وَٱلَّذِينَ ءَامَنُوا۟ فَإِنَّ حِزْبَ ٱللَّهِ هُمُ ٱلْغَـٰلِبُونَ ﴿٥٦﴾ }","id":""}],"57":[{"ar":"عن ابن عباس رضي الله عنهما قال: كان رفاعة بن زيد بن التابوت، وسويد بن الحرث قد أظهرا الإسلام ثم نافقا، وكان رجال من المسلمين يوادُّونهما، فأنزل الله فيهما: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ ٱلَّذِينَ ٱتَّخَذُوا۟ دِينَكُمْ هُزُوًا وَلَعِبًا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ مِن قَبْلِكُمْ وَٱلْكُفَّارَ أَوْلِيَآءَ ۚ } إلى قوله: { وَٱللَّهُ أَعْلَمُ بِمَا كَانُوا۟ يَكْتُمُونَ } [المائدة: ٥٧ - ٦١].","id":""}],"59":[{"ar":"عن ابن عباس رضي الله عنهما قال: أتى رسول الله ﷺ نفرٌ من اليهود، فيهم أبو ياسر بن أخطب، ورافع بن أبي رافع، وعازر، وزيد، وخالد، وأزار بن أبي أزار، وأشيع، فسألوه عمن يؤمن به من الرسل.\nقال: « أؤمن بالله وما أنزل إلينا، وما أنزل إلى إبراهيم وإسماعيل وإسحاق ويعقوب والأسباط، وما أوتي موسى وعيسى، وما أوتي النبيون من ربهم، لا نفرق بين أحد منهم ونحن له مسلمون ».\nفلما ذكر عيسى جحدوا نبوته، وقالوا: لا نؤمن بمن آمن به. فأنزل الله فيهم: { قُلْ يَـٰٓأَهْلَ ٱلْكِتَـٰبِ هَلْ تَنقِمُونَ مِنَّآ إِلَّآ أَنْ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ إِلَيْنَا وَمَآ أُنزِلَ مِن قَبْلُ وَأَنَّ أَكْثَرَكُمْ فَـٰسِقُون�� ﴿٥٩﴾ }.","id":""}],"67":[{"ar":"عَنْ عَائِشَةَ رضي الله عنها قَالَتْ: كَانَ النَّبِيُّ ﷺ يُحْرَسُ، حَتَّى نَزَلَتْ هَذِهِ الْآيَةَ { وَٱللَّهُ يَعْصِمُكَ مِنَ ٱلنَّاسِ ۗ }، فَأَخْرَجَ رَسُولُ اللهِ ﷺ رَأْسَهُ مِنَ الْقُبَّة، فَقَالَ لَهُمْ: « يَا أَيُّهَا النَّاسُ، انْصَرِفُوا فَقَدْ عَصَمَنِي الله ». واللفظ للترمذي.","id":""}],"87":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما: أَنَّ رَجُلًا أَتَى النَّبِيَّ ﷺ، فَقَالَ: يَا رَسُولَ اللهِ، إِنِّي إِذَا أَصَبْتُ اللَّحْمَ انْتَشَرْتُ لِلنِّسَاءِ وَأَخَذَتْنِي شَهْوَتِي، فَحَرَّمْتُ عَلَيَّ اللَّحْمَ. فَأَنْزَلَ اللهُ: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تُحَرِّمُوا۟ طَيِّبَـٰتِ مَآ أَحَلَّ ٱللَّهُ لَكُمْ وَلَا تَعْتَدُوٓا۟ ۚ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْمُعْتَدِينَ ﴿٨٧﴾ وَكُلُوا۟ مِمَّا رَزَقَكُمُ ٱللَّهُ حَلَـٰلًا طَيِّبًا ۚ }. و اللفظ للترمذي.","id":""}],"90":[{"ar":"عن مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ رضي الله عنه قَالَ: (... وَأَتَيْتُ عَلَى نَفَرٍ مِنْ الْأَنْصَارِ وَالْمُهَاجِرِينَ، فَقَالُوا: تَعَالَ نُطْعِمْكَ وَنَسْقِكَ خَمْراً، وَذَلِكَ قَبْلَ أَنْ تُحَرَّمَ الْخَمْرُ، قَالَ: فَأَتَيْتُهُمْ فِي حَشٍّ، وَالْحَشُّ: الْبُسْتَانُ، فَإِذَا رَأْسُ جَزُورٍ مَشْوِيٌّ عِنْدَهُمْ، وَزِقٌ مِنْ خَمْرٍ، قَالَ: فَأَكَلْتُ وَشَرِبْتُ مَعَهُمْ، قَالَ: فَذَكَرْتُ الْأَنْصَارَ وَالمُهَاجِرِينَ عِنْدَهُمْ، فَقُلْتُ: الْمُهَاجِرُونَ خَيْرٌ مِنْ الْأَنْصَارِ، قَالَ: فَأَخَذَ رَجُلٌ أَحَدَ لَحْيَي الرَّأْسِ، فَضَرَبَنِي به فَجَرَحَ بِأَنْفِي، فَأَتَيْتُ رَسُولَ اللهِ ﷺ فَأَخْبَرْتُهُ، فَأَنْزَلَ اللهُ عز و جل فِيَّ - يَعْنِي نَفْسَهُ - شَأْنَ الْخَمْرِ: { إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ وَٱلْأَنصَابُ وَٱلْأَزْلَـٰمُ رِجْسٌ مِّنْ عَمَلِ ٱلشَّيْطَـٰنِ }.","id":""}],"91":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: نَزَلَ تَحْرِيمُ الخَمْرِ فِي قَبِيلَتَيْنِ مِن قَبائِلِ الأَنصارِ، شَرِبُوا حَتَّى إِذا ثَمَلُوا، عَبَثَ بَعْضُهُم بِبَعْضٍ، فَلَمَّا صَحَوْا، جَعَلَ الرَّجُلُ يَرَى الأَعْثَرَ بِوَجْهِه وَبْرَأْسِهِ وَبِلِحْيَتِهِ، يَقُولُ: فَعَلَ هَذَا أَخِي فُلانٌ واللهِ لَوْ كَانَ بِي رَؤوفاً رَحِيماً مَا فَعَلَ هَذَا بِي، وَقَالَ: وَكَانُوا إِخْوَةً لَيْسَ في قُلوبِهِمْ ضَغَائنُ، فَوَقَعَتْ فِي قُلُوبِهِمُ الضَغَائِنُ، فَأَنزلَ اللهُ تَعَالَى: { إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ وَٱلْأَنصَابُ وَٱلْأَزْلَـٰمُ رِجْسٌ مِّنْ عَمَلِ ٱلشَّيْطَـٰنِ فَٱجْتَنِبُوهُ لَعَلَّكُمْ تُفْلِحُونَ ﴿٩٠﴾ إِنَّمَا يُرِيدُ ٱلشَّيْطَـٰنُ أَن يُوقِعَ بَيْنَكُمُ ٱلْعَدَٰوَةَ وَٱلْبَغْضَآءَ فِى ٱلْخَمْرِ وَٱلْمَيْسِرِ وَيَصُدَّكُمْ عَن ذِكْرِ ٱللَّهِ وَعَنِ ٱلصَّلَوٰةِ ۖ فَهَلْ أَنتُم مُّنتَهُونَ ﴿٩١﴾ } فَقَالَ نَاسٌ مِنَ المُتَكَلِّفِينَ: هِيَ رِجْسٌ، وَهِيَ فِي بَطْنِ فُلانٍ قُتِلَ يَوْمَ بَدرٍ، وَفُلانٍ قُتِلَ يَوْمَ أُحُدٍ؟! فَأَنزَلَ اللهُ تعالى: { لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جُنَاحٌ فِيمَا طَعِمُوٓا۟ } الآية.","id":""},{"ar":"عَنْ أَنَسٍ رضي الله عنه: كُنْتُ سَاقِيَ الْقَوْمِ فِي مَنْزِلِ أَبِي طَلْحَةَ، وَكَانَ خَمْرُهُمْ يَوْمَئِذٍ الْفَضِيخَ، فَأَمَرَ رَسُولُ اللهِ ﷺ مُنَادِياً يُنَادِي: أَلَا إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ، قَالَ: فَقَالَ لِي أَبُو طَلْحَةَ: اخْرُجْ فَأَهْرِقْهَا. فَخَرَجْتُ فَهَرَقْتُهَا، فَجَرَتْ فِي سِكَكِ الْمَدِينَةِ، فَقَالَ بَعْضُ الْقَوْمِ: قَدْ قُتِلَ قَوْمٌ وَهِيَ فِي بُطُونِهِمْ، فَأَنْزَلَ اللهُ: { لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جُنَاحٌ فِيمَا طَعِمُوٓا۟ } الْآيَةَ. واللفظ للبخاري.","id":""},{"ar":"عَنْ أَبي إِسْحَاقَ قَالَ: قَالَ البَراءُ رضي الله عنه: مَاتَ نَاسٌ مِنْ أَصْحَابِ رَسُولِ اللهِ ﷺ وَهُمْ يَشربونَ الخَمْرَ، فَلَمَّا نَزلَ تَحريمُهَا، قَالَ أُنَاسٌ مِنْ أَصْحَابِ النَّبِيِّ ﷺ: فَكَيْفَ بِأَصْحَابِنَا الذِينَ مَاتُوا وَهُمْ يَشْرَبُونَها، فَنَزلَتْ هَذِهِ الآيَةِ: { لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ } الآية.","id":""},{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: قَالُوا: يَا رَسُولَ اللهِ، أَرَأَيْتَ الَّذِينَ مَاتُوا وَهُمْ يَشْرَبُونَ الْخَمْرَ؟ لَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ، فَنَزَلَتْ: { لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جُنَاحٌ فِيمَا طَعِمُوٓا۟ إِذَا مَا ٱتَّقَوا۟ وَّءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ }.","id":""}],"93":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: نَزَلَ تَحْرِيمُ الخَمْرِ فِي قَبِيلَتَيْنِ مِن قَبائِلِ الأَنصارِ، شَرِبُوا حَتَّى إِذا ثَمَلُوا، عَبَثَ بَعْضُهُم بِبَعْضٍ، فَلَمَّا صَحَوْا، جَعَلَ الرَّجُلُ يَرَى الأَعْثَرَ بِوَجْهِه وَبْرَأْسِهِ وَبِلِحْيَتِهِ، يَقُولُ: فَعَلَ هَذَا أَخِي فُلانٌ واللهِ لَوْ كَانَ بِي رَؤوفاً رَحِيماً مَا فَعَلَ هَذَا بِي، وَقَالَ: وَكَانُوا إِخْوَةً لَيْسَ في قُلوبِهِمْ ضَغَائنُ، فَوَقَعَتْ فِي قُلُوبِهِمُ الضَغَائِنُ، فَأَنزلَ اللهُ تَعَالَى: { إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ وَٱلْأَنصَابُ وَٱلْأَزْلَـٰمُ رِجْسٌ مِّنْ عَمَلِ ٱلشَّيْطَـٰنِ فَٱجْتَنِبُوهُ لَعَلَّكُمْ تُفْلِحُونَ ﴿٩٠﴾ إِنَّمَا يُرِيدُ ٱلشَّيْطَـٰنُ أَن يُوقِعَ بَيْنَكُمُ ٱلْعَدَٰوَةَ وَٱلْبَغْضَآءَ فِى ٱلْخَمْرِ وَٱلْمَيْسِرِ وَيَصُدَّكُمْ عَن ذِكْرِ ٱللَّهِ وَعَنِ ٱلصَّلَوٰةِ ۖ فَهَلْ أَنتُم مُّنتَهُونَ ﴿٩١﴾ } فَقَالَ نَاسٌ مِنَ المُتَكَلِّفِينَ: هِيَ رِجْسٌ، وَهِيَ فِي بَطْنِ فُلانٍ قُتِلَ يَوْمَ بَدرٍ، وَفُلانٍ قُتِلَ يَوْمَ أُحُدٍ؟! فَأَنزَلَ اللهُ تعالى: { لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جُنَاحٌ فِيمَا طَعِمُوٓا۟ } الآية.","id":""},{"ar":"عَنْ أَنَسٍ رضي الله عنه: كُنْتُ سَاقِيَ الْقَوْمِ فِي مَنْزِلِ أَبِي طَلْحَةَ، وَكَانَ خَمْرُهُمْ يَوْمَئِذٍ الْفَضِيخَ، فَأَمَرَ رَسُولُ اللهِ ﷺ مُنَادِياً يُنَادِي: أَلَا إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ، قَالَ: فَقَالَ لِي أَبُو طَلْحَةَ: اخْرُجْ فَأَهْرِقْهَا. فَخَرَجْتُ فَهَرَقْتُهَا، فَجَرَتْ فِي سِكَكِ الْمَدِينَةِ، فَقَالَ بَعْضُ الْقَوْمِ: قَدْ قُتِلَ قَوْمٌ وَهِيَ فِي بُطُونِهِمْ، فَأَنْزَلَ اللهُ: { لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جُنَاحٌ فِيمَا طَعِمُوٓا۟ } الْآيَةَ. واللفظ للبخاري.","id":""},{"ar":"عَنْ أَبي إِسْحَاقَ قَالَ: قَالَ البَراءُ رضي الله عنه: مَاتَ نَاسٌ مِنْ أَصْحَابِ رَسُولِ اللهِ ﷺ وَهُمْ يَشربونَ الخَمْرَ، فَلَمَّا نَزلَ تَحريمُهَا، قَالَ أُنَاسٌ مِنْ أَصْحَابِ النَّبِيِّ ﷺ: فَكَيْفَ بِأَصْحَابِنَا الذِينَ مَاتُوا وَهُمْ يَشْرَبُونَها، فَنَزلَتْ هَذِهِ الآيَةِ: { لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ } الآية.","id":""},{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: قَالُوا: يَا رَسُولَ اللهِ، أَرَأَيْتَ الَّذِينَ مَاتُوا وَهُمْ يَشْرَبُونَ الْخَمْرَ؟ لَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ، فَنَزَلَتْ: { لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جُنَاحٌ فِيمَا طَعِمُوٓا۟ إِذَا مَا ٱتَّقَوا۟ وَّءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ }.","id":""}],"101":[{"ar":"عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه قَالَ: بَلَغَ رَسُولَ اللهِ ﷺ عَنْ أَصْحَابِهِ شَيْءٌ، فَخَطَبَ فَقَالَ: « عُرِضَتْ عَلَيَّ الْجَنَّةُ وَالنَّارُ، فَلَمْ أَرَ كَالْيَوْمِ فِي الْخَيْرِ وَالشَّرِّ، وَلَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكْيْتُمْ كَثِيرًا »، قَالَ: فَمَا أَتَى عَلَى أَصْحَابِ رَسُولِ الله ﷺ يَوْمٌ أَشَدُّ مِنْهُ، قَالَ: غَطَّوْا رُءُوسَهُمْ وَلَهُمْ خَنِينٌ، قَالَ: فَقَامَ عُمَرُ فَقَالَ: رَضِينَا بِاللهِ رَبَّا، وَبِالْإِسْلَامِ دِيناً، وَبِمُحَمَّدٍ نَبِيًّا، قَالَ: فَقَامَ ذَاكَ الرَّجُلُ فَقَالَ: مَنْ أَبِي؟ قَالَ: « أَبُوكَ فُلَانٌ »، فَنَزَلَتْ: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَسْـَٔلُوا۟ عَنْ أَشْيَآءَ إِن تُبْدَ لَكُمْ تَسُؤْكُمْ }.","id":""},{"ar":"ولها سبب نزول ثان: عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: كَانَ قَوْمٌ يَسْأَلُونَ رَسُولَ الله ﷺ اسْتِهْزَاءً، فَيَقُولُ الرَّجُلُ مَنْ أَبِي؟ وَيَقُولُ الرَّجُلُ تَضِلُّ نَاقَتُهُ: أَيْنَ نَاقَتِي؟ فَأَنْزَلَ اللهُ فِيهِمْ هَذِهِ الْآيَةَ: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَسْـَٔلُوا۟ عَنْ أَشْيَآءَ إِن تُبْدَ لَكُمْ تَسُؤْكُمْ }. حَتَّى فَرَغَ مِنْ الْآيَةِ كُلِّهَا.","id":""},{"ar":"وقد جاء سبب آخر لنزول الآية: عن أبي هريرة رضي الله عنه قال: خطبنا رسول الله فقال: « يا أيها الناس كتب الله عليكم الحج »، فقام محصن الأسدي فقال: أفي كل عام يا رسول الله؟ فقال: « أما إني لو قلت نعم لوجبت، ولو وجبت ثم تركتم لضللتم، اسكتوا عني ما سكت عنكم، فإنما هلك من كان قبلكم، بسؤالهم واختلافهم على أنبيائهم »، فأنزل الله تعالى: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَسْـَٔلُوا۟ عَنْ أَشْيَآءَ إِن تُبْدَ لَكُمْ تَسُؤْكُمْ }، إلى آخر الآية.","id":""}],"106":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: خَرَجَ رَجُلٌ مِنْ بَنِي سَهُمٍ مَعَ تَمِيمٍ الدَّارِيِّ وَعَدِيِّ بْنِ بَدَّاءٍ، فَمَاتَ السَّهْمِيُّ بِأَرضٍ لَيْسَ بِهَا مُسْلِمٌ، فَلَمَّا قَدِمَا بِتَرِكَتِهِ فَقَدُوا جَاماً مِنْ فِضَّةٍ مَخُوصاً مِنْ ذَهَبٍ، فَأَحْلَفَهُمَا رَسُولُ اللهِ ﷺ، ثُمَّ وُجِدَ الْجَامُ بِمَكَّةَ، فَقَالُوا: ابْتَعْنَاهُ مِنْ تَمِيمٍ وَعَدِيٍّ، فَقَامَ رَجُلَانِ مِنْ أَوْلِيَائِهِ، فَحَلَفَا لَشَهَادَتُنَا أَحَقُّ مِنْ شَهَادَتِهِمَا، وَإِنَّ الْجَامَ لِصَاحِبِهِمْ، قَالَ: وَفِيهِمْ نَزَلَتْ هَذِهِ الْآيَةُ { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ شَهَـٰدَةُ بَيْنِكُمْ إِذَا حَضَرَ أَحَدَكُمُ ٱلْمَوْتُ }.","id":""}],"107":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: خَرَجَ رَجُلٌ مِنْ بَنِي سَهُمٍ مَعَ تَمِيمٍ الدَّارِيِّ وَعَدِيِّ بْنِ بَدَّاءٍ، فَمَاتَ السَّهْمِيُّ بِأَرضٍ لَيْسَ بِهَا مُسْلِمٌ، فَلَمَّا قَدِمَا بِتَرِكَتِهِ فَقَدُوا جَاماً مِنْ فِضَّةٍ مَخُوصاً مِنْ ذَهَبٍ، فَأَحْلَفَهُمَا رَسُولُ اللهِ ﷺ، ثُمَّ وُجِدَ الْجَامُ بِمَكَّةَ، فَقَالُوا: ابْتَعْنَاهُ مِنْ تَمِيمٍ وَعَدِيٍّ، فَقَامَ رَجُلَانِ مِنْ أَوْلِيَائِهِ، فَحَلَفَا لَشَهَادَتُنَا أَحَقُّ مِنْ شَهَادَتِهِمَا، وَإِنَّ الْجَامَ لِصَاحِبِهِمْ، قَالَ: وَفِيهِمْ نَزَلَتْ هَذِهِ الْآيَةُ { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ شَهَـٰدَةُ بَيْنِكُمْ إِذَا حَضَرَ أَحَدَكُمُ ٱلْمَوْتُ }.","id":""}]},"mapping_ayat":{"5:2":[{"p":"Bukhari","n":6388,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ عَنْ مِسْعَرٍ وَغَيْرِهِ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَق��الَ رَجُلٌ مِنْ الْيَهُودِ لِعُمَرَ يَا أَمِيرَ الْمُؤْمِنِينَ لَوْ أَنَّ عَلَيْنَا نَزَلَتْ هَذِهِ الْآيَةُ{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمْ الْإِسْلَامَ دِينًا }لَاتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا فَقَالَ عُمَرُ إِنِّي لَأَعْلَمُ أَيَّ يَوْمٍ نَزَلَتْ هَذِهِ الْآيَةُ نَزَلَتْ يَوْمَ عَرَفَةَ فِي يَوْمِ جُمُعَةٍسَمِعَ سُفْيَانُ مِنْ مِسْعَرٍ وَمِسْعَرٌ قَيْسًا وَقَيْسٌ طَارِقًا","trj":"Telah menceritakan kepada kami [Abdullah bin Zubair Al Humaidi] telah menceritakan kepada kami [Sufyan] dari [Mis'ar] dan lainnya dari [Qais bin Muslim] dari [Thariq bin Syihab] ia berkata, \"Seorang laki-laki Yahudi berkata kepada [Umar], \"Wahai Amirul Mukminin, kalaulah ayat ini diturunkan kepada kami, yaitu ayat: '(Hari ini telah Aku sempurnakan untk kalian agama kalian, dan Aku semurkan bagi kalian Nikmat-Ku dan Aku ridhai Islam sebagai agama kalian) ' (Qs. Al Maidah: 2), niscaya telah kami jadikan hari itu sebagai hari raya.\" Lantas Umar berkata, \"Sungguh, aku tahu hari apa ayat itu diturunkan. Ayat itu diturunkan di hari Arafah pada hari jumat.\" Sufyan mendengar dari Mis'ar, Mis'ar mendengar dari Qais, dan Qais mendengar dari Thariq."}],"5:3":[{"p":"Bukhari","n":43,"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ سَمِعَ جَعْفَرَ بْنَ عَوْنٍ حَدَّثَنَا أَبُو الْعُمَيْسِ أَخْبَرَنَا قَيْسُ بْنُ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّ رَجُلًا مِنْ الْيَهُودِ قَالَ لَهُ يَا أَمِيرَ الْمُؤْمِنِينَ آيَةٌ فِي كِتَابِكُمْ تَقْرَءُونَهَا لَوْ عَلَيْنَا مَعْشَرَ الْيَهُودِ نَزَلَتْ لَاتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا قَالَ أَيُّ آيَةٍ قَالَ{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمْ الْإِسْلَامَ دِينًا }قَالَ عُمَرُ قَدْ عَرَفْنَا ذَلِكَ الْيَوْمَ وَالْمَكَانَ الَّذِي نَزَلَتْ فِيهِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ قَائِمٌ بِعَرَفَةَ يَوْمَ جُمُعَةٍ","trj":"Telah menceritakan kepada kami [Al Hasan bin Ash Shabbah] bahwa dia mendengar [Ja'far bin 'Aun] berkata; Telah menceritakan kepada kami [Abu Al 'Umais], telah mengabarkan kepada kami [Qais bin Muslim] dari [Thariq bin Syihab] dari [Umar bin Al Khaththab]; Ada seorang laki-laki Yahudi berkata: \"Wahai Amirul Mu'minin, ada satu ayat dalam kitab kalian yang kalian baca, seandainya ayat itu diturunkan kepada kami Kaum Yahudi, tentulah kami jadikan (hari diturunkannya ayat itu) sebagai hari raya ('ied). Maka Umar bin Al Khaththab berkata: \"Ayat apakah itu?\" (Orang Yahudi itu) berkata: \"Pada hari ini telah Kusempurnakan untuk kalian agama kalian, dan telah Ku-cukupkan kepada kalian nikmat-Ku, dan telah Ku-ridhai Islam itu jadi agama bagi kalian\". (QS. Al Maidah ayat 3). Maka Umar bin Al Khaththab menjawab: \"Kami tahu hari tersebut dan dimana tempat diturunkannya ayat tersebut kepada Nabi shallallahu 'alaihi wasallam, yaitu pada hari Jum'at ketika Beliau shallallahu 'alaihi wasallam berada di 'Arafah. "},{"p":"Bukhari","n":3935,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ قَيْسٍ عَنْ طَارِقِ بْنِ شِهَابٍقَالَتْ الْيَهُودُ لِعُمَرَ إِنَّكُمْ تَقْرَءُونَ آيَةً لَوْ نَزَلَتْ فِينَا لَاتَّخَذْنَاهَا عِيدًا فَقَالَ عُمَرُ إِنِّي لَأَعْلَمُ حَيْثُ أُنْزِلَتْ وَأَيْنَ أُنْزِلَتْ وَأَيْنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُنْزِلَتْ يَوْمَ عَرَفَةَ وَإِنَّا وَاللَّهِ بِعَرَفَةَ قَالَ سُفْيَانُ وَأَشُكُّ كَانَ يَوْمَ الْجُمُعَةِ أَمْ لَا{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ }","trj":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami ['Abdur Rahman] Telah menceritakan kepada kami [Sufyan] dari [Qais] dari [Thariq bin Syihab] dia berkata; Orang-orang Yahudi mengatakan kepada Umar; \"Sesungguhnya kalian membaca satu ayat, seandainya ayat itu diturunkan kepada kami, maka hari turunnya ayat tersebut pasti akan kami jadikan hari raya.\" lalu [Umar] menjawab; \"sesungguhnya aku sangat tahu dimana ayat tersebut diturunkan, pada hari apa diturunkan, dan di mana Rasulullah shallallahu 'alaihi wasallam berada ketika ayat tersebut diturunkan, bahwa ayat tersebut diturunkan pada hari Arafah dan kami demi Allah pada waktu itu sedang melaksanakan wukuf di Arafah.\" Sufyan berkata; aku ragu tentang; \"hari Jum'at atau bukan.\" yaitu ayat; \"Pada hari Ini telah Kusempurnakan untuk kamu agamamu, dan telah Ku-cukupkan kepadamu nikmat-Ku, dan telah Ku-ridhai Islam itu jadi agama bagimu.\"(QS Al Ma'idah ayat: 3)."}],"5:4":[{"p":"Ahmad","n":2016,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا مُجَالِدٌ عَنْ عَامِرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَّمَنِي الْإِسْلَامَ وَنَعَتَ لِي الصَّلَاةَ وَكَيْفَ أُصَلِّي كُلَّ صَلَاةٍ لِوَقْتِهَا ثُمَّ قَالَ لِي كَيْفَ أَنْتَ يَا ابْنَ حَاتِمٍ إِذَا رَكِبْتَ مِنْ قُصُورِ الْيَمَنِ لَا تَخَافُ إِلَّا اللَّهَ حَتَّى تَنْزِلَ قُصُورَ الْحِيرَةِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ فَأَيْنَ مَقَانِبُ طَيِّئٍ وَرِجَالُهَا قَالَ يَكْفِيكَ اللَّهُ طَيِّئًا وَمَنْ سِوَاهَا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ نَتَصَيَّدُ بِهَذِهِ الْكِلَابِ وَالْبَزَاةِ فَمَا يَحِلُّ لَنَا مِنْهَا قَالَ يَحِلُّ لَكُمْ{ مَا عَلَّمْتُمْ مِنْ الْجَوَارِحِ مُكَلِّبِينَ تُعَلِّمُونَهُنَّ مِمَّا عَلَّمَكُمْ اللَّهُ فَكُلُوا مِمَّا أَمْسَكْنَ عَلَيْكُمْ وَاذْكُرُوا اسْمَ اللَّهِ عَلَيْهِ }فَمَا عَلَّمْتَ مِنْ كَلْبٍ أَوْ بَازٍ ثُمَّ أَرْسَلْتَ وَذَكَرْتَ اسْمَ اللَّهِ عَلَيْهِ فَكُلْ مِمَّا أَمْسَكَ عَلَيْكَ قُلْتُ وَإِنْ قَتَلَ قَالَ وَإِنْ قَتَلَ وَلَمْ يَأْكُلْ مِنْهُ شَيْئًا فَإِنَّمَا أَمْسَكَهُ عَلَيْكَ قُلْتُ أَفَرَأَيْتَ إِنْ خَالَطَ كِلَابَنَا كِلَابٌ أُخْرَى حِينَ نُرْسِلُهَا قَالَ لَا تَأْكُلْ حَتَّى تَعْلَمَ أَنَّ كَلْبَكَ هُوَ الَّذِي أَمْسَكَ عَلَيْكَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ نَرْمِي بِالْمِعْرَاضِ فَمَا يَحِلُّ لَنَا قَالَ لَا تَأْكُلْ مَا أَصَبْتَ بِالْمِعْرَاضِ إِلَّا مَا ذَكَّيْتَ","trj":"Telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami [Mujalid] dari [Amir] dari [Adi bin Hatim] ia berkata, \"Aku datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau mengajariku tentang Islam, menjelaskan sifat shalat dan bagaimana agar aku shalat tepat pada waktunya. Kemudian beliau bertanya kepadaku: \"Bagaimana denganmu wahai Ibnu Hatim, jika kamu berkendaraan dari istana Yaman, apakah kamu tidak takut selain kepada Allah hingga kamu sampai di istana Hirah?\" aku menjawab, \"Wahai Rasulullah, lalu dimanakah posisi tentara suku Thayyi?\" beliau bersabda: \"Cukuplah Allah sebagai penjagamu dari orang-orang Thayyi dan selainnya.\" Aku berkata lagi, \"Wahai Rasulullah, kami adalah kaum yang suka berburu dengan anjing-anjing ini dan burung ini. Lalu apa yang halal bagi kami dari hasil buruannya?\" Beliau menjawab: \"Dihalalkan bagimu yang baik-baik dan (buruan yang ditangkap) oleh binatang buas yang Telah kamu ajar dengan melatih nya untuk berburu; kamu mengajarnya menurut apa yang Telah diajarkan Allah kepadamu. Maka makanlah dari apa yang ditangkapnya untukmu, dan sebutlah nama Allah atas binatang buas itu (waktu melepaskannya) '. (Qs. Al Maidah: 4) Maka anjing atau burung buas yang telah kamu latih, kemudian kamu melepasnya dan menyebut nama Allah, maka makanlah hasil buruan yang ditangkapnya untukmu.\" Aku bertanya, \"Kalau ia membunuhnya?\" beliau menjawab: \"Kalau ia membunuhnya namun tidak memakan secuil pun darinya, maka sesungguhnya ia hanya berburu untukmu.\" Aku bertanya lagi, \"Bagaimanakah menurut anda, jika anjing-anjing kami berbaur dengan anjing-anjing yang lain saat kami melepaskannya?\" beliau menjawab: \"Jangan kamu makan hingga kamu memastikan bahwa anjing milikmulah yang telah menangkapnya.\" Aku berkata, \"Wahai Rasulullah, kami kadang melempar (buruan) dengan mi'rdl (bagian tombak yang tumpul), lalu mana yang halal bagi kami?\" beliau bersabda: \"Jangan kamu makan, kecuali buruan yang sempat kamu sembelih.\""}],"5:6":[{"p":"Abu Dawud","n":263,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ الضَّرِيرُ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَكُنْتُ جَالِسًا بَيْنَ عَبْدِ اللَّهِ وَأَبِي مُوسَى فَقَالَ أَبُو مُوسَى يَا أَبَا عَبْدِ الرَّحْمَنِ أَرَأَيْتَ لَوْ أَنَّ رَجُلًا أَجْنَبَ فَلَمْ يَجِدْ الْمَاءَ شَهْرًا أَمَا كَانَ يَتَيَمَّمُ فَقَالَ لَا وَإِنْ لَمْ يَجِدْ الْمَاءَ شَهْرًا فَقَالَ أَبُو مُوسَى فَكَيْفَ تَصْنَعُونَ بِهَذِهِ الْآيَةِ الَّتِي فِي سُورَةِ الْمَائِدَةِ{ فَلَمْ تَجِدُوا مَاءً فَتَيَمَّمُوا صَعِيدًا طَيِّبًا }فَقَالَ عَبْدُ اللَّهِ لَوْ رُخِّصَ لَهُمْ فِي هَذَا لَأَوْشَكُوا إِذَا بَرَدَ عَلَيْهِمْ الْمَاءُ أَنْ يَتَيَمَّمُوا بِالصَّعِيدِ فَقَالَ لَهُ أَبُو مُوسَى وَإِنَّمَا كَرِهْتُمْ هَذَا لِهَذَا قَالَ نَعَمْ فَقَالَ لَهُ أَبُو مُوسَى أَلَمْ تَسْمَعْ قَوْلَ عَمَّارٍ لِعُمَرَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ فَأَجْنَبْتُ فَلَمْ أَجِدَ الْمَاءَ فَتَمَرَّغْتُ فِي الصَّعِيدِ كَمَا تَتَمَرَّغُ الدَّابَّةُ ثُمَّ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَصْنَعَ هَكَذَا فَضَرَبَ بِيَدِهِ عَلَى الْأَرْضِ فَنَفَضَهَا ثُمَّ ضَرَبَ بِشِمَالِهِ عَلَى يَمِينِهِ وَبِيَمِينِهِ عَلَى شِمَالِهِ عَلَى الْكَفَّيْنِ ثُمَّ مَسَحَ وَجْهَهُفَقَالَ لَهُ عَبْدُ اللَّهِ أَفَلَمْ تَرَ عُمَرَ لَمْ يَقْنَعْ بِقَوْلِ عَمَّارٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al-Anbari] telah menceritakan kepada kami [Abu Mu'awiyah Adl-Dlarir] dari [Al-A'masy] dari [Syaqiq] dia berkata; Saya pernah duduk di antara Abdulah dan Abu Musa. Lalu [Abu Musa] berkata; Wahai Abu Abdurrahman! Apakah kamu mengetahui, seandainya ada seseorang yang junub, kemudian dia tidak mendapatkan air selama satu bulan, bukankah dia harus bertayamum? Abdullah menjawab; Tidak, walaupun dia tidak mendapatkan air selama satu bulan. Lalu Abu Musa berkata; Bagaimanakah sikap anda terhadap ayat yang terdapat dalam surat Al- Maidah ini? Yaitu (yang artinya): \"… lalu kamu tidak mendapatkan air, maka bertayammumlah dengan debu tanah yang baik (bersih) \". (QS. Almaidah 6), Maka Abdullah menjawab; Kalau mereka diberi hukum keringanan tentang ini, dikhawatirkan mereka akan bertayammum dengan debu, kalau mereka merasa kedinginan memakai air. Kata Abu Musa kepadanya; Ternyata kamu tidak menyukai tayamum ini karena untuk alasan ini? Kata Abdullah; Ya. Kata Abu Musa kepadanya; Apakah kamu tidak pernah mendengar ucapan [Ammar] kepada Umar, yaitu Rasulullah shallallahu 'alaihi wasallam pernah mengutusku dalam suatu keperluan, lalu saya junub dan tidak mendapatkan air, sehingga saya berguling-guling di atas tanah, sebagaimana binatang yang sedang berguling-guling. Kemudian saya pergi menghadap kepada Nabi shallallahu 'alaihi wasallam dan menyampaikan hal tersebut kepada beliau, lalu beliau bersabda: \"Cukuplah kamu lakukan demikian ini.\" Lalu beliau menepukkan tangan ke tanah, lalu ditiupnya, kemudian beliau mengusap tangan kanannya dengan tangan kirinya dan tangan kirinya dengan tangan kanannya pada kedua telapak tangan, kemudian mengusap wajahnya. Maka Abdullah berkata kepada Abu Musa; Apakah kamu tidak tahu, bahwa Umar tidak puas terhadap ucapan Ammar? "},{"p":"Ahmad","n":2061,"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ قَالَكُنْتُ جَالِسًا مَعَ أَبِي مُوسَى وَعَبْدِ اللَّهِ قَالَ فَقَالَ أَبُو مُوسَى يَا أَبَا عَبْدِ الرَّحْمَنِ أَرَأَيْتَ لَوْ أَنَّ رَجُلًا لَمْ يَجِدْ الْمَاءَ وَقَدْ أَجْنَبَ شَهْرًا مَا كَانَ يَتَيَمَّمُ قَالَ لَا وَلَوْ لَمْ يَجِدْ الْمَاءَ شَهْرًا قَالَ فَقَالَ لَهُ أَبُو مُوسَى فَكَيْفَ تَصْنَعُونَ بِهَذِهِ الْآيَةِ فِي سُورَةِ الْمَائِدَةِ{ فَلَمْ تَجِدُوا مَاءً فَتَيَمَّمُوا صَعِيدًا طَيِّبًا }قَالَ فَقَالَ عَبْدُ اللَّهِ لَوْ رُخِّصَ لَهُمْ فِي هَذَا لَأَوْشَكُوا إِذَا بَرَدَ عَلَيْهِمْ الْمَاءُ أَنْ يَتَيَمَّمُوا الصَّعِيدَ ثُمَّ يُصَلُّوا قَالَ فَقَالَ لَهُ أَبُو مُوسَى إِنَّمَا كَرِهْتُمْ ذَا لِهَذَا قَالَ نَعَمْ قَالَ لَهُ أَبُو مُوسَى أَلَمْ تَسْمَعْ لِقَوْلِ عَمَّارٍ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ فَأَجْنَبْتُ فَلَمْ أَجِدْ الْمَاءَ فَتَمَرَّغْتُ فِي الصَّعِيدِ كَمَا تَمَرَّغُ الدَّابَّةُ ثُمَّ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَقُولَ وَضَرَبَ بِيَدِهِ عَلَى الْأَرْضِ ثُمَّ مَسَحَ كُلَّ وَاحِدَةٍ مِنْهُمَا بِصَاحِبَتِهَا ثُمَّ مَسَحَ بِهَا وَجْهَهُ لَمْ يُجِزْ الْأَعْمَشُ الْكَفَّيْنِ قَالَ فَقَالَ لَهُ عَبْدُ اللَّهِ أَلَمْ تَزْعُمُوا لَمْ يَقْنَعْ بِقَوْلِ عَمَّارٍ وَقَالَ أَبُو مُعَاوِيَةَ مَرَّةً قَالَ فَضَرَبَ بِيَدِهِ عَلَى الْأَرْضِ ثُمَّ نَفَضَهَا ثُمَّ ضَرَبَ بِشِمَالِهِ عَلَى يَمِينِهِ وَبِيَمِينِهِ عَلَى شِمَالِهِ عَلَى الْكَفَّيْنِ ثُمَّ مَسَحَ وَجْهَهُ","trj":"Telah menceritakan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] ia berkata, aku pernah duduk bersama [Abu Musa] dan Abdullah. Kemudian Abu Musa berkata, \"Wahai Abu Abdurrahman, bagaimana menurutmu jika ada seorang laki-laki yang tidak mendapatkan air, sementara ia telah junub selama satu bulan, bolehkah ia betayammum?\" Ia menjawab, \"Tidak, meskipun ia tidak mendapatkan air.\" Syaqiq berkata, \"Maka Abu Musa bertanya, \"Lalu apa yang kalian perbuat berkenaan dengan ayat yang terdapat dalam surat Al Maidah (ayat: 6): '(Jika kamu tidak memperoleh air, maka bertayammumlah dengan tanah yang baik (bersih)?\" Maka Abdullah berkata, \"Sekiranya mereka diberi keringanan dalam masalah ini, niscaya mereka akan segera bertayammum dan shalat disaat air sangat dingin.\" Kemudian Abu Musa bertanya kepadanya, \"Apakah hanya karena ini kalian tidak menyukainya?\" Abdullah menjawab, \"Ya.\" Abu Musa berkata lagi kepadanya, \"Tidakkah kamu mendengar ungkapan [Ammar], \"Rasulullah shallallahu 'alaihi wasallam pernah mengutusku untuk suatu keperluan. Lalu aku junub dan tidak mendapatkan air, maka aku pun berguling-guling di hamparan tanah sebagaimana bergulingnya binatang. Kemudian aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan menuturkan hal itu. Beliau bersabda: 'Cukup bagimu mengatakan, kemudian beliau menepukkan tangannya di atas tanah dan mengusapkannya pada kedua tangan dan wajahnya.\" -Al A'masy tidak membatasi pada kedua telapak tangan.- Maka Abdullah pun berkata, \"Tidakkah kalian mengira bahwa beliau belum merasa puas dengan ungkapannya Ammar?\" Sekali waktu Abu Mu'awiyah menyebutkan, \"Kemudian beliau menepukkan kedua tangannya di atas tanah lalu mengibaskannya dan mengusapkan telapak tangan kirinya ke telapak tangan kanan, kemudian telapak tangan kanannya ke atas telapak tangan kiri. Setelah itu, beliau mengusap wajahnya.\""},{"p":"Bukhari","n":334,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَكُنْتُ جَالِسًا مَعَ عَبْدِ اللَّهِ وَأَبِي مُوسَى الْأَشْعَرِيِّ فَقَالَ لَهُ أَبُو مُوسَى لَوْ أَنَّ رَجُلًا أَجْنَبَ فَلَمْ يَجِدْ الْمَاءَ شَهْرًا أَمَا كَانَ يَتَيَمَّمُ وَيُصَلِّي فَكَيْفَ تَصْنَعُونَ بِهَذِهِ الْآيَةِ فِي سُورَةِ الْمَائِدَةِ{ فَلَمْ تَجِدُوا مَاءً فَتَيَمَّمُوا صَعِيدًا طَيِّبًا }فَقَالَ عَبْدُ اللَّهِ لَوْ رُخِّصَ لَهُمْ فِي هَذَا لَأَوْشَكُوا إِذَا بَرَدَ عَلَيْهِمْ الْمَاءُ أَنْ يَتَيَمَّمُوا الصَّعِيدَ قُلْتُ وَإِنَّمَا كَرِهْتُمْ هَذَا لِذَا قَالَ نَعَمْ فَقَالَ أَبُو مُوسَى أَلَمْ تَسْمَعْ قَوْلَ عَمَّارٍ لِعُمَرَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ ف��أَجْنَبْتُ فَلَمْ أَجِد الْمَاءَ فَتَمَرَّغْتُ فِي الصَّعِيدِ كَمَا تَمَرَّغُ الدَّابَّةُ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَصْنَعَ هَكَذَا فَضَرَبَ بِكَفِّهِ ضَرْبَةً عَلَى الْأَرْضِ ثُمَّ نَفَضَهَا ثُمَّ مَسَحَ بِهِمَا ظَهْرَ كَفِّهِ بِشِمَالِهِ أَوْ ظَهْرَ شِمَالِهِ بِكَفِّهِ ثُمَّ مَسَحَ بِهِمَا وَجْهَهُ فَقَالَ عَبْدُ اللَّهِ أَفَلَمْ تَرَ عُمَرَ لَمْ يَقْنَعْ بِقَوْلِ عَمَّارٍوَزَادَ يَعْلَى عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ كُنْتُ مَعَ عَبْدِ اللَّهِ وَأَبِي مُوسَى فَقَالَ أَبُو مُوسَى أَلَمْ تَسْمَعْ قَوْلَ عَمَّارٍ لِعُمَرَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَنِي أَنَا وَأَنْتَ فَأَجْنَبْتُ فَتَمَعَّكْتُ بِالصَّعِيدِ فَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْنَاهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ هَكَذَا وَمَسَحَ وَجْهَهُ وَكَفَّيْهِ وَاحِدَةً","trj":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] ia berkata; Aku pernah duduk bersama 'Abdullah bin Mas'ud dan [Abu Musa Al Asy'ari]. Lalu Abu Musa berkata kepadanya, \"Seandainya ada seseorang mengalami junub dan tidak mendapatkan air selama satu bulan, apakah dia bertayamum dan shalat? Dan bagaimana pendapatmu dengan ayat ini di dalam Surah Al Maidah ayat 6: '(Lalu kamu tidak memperaleh air, maka bertayammumlah dengan tanah yang baik (bersih) '? 'Abdullah, \"Seandainya mereka diberi keringanan dalam masalah ini, bisa jadi nantinya bila ada seseorang dari mereka yang kedinginan dengan air dia akan bertayamum dengan tanah.\" Syaqiq bertanya, \"Apakah kalian tidak suka masalah ini karena faktor itu?\" Dia menjawab, \"Ya.\" Kemudian Abu Musa berkata, \"Tidakkah kamu pernah mendengar ucapan ['Ammar] kepada Umar, 'Rasulullah shallallahu 'alaihi wasallam mengutusku dalam suatu urusan, aku lalu junub dan tidak mendapatkan air. Maka aku pun berguling-guling di atas tanah seperti berguling-gulingnya hewan. Kemudian aku ceritakan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Sebenarnya cukup buatmu bila kamu melakukan begini.\" Nabi shallallahu 'alaihi wasallam kemudian memukulkan telapak tangannya ke permukaan tanah dan mengibaskannya, lalu mengusap punggung tangan kanannya dengan telapak tangan kirinya, atau punggung telapak kirinya dengan telapak tangan kanannya, kemudian beliau mengusap wajahnya.\" Abdullah berkata, \"Apakah kamu tidak tahu kalau 'Umar tidak menerima pendapat 'Ammar?\" [Ya'la] menambahkan dari [Al A'masy] dari [Syaqiq], \"Aku pernah bersama 'Abdullah dan Abu Musa. [Abu Musa] lalu berkata, \"Tidakkah kamu mendengar perkataan ['Ammar] kepada 'Umar 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam mengutus aku dan kamu, lalu aku mengalami junub dan aku bergulingan di atas tanah. Kemudian kita temui Rasulullah shallallahu 'alaihi wasallam menceritakan hal itu kepada beliau. Beliau lalu bersabda: \"Sebenarnya kamu cukup melakukan begini.\" Beliau lalu memukulkan telapak tangannya ke tanah, lalu mengusap muka dan kedua telapak tangannya sekali.\""},{"p":"Darimi","n":422,"ar":" حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مَسْعُودُ بْنُ عَلِيٍّ عَنْ عِكْرِمَةَ أَنَّ سَعْدًا كَانَ يُصَلِّي الصَّلَوَاتِ كُلَّهَا بِوُضُوءٍ وَاحِدٍ وَأَنَّ عَلِيًّا كَانَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ وَتَلَا هَذِهِ الْآيَةَ { إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ وَأَيْدِيَكُمْ } الْآيَةَ","trj":"Telah menceritakan kepada kami [Abdus Shamad bin Abdul Warits] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Mas'ud bin Ali] dari ['Ikrimah]. Bahwasanya [Sa'ad] menunaikan beberapa shalat dengan satu wudhu, sedangkan [Ali] selalu berwudhu untuk setiap shalat, dan ia membaca ayat ini: \"IDZAA QUMTUM ILAS SHALATI FAGHSILUU WUJUUHAKUM WA AIDIYAKUM...\" (Apabila kalian hendak menunaikan shalat basuhlah wajah dan kedua tanganmu...) -Qs. Al Ma`idah: 6-\"."},{"p":"Darimi","n":424,"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ حَتَّى كَانَ يَوْمُ فَتْحِ مَكَّةَ صَلَّى الصَّلَوَاتِ بِوُضُوءٍ وَاحِدٍ وَمَسَحَ عَلَى خُفَّيْهِ فَقَالَ لَهُ عُمَرُ رَأَيْتُكَ صَنَعْتَ شَيْئًا لَمْ تَكُنْ تَصْنَعُهُ قَالَ إِنِّي عَمْدًا صَنَعْتُ يَا عُمَرُ قَالَ أَبُو مُحَمَّد فَدَلَّ فِعْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ مَعْنَى قَوْلِ اللَّهِ تَعَالَى { إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ } الْآيَةَ لِكُلِّ مُحْدِثٍ لَيْسَ لِلطَّاهِرِ وَمِنْهُ قَوْلُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وُضُوءَ إِلَّا مِنْ حَدَثٍ وَاللَّهُ أَعْلَمُ","trj":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Ibnu Buraidah] dari [ayahnya] ia berkata: \"Rasulullah shallallahu 'alaihi wasallam selalu berwudhu untuk setiap shalatnya hingga hari fathu Makkah (penaklukan kota Makkah), beliau shalat beberapa waktu shalat dengan satu wudhu, dan beliau (cukup) mengusap kedua khufnya, lalu Umar bertanya kepada beliau: 'Aku melihat kamu melakukan sesuatu yang belum pernah kamu lakukan sebelumnya? ', beliau menjawab: 'Aku melakukan itu dengan sengaja wahai Umar', Abu Muhammad berkata: 'Perbuatan Rasulullah shallallahu 'alaihi wasallam ini (menunjukkan) bahwa makna firman Allah subhanallahu wa ta'aa: \"IDZAA QUMTUM ILASSHALATI FAGHSILUU WUJUHAKUM\" (Apabila kalian hendak menunaikan shalat, hendaklah ia membasuh wajah kalian) -Qs. Al Ma`idah: 6- itu untuk setiap orang yang berhadats dan bukan untuk orang yang masih suci, (yang semakna) diantaranya sabdanya: 'Tidaklah wajib wudhu itu melainkan untuk orang yang berhadats.\""}],"5:13":[{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."}],"5:23":[{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."}],"5:33":[{"p":"Abu Dawud","n":3682,"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ قَوْمًا مِنْ عُكْلٍ أَوْ قَالَ مِنْ عُرَيْنَةَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْتَوَوْا الْمَدِينَةَ فَأَمَرَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلِقَاحٍ وَأَمَرَهُمْ أَنْ يَشْرَبُوا مِنْ أَبْوَالِهَا وَأَلْبَانِهَا فَانْطَلَقُوا فَلَمَّا صَحُّوا قَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا النَّعَمَ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَبَرُهُمْ مِنْ أَوَّلِ النَّهَارِ فَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آثَارِهِمْ فَمَا ارْ��َفَعَ النَّهَارُ حَتَّى جِيءَ بِهِمْ فَأَمَرَ بِهِمْ فَقُطِعَتْ أَيْدِيهِمْ وَأَرْجُلُهُمْ وَسُمِرَ أَعْيُنُهُمْ وَأُلْقُوا فِي الْحَرَّةِ يَسْتَسْقُونَ فَلَا يُسْقَوْنَقَالَ أَبُو قِلَابَةَ فَهَؤُلَاءِ قَوْمٌ سَرَقُوا وَقَتَلُوا وَكَفَرُوا بَعْدَ إِيمَانِهِمْ وَحَارَبُوا اللَّهَ وَرَسُولَهُ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ بِإِسْنَادِهِ بِهَذَا الْحَدِيثِ قَالَ فِيهِ فَأَمَرَ بِمَسَامِيرَ فَأُحْمِيَتْ فَكَحَلَهُمْ وَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَمَا حَسَمَهُمْ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ قَالَ أَخْبَرَنَا ح و حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ بِهَذَا الْحَدِيثِ قَالَ فِيهِ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَلَبِهِمْ قَافَةً فَأُتِيَ بِهِمْ قَالَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى فِي ذَلِكَ{ إِنَّمَا جَزَاءُ الَّذِينَ يُحَارِبُونَ اللَّهَ وَرَسُولَهُ وَيَسْعَوْنَ فِي الْأَرْضِ فَسَادًا }الْآيَةَ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ وَقَتَادَةُ وَحُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ ذَكَرَ هَذَا الْحَدِيثَ قَالَ أَنَسٌ فَلَقَدْ رَأَيْتُ أَحَدَهُمْ يَكْدِمُ الْأَرْضَ بِفِيهِ عَطَشًا حَتَّى مَاتُوا حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ هِشَامٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ بِهَذَا الْحَدِيثِ نَحْوَهُ زَادَ ثُمَّ نَهَى عَنْ الْمُثْلَةِ وَلَمْ يَذْكُرْ مِنْ خِلَافٍ وَرَوَاهُ شُعْبَةُ عَنْ قَتَادَةَ وَسَلَّامُ بْنُ مِسْكِينٍ عَنْ ثَابِتٍ جَمِيعًا عَنْ أَنَسٍ لَمْ يَذْكُرَا مِنْ خِلَافٍ وَلَمْ أَجِدْ فِي حَدِيثِ أَحَدٍ قَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ مِنْ خِلَافٍ إِلَّا فِي حَدِيثِ حَمَّادِ بْنِ سَلَمَةَ","trj":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] berkata, \"Beberapa orang dari 'Ukl, atau ia mengatakan, \"dari Urainah datang menemui Rasulullah shallallahu 'alaihi wasallam. Namun mereka tidak cocok dengan iklim Madinah (hingga jatuh sakit). Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan untuk menyediakan liqah (unta hamil) bagi mereka. Beliau perintahkan mereka minum air kencing dan susu unta tersebut. Mereka pun pergi (menuju kandang unta), namun ketika telah sembuh mereka justru membunuh pengembala Rasulullah shallallahu 'alaihi wasallam dan membawa lari unta-unta tersebut. Menjelang siang hari, berita yang menimpa mereka sampai kepada Nabi shallallahu 'alaihi wasallam, Nabi shallallahu 'alaihi wasallam lalu mengirim (beberapa orang) untuk mengikuti jejak mereka. Matahari belum tinggi, orang-orang tersebut telah ditangkap dan dihadapkan kepada beliau. Beliau pun memberi perintah untuk memberi hukuman kepada mereka, tangan dan kaki mereka lalu dipotong, matanya dicongkel kemudian mereka dibuang ke padang pasir. Mereka minta minum namun tidak diberi.\" [Abu Qilabah] berkata, \"Orang-orang itu telah mencuri dan membunuh, murtad setelah beriman, serta memerangi Allah dan Rasul-Nya.\" Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dengan sanadnya sebagaimana dalam hadits tersebut. Namun ia menambahkan dalam haditsnya, \"Beliau memerintahkan untuk mengambil beberapa paku yang dipanaskan, lalu mereka disayat (dengan paku tersebut), tangan dan kaki mereka juga dipotong, namun beliau tidak memerintahkan untuk menghentikan darah mereka dengan menempelkan besi panas.\" Telah menceritakan kepada kami [Muhammad bin Ash Shabbah bin Sufyan] ia berkata; telah mengabarkan kepada kami. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Amru bin Utsman] berkata, telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Yahya] -maksudnya Yahya bin Abu Katsir- dari [Abu Qilabah] dari [Anas bin Malik] dengan hadits yang sama. Dalam hadits tersebut ia mengatakan, \"Rasulullah shallallahu 'alaihi wasallam lalu mengirim teliksandi untuk mencari mereka, hingga akhirnya mereka tertangkap. Anas berkata, \"Allah Tabaaraka Wa Ta'ala lalu menurunkan ayat: '(Sesungguhnya pembalasan terhadap orang-orang yang memerangi Allah dan Rasul-Nya dan membuat kerusakan..) ' -Qs. Al Maidah: 33-. Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami [Tsabit] dan [Qatadah] dan [Humaid] dari [Anas bin Malik] ia lalu menyebutkan hadits tersebut. Anas berkata, \"Aku melihat salah seorang dari mereka menjilati bumi dengan mulutnya karena haus, hingga akhirnya mati.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] dari [Hisyam] dari [Qatadah] dari [Anas bin Malik] sama dengan hadits tersebut, namun ia menambahkan, \"kemudian beliau melarang untuk melakukan mutslah (Mutilasi atau menyayat mayat). dan ia tidak menyebut kata; 'min khilaf' (secara bersilang). [Syu'bah] juga meriwayatkan dari [Qatadah] dan [Salam bin Miskin], dari [Tsabit]. Semuanya juga berasal dari [Anas], namun keduanya juga tidak menyebutkan kata; min khilaf (dipotong tangan dan kakinya secara bersilang). Aku tidak pernah mendapatkan dalam hadits seorang pun yang menyebutkan; 'beliau memotong tangan dan kaki mereka secara bersilang', kecuali hadits hadits riwayat Hammad bin Salamah.\""}],"5:34":[{"p":"Ahmad","n":1671,"ar":"حَدَّثَنَا هِشَامُ بْنُ سَعِيدٍ حَدَّثَنَا حَسَنُ بْنُ أَيُّوبَ الْحَضْرَمِيُّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ نَاسِجٍ الْحَضْرَمِيُّ وَكَانَ قَدْ أَدْرَكَ أَبَا بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَمَنْ دُونَهُمَا عَنْ عُتْبَةَ بْنِ عَبْدٍ السُّلَمِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَصْحَابِهِ قُومُوا فَقَاتِلُوا قَالُوا نَعَمْ يَا رَسُولَ اللَّهِ وَلَا نَقُولُ كَمَا قَالَتْ بَنُو إِسْرَائِيلَ لِمُوسَى عَلَيْهِ السَّلَام انْطَلِقْ أَنْتَ وَرَبُّكَ فَقَاتِلَا إِنَّا هَاهُنَا قَاعِدُونَ وَلَكِنْ انْطَلِقْ أَنْتَ وَرَبُّكَ يَا مُحَمَّدُ فَقَاتِلَا وَإِنَّا مَعَكُمَا نُقَاتِلُ","trj":"Telah menceritakan kepada kami [Hisyam bin Sa'id] Telah menceritakan kepada kami [Hasan bin Ayyub Al Hadlrami] telah menceritakan kepadaku [Abdullah bin Nasij Al Hadlrami] -ia pernah bertemu dengan Abu Bakar dan Umar Radiallahu 'Anhuma dan orang-orang selain keduanya- dari Utbah bin Abdu As Sulami, bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: \"Berdiri dan berperanglah kalian!\" para sahabat menjawab, \"Kami siap wahai Rasulullah. Kami tidak akan mengatakan sebagaimana yang dikatakan oleh Banu Isara`il kepada Musa, '(Pergilah kamu bersama Tuhanmu, dan berperanglah kamu berdua, Sesungguhnya kami Hanya duduk menanti disini saja) ' (Qs. Al Maidah: 34). Akan tetapi, (kami akan katakan) pergilah kamu bersama Tuhanmu wahai Muhammad dan berperanglah, sesungguhnya kami bersamamu untuk berperang.\""}],"5:36":[{"p":"Muslim","n":294,"ar":"حَدَّثَنِي يُونُسُ بْنُ عَبْدِ الْأَعْلَى الصَّدَفِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ بَكْرَ بْنَ سَوَادَةَ حَدَّثَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلَا قَوْلَ اللَّهِ عَزَّ وَجَلَّ فِي إِبْرَاهِيمَ{ رَبِّ إِنَّهُنَّ أَضْلَلْنَ كَثِيرًا مِنْ النَّاسِ فَمَنْ تَبِعَنِي فَإِنَّهُ مِنِّي }الْآيَةَ وَقَالَ عِيسَى عَلَيْهِ السَّلَام{ إِنْ تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ وَإِنْ تَغْفِرْ لَهُمْ فَإِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ }فَرَفَعَ يَدَيْهِ وَقَالَ اللَّهُمَّ أُمَّتِي أُمَّتِي وَبَكَى فَقَالَ اللَّهُ عَزَّ وَجَلَّ يَا جِبْرِيلُ اذْهَبْ إِلَى مُحَمَّدٍ وَرَبُّكَ أَعْلَمُ فَسَلْهُ مَا يُبْكِيكَ فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَسَأَلَهُ فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا قَالَ وَهُوَ أَعْلَمُ فَقَالَ اللَّهُ يَا جِبْرِيلُ اذْهَبْ إِلَى مُحَمَّدٍ فَقُلْ إِنَّا سَنُرْضِيكَ فِي أُمَّتِكَ وَلَا نَسُوءُكَ","trj":"Telah menceritakan kepada kami [Yunus bin Abdul A'la ash-Shadafi] telah mengabarkan kepada kami [Ibnu Wahb] dia berkata, telah mengabarkan kepada kami [Amru bin al-Harits] bahwa [Bakr bin Sawadah] telah menceritakan kepadanya dari [Abdurrahman bin Jubair] dari [Abdullah bin Amr bin al-'Ash] bahwa Nabi shallallahu 'alaihi wasallam pernah membaca firman Allah mengenai Ibrahim: '(Ya Tuhanku, sesungguhnya berhala-berhala itu telah menyesatkan kebanyakan daripada manusia, maka barangsiapa yang mengikutiku, Maka Sesungguhnya orang itu termasuk golonganku) ' (Qs. Ibrahim: 36) hingga akhir ayat. Dan mengenai Isa Alaihissalam: '(Jika Engkau menyiksa mereka, maka sesungguhnya mereka adalah hamba-hamba Engkau, dan jika Engkau mengampuni mereka, maka sesungguhnya Engkaulah yang Maha Perkasa lagi Maha Bijaksana) ' (Qs. Al Maidah: 118), kemudian beliau mengangkat kedua tangannya seraya berdo'a: \"Ya Allah, selamatkanlah umatku, selamatkanlah umatku, \" dengan bercucuran air mata. Kemudian Allah 'azza wajalla berkata kepada malaikat Jibril: \"Temuilah Muhammad -dan Rabbmulah yang lebih tahu- dan tanyakan kepadanya, 'Apa yang membuatmu menangis? ' Maka malaikat Jibril pun bertanya kepada beliau, dan beliau shallallahu 'alaihi wasallam menjawabnya dengan apa yang dikatakan Allah-dan Allah lebih mengetahui hal itu-. Kemudian Allah berkata: 'Wahai Jibril, temuilah Muhammad dan katakan bahwa Kami akan membuatmu senang dengan umatmu dan tidak akan membuatmu sedih karenanya (Kami akan menyelamatkan semua umatmu-pent) '.\""}],"5:37":[{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""}],"5:38":[{"p":"Malik","n":1308,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ زُرَيْقِ بْنِ حَكِيمٍ أَنَّهُ أَخْبَرَهُ أَنَّهُ أَخَذَ عَبْدًا آبِقًا قَدْ سَرَقَ قَالَ فَأَشْكَلَ عَلَيَّ أَمْرُهُ قَالَ فَكَتَبْتُ فِيهِ إِلَى عُمَرَ بْنِ عَبْدِ الْعَزِيزِأَسْأَلُهُ عَنْ ذَلِكَ وَهُوَ الْوَالِي يَوْمَئِذٍ قَالَ فَأَخْبَرْتُهُ أَنَّنِي كُنْتُ أَسْمَعُ أَنَّ الْعَبْدَ الْآبِقَ إِذَا سَرَقَ وَهُوَ آبِقٌ لَمْ تُقْطَعْ يَدُهُ قَالَ فَكَتَبَ إِلَيَّ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ نَقِيضَ كِتَابِي يَقُولُ كَتَبْتَ إِلَيَّ أَنَّكَ كُنْتَ تَسْمَعُ أَنَّ الْعَبْدَ الْآبِقَ إِذَا سَرَقَ لَمْ تُقْطَعْ يَدُهُ وَإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ فِي كِتَابِهِ{ وَالسَّارِقُ وَالسَّارِقَةُ فَاقْطَعُوا أَيْدِيَهُمَا جَزَاءً بِمَا كَسَبَا نَكَالًا مِنْ اللَّهِ وَاللَّهُ عَزِيزٌ حَكِيمٌ }فَإِنْ بَلَغَتْ سَرِقَتُهُ رُبُعَ دِينَارٍ فَصَاعِدًا فَاقْطَعْ يَدَهُو حَدَّثَنِي عَنْ مَالِك أَنَّهُ بَلَغَهُ أَنَّ الْقَاسِمَ بْنَ مُحَمَّدٍ وَسَالِمَ بْنَ عَبْدِ اللَّهِ وَعُرْوَةَ بْنَ الزُّبَيْرِ كَانُوا يَقُولُونَ إِذَا سَرَقَ الْعَبْدُ الْآبِقُ مَا يَجِبُ فِيهِ الْقَطْعُ قُطِعَ قَالَ مَالِك وَذَلِكَ الْأَمْرُ الَّذِي لَا اخْتِلَافَ فِيهِ عِنْدَنَا أَنَّ الْعَبْدَ الْآبِقَ إِذَا سَرَقَ مَا يَجِبُ فِيهِ الْقَطْعُ قُطِعَ","trj":"Telah menceritakan kepadaku dari Malik dari [Zuraiq bin Hakim] ia mengabarkan kepadanya, bahwa ia menemukan seorang budak yang kabur setelah mencuri. Zuraiq melanjutkan; \"Hal ini mengundang masalah bagiku. Maka aku menulis surat kepada Umar bin Abdul Aziz yang saat itu menjadi gubernur, untuk menanyakan hal tersebut. Aku kabarkan kepadanya bahwa aku mendengar seorang hamba yang melarikan diri jika mencuri dan kabur, maka tangannya tidak dipotong.\" Zuraiq melanjutkan, \" [Umar bin Abdul Aziz] lalu membalas suratku dan mengatakan; 'Kamu menulis surat kepadaku bahwasanya kamu telah mendengar, jika seorang hamba yang melarikan diri mencuri lalu dia kabur, maka tidak dipotong tangannya, sedangkan Allah Tabaraka Wa Ta'ala dalam kitab-Nya berfirman; \"Seorang pencuri baik laki-laki maupun perempuan maka potonglah tangannya sebagai balasan dari perbuatannya dan hukuman dari Allah, dan Allah Maha Mulia dan Maha Bijaksana) ' (Qs. Al Maidah: 38) jika barang curiannya mencapai seperempat dinar atau lebih, maka potonglah tangannya.\" Telah menceritakan kepadaku dari Malik, bahwasanya telah sampai kepadanya, bahwa Al Qasim bin Muhammad dan Salim bin Abdullah dan 'Urwah bin Zubair mereka mengatakan; \"Jika budak yang melarikan diri mencuri sesuatu yang mencapai kewajiban untuk dipotong, maka tangannya dipotong.\" Malik berkata; \"Itu adalah perkara yang tidak ada perbedaan pendapat di antara kami, yaitu jika seorang hamba yang kabur mencuri barang yang mencapai kewajiban potonga tangan, maka tangannya harus dipotong.\""}],"5:41":[{"p":"Muslim","n":2979,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ كِلَاهُمَا عَنْ أَبِي مُعَاوِيَةَ قَالَ يَحْيَى أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَهُودِيٍّ مُحَمَّمًا مَجْلُودًا فَدَعَاهُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالُوا نَعَمْ فَدَعَا رَجُلًا مِنْ عُلَمَائِهِمْ فَقَالَ أَنْشُدُكَ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى أَهَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالَ لَا وَلَوْلَا أَنَّكَ نَشَدْتَنِي بِهَذَا لَمْ أُخْبِرْكَ نَجِدُهُ الرَّجْمَ وَلَكِنَّهُ كَثُرَ فِي أَشْرَافِنَا فَكُنَّا إِذَا أَخَذْنَا الشَّرِيفَ تَرَكْنَاهُ وَإِذَا أَخَذْنَا الضَّعِيفَ أَقَمْنَا عَلَيْهِ الْحَدَّ قُلْنَا تَعَالَوْا فَلْنَجْتَمِعْ عَلَى شَيْءٍ نُقِيمُهُ عَلَى الشَّرِيفِ وَالْوَضِيعِ فَجَعَلْنَا التَّحْمِيمَ وَالْجَلْدَ مَكَانَ الرَّجْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَوَّلُ مَنْ أَحْيَا أَمْرَكَ إِذْ أَمَاتُوهُ فَأَمَرَ بِهِ فَرُجِمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَا أَيُّهَا الرَّسُولُ لَا يَحْزُنْكَ الَّذِينَ يُسَارِعُونَ فِي الْكُفْرِ }إِلَى قَوْلِهِ{ إِنْ أُوتِيتُمْ هَذَا فَخُذُوهُ }يَقُولُ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ أَمَرَكُمْ بِالتَّحْمِيمِ وَالْجَلْدِ فَخُذُوهُ وَإِنْ أَفْتَاكُمْ بِالرَّجْمِ فَاحْذَرُوا فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الظَّالِمُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْفَاسِقُونَ }فِي الْكُفَّارِ كُلُّهَاحَدَّثَنَا ابْنُ نُمَيْرٍ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَى قَوْلِهِ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ وَلَمْ يَذْكُرْ مَا بَعْدَهُ مِنْ نُزُولِ الْآيَةِ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] keduanya dari [Abu Mu'awiyah], [Yahya] berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Al Barra` bin 'Azib] dia berkata, \"Suatu ketika seorang Yahudi yang dicat hitam dan didera lewat di hadapan Nabi shallallahu 'alaihi wasallam, kemudian beliau memanggil mereka seraya bersabda: \"Beginikah hukuman zina yang kalian dapati dalam kitab Taurat kalian?\" mereka menjawab, \"Ya benar.\" Lalu beliau memanggil seorang laki-laki yang tergolong dari ulama mereka, beliau bertanya: \"Aku mengharap kamu mau bersumpah dengan nama Allah yang telah menurunkan kitab Taurat kepada Musa, betulkah begini caranya hukuman zina yang kalian dapati dalam kitab tauratmu?\" dia menjawab, \"Tidak, seandainya anda tidak menyumpahku dengan nama Allah, aku tidak akan mengatakan yang sebenarnya kepada anda. Dan yang kami ketahui dalam kitab Taurat, hukumannya adalah rajam, akan tetapi biasanya hukuman itu tidak berlaku bagi pembesar-pembesar kami, jika yang tertangkap itu dari pembesar, maka kami biarkan begitu saja, akan tetapi jika yang tertangkap rakyat kecil maka kami tegakkan hukum sesuai Taurat. Akhirnya kami bermusyawarah, membicarakan hukum yang dapat kami tegakkan bagi pembesar dan rakyat biasa. Lalu kami putuskan untuk membuat hitam tubuh dan mendera pelaku zina sebagai pengganti hukum rajam.\" Setelah laki-laki itu selesai bicara, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sesungguhnya akulah orang yang pertama-tama menghidupkan kembali sunnah-Mu setelah mereka hapus perintah tersebut.\" Setelah itu, beliau memerintahkan supaya Yahudi yang berzina itu dihukum rajam, lalu Allah 'azza wajalla menurunkan ayat: '(Wahai rasul, janganlah kamu merasa sedih, karena orang-orang yang bersegera menuju kekafiran -hingga firman-Nya- Jika diberikan ini kepadamu, maka terimalah) ' (Qs. Al Maidah: 41). Orang-orang Yahudi berkata, \"Datanglah kalian kepada Muhammad shallallahu 'alaihi wasallam, jika beliau memutuskan hukuman kepadamu dengan menghitamkan tubuh dan didera, maka terimalah, namun jika dia berfatwa kepadamu dengan hukuman rajam, maka waspadalah. Maka Allah Ta'ala menurunkan ayat: '(Barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang kafir. Dan barangsiapa tidak berhukum dengan sesuatu yang telah diturunkan Allah, maka mereka itu adalah orang-orang yang Zhalim. Dan barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang fasik' (Qs. Al Maidah: 44- 47). Hal ini juga berlaku kepada orang-orang kafir semuanya.\" Telah menceritakan kepada kami [Ibnu Numair] dan [Abu Sa'id Al Asyaj] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dengan isnad seperti ini sampai kepada perkataannya, \"Lalu Nabi shallallahu 'alaihi wasallam memerintahkan untuk merajmanya, akhirnya dia pun dirajam.\" Dan tidak menyebutkan sesuatu setelahnya seperti turunnya ayat.\""}],"5:42":[{"p":"Abu Dawud","n":3039,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ فَإِنْ جَاءُوكَ فَاحْكُمْ بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ }فَنُسِخَتْ قَالَ{ فَاحْكُمْ بَيْنَهُمْ بِمَا أَنْزَلَ اللَّهُ }","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepadaku [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Ayat: '(Jika mereka (orang Yahudi) datang kepadamu (untuk meminta putusan), maka putuskanlah (perkara itu) diantara mereka, atau berpalinglah dari mereka) ' (Qs. Al Maidah: 42), dihapus dan diganti dengan ayat: '(maka putuskanlah perkara mereka menurut apa yang Allah turunkan) ' (Qs. Al Maidah: 48). "},{"p":"Abu Dawud","n":3040,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ فَإِنْ جَاءُوكَ فَاحْكُمْ بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ }{ وَإِنْ حَكَمْتَ فَاحْكُمْ بَيْنَهُمْ بِالْقِسْطِ }الْآيَةُ قَالَ كَانَ بَنُو النَّضِيرِ إِذَا قَتَلُوا مِنْ بَنِي قُرَيْظَةَ أَدَّوْا نِصْفَ الدِّيَةِ وَإِذَا قَتَلَ بَنُو قُرَيْظَةَ مِنْ بَنِي النَّضِيرِ أَدَّوْا إِلَيْهِمْ الدِّيَةَ كَامِلَةً فَسَوَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمْ","trj":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Daud bin Al Hushain] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Tatkala turun ayat ini: '(Jika mereka (orang Yahudi) datang kepadamu (untuk meminta putusan), maka putuskanlah (perkara itu) diantara mereka, atau berpalinglah dari mereka; jika kamu berpaling dari mereka maka mereka tidak akan memberi mudharat kepadamu sedikitpun. Dan jika kamu memutuskan perkara mereka, maka putuskanlah (perkara itu) diantara mereka dengan adil) ' (Qs. Al Maidah: 42), Ibnu Abbas berkata, \"Dahulu jika orang-orang Bani An Nadlir membunuh orang dari Bani Quraizhah maka mereka memberikan setengah diyat (tebusan), dan apabila Bani Quraizhah membunuh sebagian orang dari Bani An Nazlir, maka mereka menunaikan diyat secara penuh. Lalu Rasulullah shallallahu 'alaihi wasallam menyamaratakan besaran diyat di antara mereka.\""}],"5:43":[{"p":"Tirmidzi","n":2845,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."}],"5:44":[{"p":"Abu Dawud","n":3027,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ بْنِ أَبِي يَحْيَى الرَّمْلِيُّ حَدَّثَنَا زَيْدُ بْنُ أَبِي الزَّرْقَاءِ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ إِلَى قَوْلِهِ الْفَاسِقُونَ }هَؤُلَاءِ الْآيَاتِ الثَّلَاثِ نَزَلَتْ فِي الْيَهُودِ خَاصَّةً فِي قُرَيْظَةَ وَالنَّضِيرِ","trj":"Telah menceritakan kepada kami [Ibrahim bin Hamzah bin Abu Yahya Ar Ramli] telah menceritakan kepada kami [Zaid bin Abu Az Zarqa`] telah menceritakan kepada kami [Ibnu Az Zinad] dari [Ayahnya] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] ia membaca ayat: '(Barangsiapa yang tidak memutuskan menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang kafir) ' hingga firman Allah: '(…… orang-orang yang fasik) ' (Qs. Al Maidah: 44-47). ketiga ayat tersebut turun mengenai orang-orang Yahudi, khususnya orang-orang Bani Quraizhah dan An Nazlir.\""},{"p":"Muslim","n":2979,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ كِلَاهُمَا عَنْ أَبِي مُعَاوِيَةَ قَالَ يَحْيَى أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَهُودِيٍّ مُحَمَّمًا مَجْلُودًا فَدَعَاهُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالُوا نَعَمْ فَدَعَا رَجُلًا مِنْ عُلَمَائِهِمْ فَقَالَ أَنْشُدُكَ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى أَهَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالَ لَا وَلَوْلَا أَنَّكَ نَشَدْتَنِي بِهَذَا لَمْ أُخْبِرْكَ نَجِدُهُ الرَّجْمَ وَلَكِنَّهُ كَثُرَ فِي أَشْرَافِنَا فَكُنَّا إِذَا أَخَذْنَا الشَّرِيفَ تَرَكْنَاهُ وَإِذَا أَخَذْنَا الضَّعِيفَ أَقَمْنَا عَلَيْهِ الْحَدَّ قُلْنَا تَعَالَوْا فَلْنَجْتَمِعْ عَلَى شَيْءٍ نُقِيمُهُ عَلَى الشَّرِيفِ وَالْوَضِيعِ فَجَعَلْنَا التَّحْمِيمَ وَالْجَلْدَ مَكَانَ الرَّجْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَوَّلُ مَنْ أَحْيَا أَمْرَكَ إِذْ أَمَاتُوهُ فَأَمَرَ بِهِ فَرُجِمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَا أَيُّهَا الرَّسُولُ لَا يَحْزُنْكَ الَّذِينَ يُسَارِعُونَ فِي الْكُفْرِ }إِلَى قَوْلِهِ{ إِنْ أُوتِيتُمْ هَذَا فَخُذُوهُ }يَقُولُ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ أَمَرَكُمْ بِالتَّحْمِيمِ وَالْجَلْدِ فَخُذُوهُ وَإِنْ أَفْتَاكُمْ بِالرَّجْمِ فَاحْذَرُوا فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الظَّالِمُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْفَاسِقُونَ }فِي الْكُفَّارِ كُلُّهَاحَدَّثَنَا ابْنُ نُمَيْرٍ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَى قَوْلِهِ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ وَلَمْ يَذْكُرْ مَا بَعْدَهُ مِنْ نُزُولِ الْآيَةِ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] keduanya dari [Abu Mu'awiyah], [Yahya] berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Al Barra` bin 'Azib] dia berkata, \"Suatu ketika seorang Yahudi yang dicat hitam dan didera lewat di hadapan Nabi shallallahu 'alaihi wasallam, kemudian beliau memanggil mereka seraya bersabda: \"Beginikah hukuman zina yang kalian dapati dalam kitab Taurat kalian?\" mereka menjawab, \"Ya benar.\" Lalu beliau memanggil seorang laki-laki yang tergolong dari ulama mereka, beliau bertanya: \"Aku mengharap kamu mau bersumpah dengan nama Allah yang telah menurunkan kitab Taurat kepada Musa, betulkah begini caranya hukuman zina yang kalian dapati dalam kitab tauratmu?\" dia menjawab, \"Tidak, seandainya anda tidak menyumpahku dengan nama Allah, aku tidak akan mengatakan yang sebenarnya kepada anda. Dan yang kami ketahui dalam kitab Taurat, hukumannya adalah rajam, akan tetapi biasanya hukuman itu tidak berlaku bagi pembesar-pembesar kami, jika yang tertangkap itu dari pembesar, maka kami biarkan begitu saja, akan tetapi jika yang tertangkap rakyat kecil maka kami tegakkan hukum sesuai Taurat. Akhirnya kami bermusyawarah, membicarakan hukum yang dapat kami tegakkan bagi pembesar dan rakyat biasa. Lalu kami putuskan untuk membuat hitam tubuh dan mendera pelaku zina sebagai pengganti hukum rajam.\" Setelah laki-laki itu selesai bicara, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sesungguhnya akulah orang yang pertama-tama menghidupkan kembali sunnah-Mu setelah mereka hapus perintah tersebut.\" Setelah itu, beliau memerintahkan supaya Yahudi yang berzina itu dihukum rajam, lalu Allah 'azza wajalla menurunkan ayat: '(Wahai rasul, janganlah kamu merasa sedih, karena orang-orang yang bersegera menuju kekafiran -hingga firman-Nya- Jika diberikan ini kepadamu, maka terimalah) ' (Qs. Al Maidah: 41). Orang-orang Yahudi berkata, \"Datanglah kalian kepada Muhammad shallallahu 'alaihi wasallam, jika beliau memutuskan hukuman kepadamu dengan menghitamkan tubuh dan didera, maka terimalah, namun jika dia berfatwa kepadamu dengan hukuman rajam, maka waspadalah. Maka Allah Ta'ala menurunkan ayat: '(Barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang kafir. Dan barangsiapa tidak berhukum dengan sesuatu yang telah diturunkan Allah, maka mereka itu adalah orang-orang yang Zhalim. Dan barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang fasik' (Qs. Al Maidah: 44- 47). Hal ini juga berlaku kepada orang-orang kafir semuanya.\" Telah menceritakan kepada kami [Ibnu Numair] dan [Abu Sa'id Al Asyaj] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dengan isnad seperti ini sampai kepada perkataannya, \"Lalu Nabi shallallahu 'alaihi wasallam memerintahkan untuk merajmanya, akhirnya dia pun dirajam.\" Dan tidak menyebutkan sesuatu setelahnya seperti turunnya ayat.\""}],"5:45":[{"p":"Abu Dawud","n":3027,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ بْنِ أَبِي يَحْيَى الرَّمْلِيُّ حَدَّثَنَا زَيْدُ بْنُ أَبِي الزَّرْقَاءِ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ إِلَى قَوْلِهِ الْفَاسِقُونَ }هَؤُلَاءِ الْآيَاتِ الثَّلَاثِ نَزَلَتْ فِي الْيَهُودِ خَاصَّةً فِي قُرَيْظَةَ وَالنَّضِيرِ","trj":"Telah menceritakan kepada kami [Ibrahim bin Hamzah bin Abu Yahya Ar Ramli] telah menceritakan kepada kami [Zaid bin Abu Az Zarqa`] telah menceritakan kepada kami [Ibnu Az Zinad] dari [Ayahnya] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] ia membaca ayat: '(Barangsiapa yang tidak memutuskan menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang kafir) ' hingga firman Allah: '(…… orang-orang yang fasik) ' (Qs. Al Maidah: 44-47). ketiga ayat tersebut turun mengenai orang-orang Yahudi, khususnya orang-orang Bani Quraizhah dan An Nazlir.\""},{"p":"Abu Dawud","n":3375,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنَا يُونُسُ بْنُ يَزِيدَ عَنْ أَبِي عَلِيِّ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَالْعَيْنُ بِالْعَيْنِ }","trj":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Muhammad bin Al 'Ala] mereka berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah menceritakan kepada kami [Yunus bin Yazid] dari [Abu Ali bin Yazid] dari [Az Zuhri] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membaca ayat: '(... dan mata dengan mata) ' (Qs. Al Maidah: 45). "},{"p":"Muslim","n":2979,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ كِلَاهُمَا عَنْ أَبِي مُعَاوِيَةَ قَالَ يَحْيَى أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَهُودِيٍّ مُحَمَّمًا مَجْلُودًا فَدَعَاهُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالُوا نَعَمْ فَدَعَا رَجُلًا مِنْ عُلَمَائِهِمْ فَقَالَ أَنْشُدُكَ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى أَهَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالَ لَا وَلَوْلَا أَنَّكَ نَشَدْتَنِي بِهَذَا لَمْ أُخْبِرْكَ نَجِدُهُ الرَّجْمَ وَلَكِنَّهُ كَثُرَ فِي أَشْرَافِنَا فَكُنَّا إِذَا أَخَذْنَا الشَّرِيفَ تَرَكْنَاهُ وَإِذَا أَخَذْنَا الضَّعِيفَ أَقَمْنَا عَلَيْهِ الْحَدَّ قُلْنَا تَعَالَوْا فَلْنَجْتَمِعْ عَلَى شَيْءٍ نُقِيمُهُ عَلَى الشَّرِيفِ وَالْوَضِيعِ فَجَعَلْنَا التَّحْمِيمَ وَالْجَلْدَ مَكَانَ الرَّجْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَوَّلُ مَنْ أَحْيَا أَمْرَكَ إِذْ أَمَاتُوهُ فَأَمَرَ بِهِ فَرُجِمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَا أَيُّهَا الرَّسُولُ لَا يَحْزُنْكَ الَّذِينَ يُسَارِعُونَ فِي الْكُفْرِ }إِلَى قَوْلِهِ{ إِنْ أُوتِيتُمْ هَذَا فَخُذُوهُ }يَقُولُ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ أَمَرَكُمْ بِالتَّحْمِيمِ وَالْجَلْدِ فَخُذُوهُ وَإِنْ أَفْتَاكُمْ بِالرَّجْمِ فَاحْذَرُوا فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الظَّالِمُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْفَاسِقُونَ }فِي الْكُفَّارِ كُلُّهَاحَدَّثَنَا ابْنُ نُمَيْرٍ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَى قَوْلِهِ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ وَلَمْ يَذْكُرْ مَا بَعْدَهُ مِنْ نُزُولِ الْآيَةِ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] keduanya dari [Abu Mu'awiyah], [Yahya] berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Al Barra` bin 'Azib] dia berkata, \"Suatu ketika seorang Yahudi yang dicat hitam dan didera lewat di hadapan Nabi shallallahu 'alaihi wasallam, kemudian beliau memanggil mereka seraya bersabda: \"Beginikah hukuman zina yang kalian dapati dalam kitab Taurat kalian?\" mereka menjawab, \"Ya benar.\" Lalu beliau memanggil seorang laki-laki yang tergolong dari ulama mereka, beliau bertanya: \"Aku mengharap kamu mau bersumpah dengan nama Allah yang telah menurunkan kitab Taurat kepada Musa, betulkah begini caranya hukuman zina yang kalian dapati dalam kitab tauratmu?\" dia menjawab, \"Tidak, seandainya anda tidak menyumpahku dengan nama Allah, aku tidak akan mengatakan yang sebenarnya kepada anda. Dan yang kami ketahui dalam kitab Taurat, hukumannya adalah rajam, akan tetapi biasanya hukuman itu tidak berlaku bagi pembesar-pembesar kami, jika yang tertangkap itu dari pembesar, maka kami biarkan begitu saja, akan tetapi jika yang tertangkap rakyat kecil maka kami tegakkan hukum sesuai Taurat. Akhirnya kami bermusyawarah, membicarakan hukum yang dapat kami tegakkan bagi pembesar dan rakyat biasa. Lalu kami putuskan untuk membuat hitam tubuh dan mendera pelaku zina sebagai pengganti hukum rajam.\" Setelah laki-laki itu selesai bicara, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sesungguhnya akulah orang yang pertama-tama menghidupkan kembali sunnah-Mu setelah mereka hapus perintah tersebut.\" Setelah itu, beliau memerintahkan supaya Yahudi yang berzina itu dihukum rajam, lalu Allah 'azza wajalla menurunkan ayat: '(Wahai rasul, janganlah kamu merasa sedih, karena orang-orang yang bersegera menuju kekafiran -hingga firman-Nya- Jika diberikan ini kepadamu, maka terimalah) ' (Qs. Al Maidah: 41). Orang-orang Yahudi berkata, \"Datanglah kalian kepada Muhammad shallallahu 'alaihi wasallam, jika beliau memutuskan hukuman kepadamu dengan menghitamkan tubuh dan didera, maka terimalah, namun jika dia berfatwa kepadamu dengan hukuman rajam, maka waspadalah. Maka Allah Ta'ala menurunkan ayat: '(Barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang kafir. Dan barangsiapa tidak berhukum dengan sesuatu yang telah diturunkan Allah, maka mereka itu adalah orang-orang yang Zhalim. Dan barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang fasik' (Qs. Al Maidah: 44- 47). Hal ini juga berlaku kepada orang-orang kafir semuanya.\" Telah menceritakan kepada kami [Ibnu Numair] dan [Abu Sa'id Al Asyaj] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dengan isnad seperti ini sampai kepada perkataannya, \"Lalu Nabi shallallahu 'alaihi wasallam memerintahkan untuk merajmanya, akhirnya dia pun dirajam.\" Dan tidak menyebutkan sesuatu setelahnya seperti turunnya ayat.\""},{"p":"Tirmidzi","n":1336,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ عَنْ شُعْبَةَ عَنْ قَتَادَةَ قَال سَمِعْتُ زُرَارَةَ بْنَ أَوْفَى يُحَدِّثُ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا عَضَّ يَدَ رَجُلٍ فَنَزَعَ يَدَهُ فَوَقَعَتْ ثَنِيَّتَاهُ فَاخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَعَضُّ أَحَدُكُمْ أَخَاهُ كَمَا يَعَضُّ الْفَحْلُ لَا دِيَةَ لَكَ فَأَنْزَلَ اللَّهُ{ وَالْجُرُوحَ قِصَاصٌ }قَالَ وَفِي الْبَاب عَنْ يَعْلَى بْنِ أُمَيَّةَ وَسَلَمَةَ بْنِ أُمَيَّةَ وَهُمَا أَخَوَانِ قَالَ أَبُو عِيسَى حَدِيثُ عِمْرَانَ بْنِ حُصَيْنٍ حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khasyram], telah memberitakan kepada kami [Isa bin Yunus] dari [Syu'bah] dari [Qatadah] ia berkata; Aku mendengar [Zurarah bin Aufa] menceritakan dari [Imran bin Hushain] bahwa ada seseorang yang menggigit tangan orang lain, maka orang yang digigit tangannya itu menarik kedua tangannya sehingga tanggallah kedua gigi depan si penggigit tersebut. Maka keduanya saling mengadu kepada Nabi shallallahu 'alaihi wasallam, dan beliau menjawab, \"Salah seorang dari kalian menggigit saudaranya, seperti halnya unta yang menggigit (temannya), maka tidak ada diyat bagimu.\" Kemudian turunlah ayat, \"WAL JURUHA QISHAH\" (dan luka-luka pun ada qishasnya) (QS. Al Maidah: 45) Ia mengatakan; Dalam hal ini ada hadits serupa dari Ya'la bin Umayyah dan Salamah bin Umayyah keduanya bersaudara. Abu 'Isa berkata; Hadits Imran bin Hushain adalah hadits hasan shahih."}],"5:46":[{"p":"Abu Dawud","n":3027,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ بْنِ أَبِي يَحْيَى الرَّمْلِيُّ حَدَّثَنَا زَيْدُ بْنُ أَبِي الزَّرْقَاءِ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ إِلَى قَوْلِهِ الْفَاسِقُونَ }هَؤُلَاءِ الْآيَاتِ الثَّلَاثِ نَزَلَتْ فِي الْيَهُودِ خَاصَّةً فِي قُرَيْظَةَ وَالنَّضِيرِ","trj":"Telah menceritakan kepada kami [Ibrahim bin Hamzah bin Abu Yahya Ar Ramli] telah menceritakan kepada kami [Zaid bin Abu Az Zarqa`] telah menceritakan kepada kami [Ibnu Az Zinad] dari [Ayahnya] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] ia membaca ayat: '(Barangsiapa yang tidak memutuskan menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang kafir) ' hingga firman Allah: '(…… orang-orang yang fasik) ' (Qs. Al Maidah: 44-47). ketiga ayat tersebut turun mengenai orang-orang Yahudi, khususnya orang-orang Bani Quraizhah dan An Nazlir.\""},{"p":"Muslim","n":2979,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ كِلَاهُمَا عَنْ أَبِي مُعَاوِيَةَ قَالَ يَحْيَى أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَهُودِيٍّ مُحَمَّمًا مَجْلُودًا فَدَعَاهُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالُوا نَعَمْ فَدَعَا رَجُلًا مِنْ عُلَمَائِهِمْ فَقَالَ أَنْشُدُكَ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى أَهَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالَ لَا وَلَوْلَا أَنَّكَ نَشَدْتَنِي بِهَذَا لَمْ أُخْبِرْكَ نَجِدُهُ الرَّجْمَ وَلَكِنَّهُ كَثُرَ فِي أَشْرَافِنَا فَكُنَّا إِذَا أَخَذْنَا الشَّرِيفَ تَرَكْنَاهُ وَإِذَا أَخَذْنَا الضَّعِيفَ أَقَمْنَا عَلَيْهِ الْحَدَّ قُلْنَا تَعَالَوْا فَلْنَجْتَمِعْ عَلَى شَيْءٍ نُقِيمُهُ عَلَى الشَّرِيفِ وَالْوَضِيعِ فَجَعَلْنَا التَّحْمِيمَ وَالْجَلْدَ مَكَانَ الرَّجْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَوَّلُ مَنْ أَحْيَا أَمْرَكَ إِذْ أَمَاتُوهُ فَأَمَرَ بِهِ فَرُجِمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَا أَيُّهَا الرَّسُولُ لَا يَحْزُنْكَ الَّذِينَ يُسَارِعُونَ فِي الْكُفْرِ }إِلَى قَوْلِهِ{ إِنْ أُوتِيتُمْ هَذَا فَخُذُوهُ }يَقُولُ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ أَمَرَكُمْ بِالتَّحْمِيمِ وَالْجَلْدِ فَخُذُوهُ وَإِنْ أَفْتَاكُمْ بِالرَّجْمِ فَاحْذَرُوا فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الظَّالِمُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْفَاسِقُونَ }فِي الْكُفَّارِ كُلُّهَاحَدَّثَنَا ابْنُ نُمَيْرٍ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَى قَوْلِهِ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ وَلَمْ يَذْكُرْ مَا بَعْدَهُ مِنْ نُزُولِ الْآيَةِ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] keduanya dari [Abu Mu'awiyah], [Yahya] berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Al Barra` bin 'Azib] dia berkata, \"Suatu ketika seorang Yahudi yang dicat hitam dan didera lewat di hadapan Nabi shallallahu 'alaihi wasallam, kemudian beliau memanggil mereka seraya bersabda: \"Beginikah hukuman zina yang kalian dapati dalam kitab Taurat kalian?\" mereka menjawab, \"Ya benar.\" Lalu beliau memanggil seorang laki-laki yang tergolong dari ulama mereka, beliau bertanya: \"Aku mengharap kamu mau bersumpah dengan nama Allah yang telah menurunkan kitab Taurat kepada Musa, betulkah begini caranya hukuman zina yang kalian dapati dalam kitab tauratmu?\" dia menjawab, \"Tidak, seandainya anda tidak menyumpahku dengan nama Allah, aku tidak akan mengatakan yang sebenarnya kepada anda. Dan yang kami ketahui dalam kitab Taurat, hukumannya adalah rajam, akan tetapi biasanya hukuman itu tidak berlaku bagi pembesar-pembesar kami, jika yang tertangkap itu dari pembesar, maka kami biarkan begitu saja, akan tetapi jika yang tertangkap rakyat kecil maka kami tegakkan hukum sesuai Taurat. Akhirnya kami bermusyawarah, membicarakan hukum yang dapat kami tegakkan bagi pembesar dan rakyat biasa. Lalu kami putuskan untuk membuat hitam tubuh dan mendera pelaku zina sebagai pengganti hukum rajam.\" Setelah laki-laki itu selesai bicara, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sesungguhnya akulah orang yang pertama-tama menghidupkan kembali sunnah-Mu setelah mereka hapus perintah tersebut.\" Setelah itu, beliau memerintahkan supaya Yahudi yang berzina itu dihukum rajam, lalu Allah 'azza wajalla menurunkan ayat: '(Wahai rasul, janganlah kamu merasa sedih, karena orang-orang yang bersegera menuju kekafiran -hingga firman-Nya- Jika diberikan ini kepadamu, maka terimalah) ' (Qs. Al Maidah: 41). Orang-orang Yahudi berkata, \"Datanglah kalian kepada Muhammad shallallahu 'alaihi wasallam, jika beliau memutuskan hukuman kepadamu dengan menghitamkan tubuh dan didera, maka terimalah, namun jika dia berfatwa kepadamu dengan hukuman rajam, maka waspadalah. Maka Allah Ta'ala menurunkan ayat: '(Barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang kafir. Dan barangsiapa tidak berhukum dengan sesuatu yang telah diturunkan Allah, maka mereka itu adalah orang-orang yang Zhalim. Dan barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang fasik' (Qs. Al Maidah: 44- 47). Hal ini juga berlaku kepada orang-orang kafir semuanya.\" Telah menceritakan kepada kami [Ibnu Numair] dan [Abu Sa'id Al Asyaj] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dengan isnad seperti ini sampai kepada perkataannya, \"Lalu Nabi shallallahu 'alaihi wasallam memerintahkan untuk merajmanya, akhirnya dia pun dirajam.\" Dan tidak menyebutkan sesuatu setelahnya seperti turunnya ayat.\""}],"5:47":[{"p":"Abu Dawud","n":3027,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ بْنِ أَبِي يَحْيَى الرَّمْلِيُّ حَدَّثَنَا زَيْدُ بْنُ أَبِي الزَّرْقَاءِ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ إِلَى قَوْلِهِ الْفَاسِقُونَ }هَؤُلَاءِ الْآيَاتِ الثَّلَاثِ نَزَلَتْ فِي الْيَهُودِ خَاصَّةً فِي قُرَيْظَةَ وَالنَّضِيرِ","trj":"Telah menceritakan kepada kami [Ibrahim bin Hamzah bin Abu Yahya Ar Ramli] telah menceritakan kepada kami [Zaid bin Abu Az Zarqa`] telah menceritakan kepada kami [Ibnu Az Zinad] dari [Ayahnya] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] ia membaca ayat: '(Barangsiapa yang tidak memutuskan menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang kafir) ' hingga firman Allah: '(…… orang-orang yang fasik) ' (Qs. Al Maidah: 44-47). ketiga ayat tersebut turun mengenai orang-orang Yahudi, khususnya orang-orang Bani Quraizhah dan An Nazlir.\""},{"p":"Muslim","n":2979,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ كِلَاهُمَا عَنْ أَبِي مُعَاوِيَةَ قَالَ يَحْيَى أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَهُودِيٍّ مُحَمَّمًا مَجْلُودًا فَدَعَاهُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالُوا نَعَمْ فَدَعَا رَجُلًا مِنْ عُلَمَائِهِمْ فَقَالَ أَنْشُدُكَ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى أَهَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالَ لَا وَلَوْلَا أَنَّكَ نَشَدْتَنِي بِهَذَا لَمْ أُخْبِرْكَ نَجِدُهُ الرَّجْمَ وَلَكِنَّهُ كَثُرَ فِي أَشْرَافِنَا فَكُنَّا إِذَا أَخَذْنَا الشَّرِيفَ تَرَكْنَاهُ وَإِذَا أَخَذْنَا الضَّعِيفَ أَقَمْنَا عَلَيْهِ الْحَدَّ قُلْنَا تَعَالَوْا فَلْنَجْتَمِعْ عَلَى شَيْءٍ نُقِيمُهُ عَلَى الشَّرِيفِ وَالْوَضِيعِ فَجَعَلْنَا التَّحْمِيمَ وَالْجَلْدَ مَكَانَ الرَّجْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَوَّلُ مَنْ أَحْيَا أَمْرَكَ إِذْ أَمَاتُوهُ فَأَمَرَ بِهِ فَرُجِمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَا أَيُّهَا الرَّسُولُ لَا يَحْزُنْكَ الَّذِينَ يُسَارِعُونَ فِي الْكُفْرِ }إِلَى قَوْلِهِ{ إِنْ أُوتِيتُمْ هَذَا فَخُذُوهُ }يَقُولُ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ أَمَرَكُمْ بِالتَّحْمِيمِ وَالْجَلْدِ فَخُذُوهُ وَإِنْ أَفْتَاكُمْ بِالرَّجْمِ فَاحْذَرُوا فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الظَّالِمُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْفَاسِقُونَ }فِي الْكُفَّارِ كُلُّهَاحَدَّثَنَا ابْنُ نُمَيْرٍ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَى قَوْلِهِ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ وَلَمْ يَذْكُرْ مَا بَعْدَهُ مِنْ نُزُولِ الْآيَةِ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] keduanya dari [Abu Mu'awiyah], [Yahya] berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Al Barra` bin 'Azib] dia berkata, \"Suatu ketika seorang Yahudi yang dicat hitam dan didera lewat di hadapan Nabi shallallahu 'alaihi wasallam, kemudian beliau memanggil mereka seraya bersabda: \"Beginikah hukuman zina yang kalian dapati dalam kitab Taurat kalian?\" mereka menjawab, \"Ya benar.\" Lalu beliau memanggil seorang laki-laki yang tergolong dari ulama mereka, beliau bertanya: \"Aku mengharap kamu mau bersumpah dengan nama Allah yang telah menurunkan kitab Taurat kepada Musa, betulkah begini caranya hukuman zina yang kalian dapati dalam kitab tauratmu?\" dia menjawab, \"Tidak, seandainya anda tidak menyumpahku dengan nama Allah, aku tidak akan mengatakan yang sebenarnya kepada anda. Dan yang kami ketahui dalam kitab Taurat, hukumannya adalah rajam, akan tetapi biasanya hukuman itu tidak berlaku bagi pembesar-pembesar kami, jika yang tertangkap itu dari pembesar, maka kami biarkan begitu saja, akan tetapi jika yang tertangkap rakyat kecil maka kami tegakkan hukum sesuai Taurat. Akhirnya kami bermusyawarah, membicarakan hukum yang dapat kami tegakkan bagi pembesar dan rakyat biasa. Lalu kami putuskan untuk membuat hitam tubuh dan mendera pelaku zina sebagai pengganti hukum rajam.\" Setelah laki-laki itu selesai bicara, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sesungguhnya akulah orang yang pertama-tama menghidupkan kembali sunnah-Mu setelah mereka hapus perintah tersebut.\" Setelah itu, beliau memerintahkan supaya Yahudi yang berzina itu dihukum rajam, lalu Allah 'azza wajalla menurunkan ayat: '(Wahai rasul, janganlah kamu merasa sedih, karena orang-orang yang bersegera menuju kekafiran -hingga firman-Nya- Jika diberikan ini kepadamu, maka terimalah) ' (Qs. Al Maidah: 41). Orang-orang Yahudi berkata, \"Datanglah kalian kepada Muhammad shallallahu 'alaihi wasallam, jika beliau memutuskan hukuman kepadamu dengan menghitamkan tubuh dan didera, maka terimalah, namun jika dia berfatwa kepadamu dengan hukuman rajam, maka waspadalah. Maka Allah Ta'ala menurunkan ayat: '(Barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang kafir. Dan barangsiapa tidak berhukum dengan sesuatu yang telah diturunkan Allah, maka mereka itu adalah orang-orang yang Zhalim. Dan barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang fasik' (Qs. Al Maidah: 44- 47). Hal ini juga berlaku kepada orang-orang kafir semuanya.\" Telah menceritakan kepada kami [Ibnu Numair] dan [Abu Sa'id Al Asyaj] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dengan isnad seperti ini sampai kepada perkataannya, \"Lalu Nabi shallallahu 'alaihi wasallam memerintahkan untuk merajmanya, akhirnya dia pun dirajam.\" Dan tidak menyebutkan sesuatu setelahnya seperti turunnya ayat.\""}],"5:48":[{"p":"Abu Dawud","n":3039,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ فَإِنْ جَاءُوكَ فَاحْكُمْ بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ }فَنُسِخَتْ قَالَ{ فَاحْكُمْ بَيْنَهُمْ بِمَا أَنْزَلَ اللَّهُ }","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepadaku [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Ayat: '(Jika mereka (orang Yahudi) datang kepadamu (untuk meminta putusan), maka putuskanlah (perkara itu) diantara mereka, atau berpalinglah dari mereka) ' (Qs. Al Maidah: 42), dihapus dan diganti dengan ayat: '(maka putuskanlah perkara mereka menurut apa yang Allah turunkan) ' (Qs. Al Maidah: 48). "}],"5:51":[{"p":"Malik","n":924,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّهُ سُئِلَ عَنْ ذَبَائِحِ نَصَارَى الْعَرَبِ فَقَالَ لَا بَأْسَ بِهَا وَتَلَا هَذِهِ الْآيَةَ{ وَمَنْ يَتَوَلَّهُمْ مِنْكُمْ فَإِنَّهُ مِنْهُمْ }و حَدَّثَنِي عَنْ مَالِك أَنَّهُ بَلَغَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ كَانَ يَقُولُ مَا فَرَى الْأَوْدَاجَ فَكُلُوهُ","trj":"Telah menceritakan kepadaku dari Malik dari [Tsaur bin Zaid Ad-Dili] dari [Abdullah bin Abbas] Bahwasanya ia pernah ditanya tentang sembelihan orang Nasrani Arab. Ibnu Abbas lalu menjawab, \"Itu tidak apa-apa.\" kemudian dia membaca ayat ini: '(Barangsiapa yang menjadikan mereka (orang-orang Nasrani) sebagai wali bagi kalian maka sesungguhnya dia bagian dari mereka) ' (Qs. Al Maidah: 51) Telah menceritakan kepadaku dari Malik telah sampai kepadanya bahwa Abdullah bin Abbas berkata; \"Sesuatu yang dapat memutuskan urat leher binatang, maka makanlah dagingnya.\""},{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."}],"5:64":[{"p":"Tirmidzi","n":2842,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينُ الرَّحْمَنِ مَلْأَى سَحَّاءُ لَا يُغِيضُهَا اللَّيْلُ وَالنَّهَارُ قَالَ أَرَأَيْتُمْ مَا أَنْفَقَ مُنْذُ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ فَإِنَّهُ لَمْ يَغِضْ مَا فِي يَمِينِهِ وَعَرْشُهُ عَلَى الْمَاءِ وَبِيَدِهِ الْأُخْرَى الْمِيزَانُ يَرْفَعُ وَيَخْفِضُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَتَفْسِيرُ هَذِهِ الْآيَةِ{ وَقَالَتْ الْيَهُودُ يَدُ اللَّهِ مَغْلُولَةٌ غُلَّتْ أَيْدِيهِمْ وَلُعِنُوا بِمَا قَالُوا بَلْ يَدَاهُ مَبْسُوطَتَانِ يُنْفِقُ كَيْفَ يَشَاءُ }وَهَذَا حَدِيثٌ قَدْ رَوَتْهُ الْأَئِمَّةُ نُؤْمِنُ بِهِ كَمَا جَاءَ مِنْ غَيْرِ أَنْ يُفَسَّرَ أَوْ يُتَوَهَّمَ هَكَذَا قَالَ غَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ مِنْهِمْ سُفْيَانُ الثَّوْرِيُّ وَمَالِكُ بْنُ أَنَسٍ وَابْنُ عُيَيْنَةَ وَابْنُ الْمُبَارَكِ أَنَّهُ تُرْوَى هَذِهِ الْأَشْيَاءُ وَيُؤْمَنُ بِهَا وَلَا يُقَالُ كَيْفَ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] ia berkata; Rasulullah Shallallahu 'alahi wasallam bersabda: \"Tangan kanan Ar Rahman kaya dengan rizki dan berkah yang tak akan pernah berkurang karena siang maupun malam. Tahukah kalian apa saja yang telah didinfakanNya sejak pertama kali langit dan bumi ini diciptakan? sesungguhnya semua yang berada di tangan kananNya tidak berkurang, 'Arsy Nya diatas air dan tangan lainnya terdapat timbangan (rizki) yang sesekali naik dan terkadang turun.\" Abu Isa mengatakan; Hadit ini Hadits ini hasan shahih, dan tafsir dari ayat Orang-orang Yahudi berkata; 'Tangan Allah terbelenggu, sebenarnya tangan merekalah yang dibelenggu dan merekalah yang dila'nat disebabkan apa yang telah mereka katakan itu. (Tidak demikian), tetapi kedua-dua tangan Allah terbuka; Dia menafkahkan sebagaimana Dia kehendaki QS Al Ma`idah: 64. Hadits ini diriwayatkan oleh para imam, kami mengimaninya apa adanya, tanpa ditafsirkan atau diperkirakan. Demikianlah yang di riwayatkan dari beberapa imam seperti Sufyan Ats Tsauri, Malik bin Anas, Ibnu 'Uyainah dan Ibnu Al Mubarak, mereka berkata; \"Semua itu diriwayatkan dan di imani tanpa ditanyakan bagaimananya.\""}],"5:65":[{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Tirmidzi","n":2851,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ قُلْ هُوَ الْقَادِرُ عَلَى أَنْ يَبْعَثَ عَلَيْكُمْ عَذَابًا مِنْ فَوْقِكُمْ أَوْ مِنْ تَحْتِ أَرْجُلِكُمْ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعُوذُ بِوَجْهِكَ فَلَمَّا نَزَلَتْ{ أَوْ يَلْبِسَكُمْ شِيَعًا وَيُذِيقَ بَعْضَكُمْ بَأْسَ بَعْضٍ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَاتَانِ أَهْوَنُ أَوْ هَاتَانِ أَيْسَرُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dia mendengar [Jabir bin Abdullah] ia berkata: \"Ketika turun ayat ini Katakanlah: 'Dialah yang berkuasa untuk mengirimkan azab kepadamu dari atas kamu atau dari bawah kakimu QS Al Ma`idah: 65, Rasulullah Shallallahu 'alahi wasallam berdoa: \"Ya Allah aku berlindung dengan wajah-Mu, \" akan tetapi ketika turun Atau dia mencampurkan kamu dalam golongan-golongan (yang saling bertentangan) dan merasakan kepada sebahagian kamu keganasan sebahagian yang lain QS Al An'aam: 65, beliau bersabda: \"Dua ayat ini lebih ringan atau dua ayat ini lebih mudah.\" Abu Isa mengatakan bahwa hadits ini hasan shahih."},{"p":"Tirmidzi","n":2852,"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ الْغَسَّانِيِّ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذِهِ الْآيَةِ{ قُلْ هُوَ الْقَادِرُ عَلَى أَنْ يَبْعَثَ عَلَيْكُمْ عَذَابًا مِنْ فَوْقِكُمْ أَوْ مِنْ تَحْتِ أَرْجُلِكُمْ }فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهَا كَائِنَةٌ وَلَمْ يَأْتِ تَأْوِيلُهَا بَعْدُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","trj":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Abu Bakr bin Abu Maryam Al Ghassani] dari [Rasyid bin Sa'd] dari [Sa'd bin Abu Waqqash] dari Nabi shallallahu 'alaihi wasallam berkenaan dengan ayat ini Katakanlah: 'Dialah yang berkuasa untuk mengirimkan azab kepadamu, dari atas kamu atau dari bawah kakimu QS Al Ma`idah: 65, beliau bersabda: \"Ingatlah, sesungguhnya itu akan terjadi, sementara penjelasannya belum tiba sama sekali.\" Abu Isa mengatakan bahwa hadits ini hasan gharib."},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."}],"5:67":[{"p":"Bukhari","n":6607,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ مَنْ حَدَّثَكَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا وَقَالَ مُحَمَّدٌ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْمَنْ حَدَّثَكَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ الْوَحْيِ فَلَا تُصَدِّقْهُ إِنَّ اللَّهَ تَعَالَى يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ismail] dari [Asy Sya'bi] dari [Masruq] dari [Aisyah] radliyallahu'anhuma, ia berkata, \"Siapa saja yang menceritakan kepadamu bahwa Muhammad shallallahu 'alaihi wasallam menyembunyikan sesuatu…sedang [Muhammad] berkata, telah menceritakan kepada kami [Abu Amir Al 'Aqadi] telah menceritakan kepada kami [Syu'bah] dari [Ismail bin Abu Khalid] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] berkata, \"Siapa saja yang menceritakan kepadamu bahwa Nabi shallallahu 'alaihi wasallam menyembunyikan sesuatu dari wahyu, maka janganlah kamu mempercayainya, sebab Allah Ta'ala berfirman: '(Wahai rasul, sampaikan yang diturunkan kepadamu dari Tuhanmu, jika kamu tidak mengerjakan lantas tidak kau sampaikan risalah….) ' (Qs. Al Maidah: 67)."},{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."}],"5:78":[{"p":"Ibnu Majah","n":3960,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَنِي إِسْرَائِيلَ لَمَّا وَقَعَ فِيهِمْ النَّقْصُ كَانَ الرَّجُلُ يَرَى أَخَاهُ عَلَى الذَّنْبِ فَيَنْهَاهُ عَنْهُ فَإِذَا كَانَ الْغَدُ لَمْ يَمْنَعْهُ مَا رَأَى مِنْهُ أَنْ يَكُونَ أَكِيلَهُ وَشَرِيبَهُ وَخَلِيطَهُ فَضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ وَنَزَلَ فِيهِمْ الْقُرْآنُ فَقَالَ{ لُعِنَ الَّذِينَ كَفَرُوا مِنْ بَنِي إِسْرَائِيلَ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ حَتَّى بَلَغَ وَلَوْ كَانُوا يُؤْمِنُونَ بِاللَّهِ وَالنَّبِيِّ وَمَا أُنْزِلَ إِلَيْهِ مَا اتَّخَذُوهُمْ أَوْلِيَاءَ وَلَكِنَّ كَثِيرًا مِنْهُمْ فَاسِقُونَ }قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا فَجَلَسَ وَقَالَ لَا حَتَّى تَأْخُذُوا عَلَى يَدَيْ الظَّالِمِ فَتَأْطِرُوهُ عَلَى الْحَقِّ أَطْرًاحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ أَمْلَاهُ عَلَيَّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْوَضَّاحِ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika terjadi krisis moral di tengah-tengah Bani Israil, ada seorang laki-laki melihat saudaranya berbuat dosa, maka dia pun melarangnya. Namun di esok harinya dia tidak mencegahnya dari apa yang dia lihat dari saudaranya supaya dia menjadi teman makan, teman minum dan teman bergaul. Maka Allah menutup hati mereka dengan sebagian yang lain, dan turunlah ayat Al Quran mengenai diri mereka, Allah berfirman: '(Telah dilaknati orang-orang kafir dari Bani Israil dengan lisan Daud dan 'Isa putera Maryam...) ' sampai pada ayat '(Sekiranya mereka beriman kepada Allah, kepada Nabi (Musa) dan kepada apa yang diturunkan kepadanya (Nabi), niscaya mereka tidak akan mengambil orang-orang musyrikin itu menjadi penolong-penolong, tapi kebanyakan dari mereka adalah orang-orang yang fasik) ' (Qs. Al Maidah: 78-81). Abu 'Ubaidah berkata, \"Rasulullah shallallahu 'alaihi wasallam pada saat itu bersandar kemudian duduk seraya bersabda: \"Tidak, sehingga kalian mengambil dari kedua tangan orang yang zhalim, kemudian kalian benar-benar meletakkannya kepada jalan yang benar.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud] yang ia diktekan kepadaku, telah menceritakan kepada kami [Muhammad bin Abu Al Waddlah] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""}],"5:79":[{"p":"Ibnu Majah","n":3960,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَنِي إِسْرَائِيلَ لَمَّا وَقَعَ فِيهِمْ النَّقْصُ كَانَ الرَّجُلُ يَرَى أَخَاهُ عَلَى الذَّنْبِ فَيَنْهَاهُ عَنْهُ فَإِذَا كَانَ الْغَدُ لَمْ يَمْنَعْهُ مَا رَأَى مِنْهُ أَنْ يَكُونَ أَكِيلَهُ وَشَرِيبَهُ وَخَلِيطَهُ فَضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ وَنَزَلَ فِيهِمْ الْقُرْآنُ فَقَالَ{ لُعِنَ الَّذِينَ كَفَرُوا مِنْ بَنِي إِسْرَائِيلَ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ حَتَّى بَلَغَ وَلَوْ كَانُوا يُؤْمِنُونَ بِاللَّهِ وَالنَّبِيِّ وَمَا أُنْزِلَ إِلَيْهِ مَا اتَّخَذُوهُمْ أَوْلِيَاءَ وَلَكِنَّ كَثِيرًا مِنْهُمْ فَاسِقُونَ }قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا فَجَلَسَ وَقَالَ لَا حَتَّى تَأْخُذُوا عَلَى يَدَيْ الظَّالِمِ فَتَأْطِرُوهُ عَلَى الْحَقِّ أَطْرًاحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ أَمْلَاهُ عَلَيَّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْوَضَّاحِ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika terjadi krisis moral di tengah-tengah Bani Israil, ada seorang laki-laki melihat saudaranya berbuat dosa, maka dia pun melarangnya. Namun di esok harinya dia tidak mencegahnya dari apa yang dia lihat dari saudaranya supaya dia menjadi teman makan, teman minum dan teman bergaul. Maka Allah menutup hati mereka dengan sebagian yang lain, dan turunlah ayat Al Quran mengenai diri mereka, Allah berfirman: '(Telah dilaknati orang-orang kafir dari Bani Israil dengan lisan Daud dan 'Isa putera Maryam...) ' sampai pada ayat '(Sekiranya mereka beriman kepada Allah, kepada Nabi (Musa) dan kepada apa yang diturunkan kepadanya (Nabi), niscaya mereka tidak akan mengambil orang-orang musyrikin itu menjadi penolong-penolong, tapi kebanyakan dari mereka adalah orang-orang yang fasik) ' (Qs. Al Maidah: 78-81). Abu 'Ubaidah berkata, \"Rasulullah shallallahu 'alaihi wasallam pada saat itu bersandar kemudian duduk seraya bersabda: \"Tidak, sehingga kalian mengambil dari kedua tangan orang yang zhalim, kemudian kalian benar-benar meletakkannya kepada jalan yang benar.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud] yang ia diktekan kepadaku, telah menceritakan kepada kami [Muhammad bin Abu Al Waddlah] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""}],"5:80":[{"p":"Ibnu Majah","n":3960,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَنِي إِسْرَائِيلَ لَمَّا وَقَعَ فِيهِمْ النَّقْصُ كَانَ الرَّجُلُ يَرَى أَخَاهُ عَلَى الذَّنْبِ فَيَنْهَاهُ عَنْهُ فَإِذَا كَانَ الْغَدُ لَمْ يَمْنَعْهُ مَا رَأَى مِنْهُ أَنْ يَكُونَ أَكِيلَهُ وَشَرِيبَهُ وَخَلِيطَهُ فَضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ وَنَزَلَ فِيهِمْ الْقُرْآنُ فَقَالَ{ لُعِنَ الَّذِينَ كَفَرُوا مِنْ بَنِي إِسْرَائِيلَ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ حَتَّى بَلَغَ وَلَوْ كَانُوا يُؤْمِنُونَ بِاللَّهِ وَالنَّبِيِّ وَمَا أُنْزِلَ إِلَيْهِ مَا اتَّخَذُوهُمْ أَوْلِيَاءَ وَلَكِنَّ كَثِيرًا مِنْهُمْ فَاسِقُونَ }قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا فَجَلَسَ وَقَالَ لَا حَتَّى تَأْخُذُوا عَلَى يَدَيْ الظَّالِمِ فَتَأْطِرُوهُ عَلَى الْحَقِّ أَطْرًاحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ أَمْلَاهُ عَلَيَّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْوَضَّاحِ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika terjadi krisis moral di tengah-tengah Bani Israil, ada seorang laki-laki melihat saudaranya berbuat dosa, maka dia pun melarangnya. Namun di esok harinya dia tidak mencegahnya dari apa yang dia lihat dari saudaranya supaya dia menjadi teman makan, teman minum dan teman bergaul. Maka Allah menutup hati mereka dengan sebagian yang lain, dan turunlah ayat Al Quran mengenai diri mereka, Allah berfirman: '(Telah dilaknati orang-orang kafir dari Bani Israil dengan lisan Daud dan 'Isa putera Maryam...) ' sampai pada ayat '(Sekiranya mereka beriman kepada Allah, kepada Nabi (Musa) dan kepada apa yang diturunkan kepadanya (Nabi), niscaya mereka tidak akan mengambil orang-orang musyrikin itu menjadi penolong-penolong, tapi kebanyakan dari mereka adalah orang-orang yang fasik) ' (Qs. Al Maidah: 78-81). Abu 'Ubaidah berkata, \"Rasulullah shallallahu 'alaihi wasallam pada saat itu bersandar kemudian duduk seraya bersabda: \"Tidak, sehingga kalian mengambil dari kedua tangan orang yang zhalim, kemudian kalian benar-benar meletakkannya kepada jalan yang benar.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud] yang ia diktekan kepadaku, telah menceritakan kepada kami [Muhammad bin Abu Al Waddlah] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""}],"5:81":[{"p":"Ibnu Majah","n":3960,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَنِي إِسْرَائِيلَ لَمَّا وَقَعَ فِيهِمْ النَّقْصُ كَانَ الرَّجُلُ يَرَى أَخَاهُ عَلَى الذَّنْبِ فَيَنْهَاهُ عَنْهُ فَإِذَا كَانَ الْغَدُ لَمْ يَمْنَعْهُ مَا رَأَى مِنْهُ أَنْ يَكُونَ أَكِيلَهُ وَشَرِيبَهُ وَخَلِيطَهُ فَضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ وَنَزَلَ فِيهِمْ الْقُرْآنُ فَقَالَ{ لُعِنَ الَّذِينَ كَفَرُوا مِنْ بَنِي إِسْرَائِيلَ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ حَتَّى بَلَغَ وَلَوْ كَانُوا يُؤْمِنُونَ بِاللَّهِ وَالنَّبِيِّ وَمَا أُنْزِلَ إِلَيْهِ مَا اتَّخَذُوهُمْ أَوْلِيَاءَ وَلَكِنَّ كَثِيرًا مِنْهُمْ فَاسِقُونَ }قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا فَجَلَسَ وَقَالَ لَا حَتَّى تَأْخُذُوا عَلَى يَدَيْ الظَّالِمِ فَتَأْطِرُوهُ عَلَى الْحَقِّ أَطْرًاحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ أَمْلَاهُ عَلَيَّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْوَضَّاحِ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika terjadi krisis moral di tengah-tengah Bani Israil, ada seorang laki-laki melihat saudaranya berbuat dosa, maka dia pun melarangnya. Namun di esok harinya dia tidak mencegahnya dari apa yang dia lihat dari saudaranya supaya dia menjadi teman makan, teman minum dan teman bergaul. Maka Allah menutup hati mereka dengan sebagian yang lain, dan turunlah ayat Al Quran mengenai diri mereka, Allah berfirman: '(Telah dilaknati orang-orang kafir dari Bani Israil dengan lisan Daud dan 'Isa putera Maryam...) ' sampai pada ayat '(Sekiranya mereka beriman kepada Allah, kepada Nabi (Musa) dan kepada apa yang diturunkan kepadanya (Nabi), niscaya mereka tidak akan mengambil orang-orang musyrikin itu menjadi penolong-penolong, tapi kebanyakan dari mereka adalah orang-orang yang fasik) ' (Qs. Al Maidah: 78-81). Abu 'Ubaidah berkata, \"Rasulullah shallallahu 'alaihi wasallam pada saat itu bersandar kemudian duduk seraya bersabda: \"Tidak, sehingga kalian mengambil dari kedua tangan orang yang zhalim, kemudian kalian benar-benar meletakkannya kepada jalan yang benar.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud] yang ia diktekan kepadaku, telah menceritakan kepada kami [Muhammad bin Abu Al Waddlah] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""}],"5:87":[{"p":"Bukhari","n":4381,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ قَالَ قَالَ عَبْدُ اللَّهِكُنَّا نَغْزُو مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ لَنَا شَيْءٌ فَقُلْنَا أَلَا نَسْتَخْصِي فَنَهَانَا عَنْ ذَلِكَ ثُمَّ رَخَّصَ لَنَا أَنْ نَنْكِحَ الْمَرْأَةَ بِالثَّوْبِ ثُمَّ قَرَأَ عَلَيْنَا{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُحَرِّمُوا طَيِّبَاتِ مَا أَحَلَّ اللَّهُ لَكُمْ وَلَا تَعْتَدُوا إِنَّ اللَّهَ لَا يُحِبُّ الْمُعْتَدِينَ }وَقَالَ أَصْبَغُ أَخْبَرَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ شَابٌّ وَأَنَا أَخَافُ عَلَى نَفْسِي الْعَنَتَ وَلَا أَجِدُ مَا أَتَزَوَّجُ بِهِ النِّسَاءَ فَسَكَتَ عَنِّي ثُمَّ قُلْتُ مِثْلَ ذَلِكَ فَسَكَتَ عَنِّي ثُمَّ قُلْتُ مِثْلَ ذَلِكَ فَسَكَتَ عَنِّي ثُمَّ قُلْتُ مِثْلَ ذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا هُرَيْرَةَ جَفَّ الْقَلَمُ بِمَا أَنْتَ لَاقٍ فَاخْتَصِ عَلَى ذَلِكَ أَوْ ذَرْ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Isma'il] dari [Qais] ia berkata; [Abdullah] berkata; Kami pernah berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam, dan saat itu kami tak punya apa-apa. Kemudian kami pun berkata, \"Apakah kami harus mengebiri?\" Dan ternyata beliau pun melarang kami untuk melakukannya, lalu beliau memberikan rukhshah kepada kami, yakni menikahi wanita meskipun dengan mahar kain. Kemudian membacakan ayat: \"Wahai orang-orang yang beriman, janganlah kamu mengharamkan sesuatu yang baik yang dihalalkan Allah untuk kalian, dan janganlah kalian melampau batas, sesungguhnya Allah tidak menyukai orang yang melampaui batas.\" (QS. Almaidah 87). [Ashbagh] berkata; Telah mengabarkan kepadaku [Ibnu Wahb] dari [Yunus bin Yazid] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Aku berkata, \"Wahai Rasulullah, aku adalah seorang pemuda, dan aku khawatir terhadap diriku bila terjerumus dalam kekejian, namun aku tidak memiliki sesuatu untuk menikahi wanita.\" Beliau terdiam. Aku pun berkata lagi seperti itu, beliau masih terdiam. Aku pun mengulanginya kembali, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Hurairah, qalam telah mengering (takdir telah ditetapkan) atas semua yang harus kamu hadapi, bolehlah kamu mengebiri, atau silahkan tinggalkan.\""}],"5:91":[{"p":"Tirmidzi","n":2845,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."}],"5:93":[{"p":"Muslim","n":3413,"ar":"حَدَّثَنِي أَبُو الرَّبِيعِ سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ سَاقِيَ الْقَوْمِ يَوْمَ حُرِّمَتْ الْخَمْرُ فِي بَيْتِ أَبِي طَلْحَةَ وَمَا شَرَابُهُمْ إِلَّا الْفَضِيخُ الْبُسْرُ وَالتَّمْرُ فَإِذَا مُنَادٍ يُنَادِي فَقَالَ اخْرُجْ فَانْظُرْ فَخَرَجْتُ فَإِذَا مُنَادٍ يُنَادِي أَلَا إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ قَالَ فَجَرَتْ فِي سِكَكِ الْمَدِينَةِ فَقَالَ لِي أَبُو طَلْحَةَ اخْرُجْ فَاهْرِقْهَا فَهَرَقْتُهَا فَقَالُوا أَوْ قَالَ بَعْضُهُمْ قُتِلَ فُلَانٌ قُتِلَ فُلَانٌ وَهِيَ فِي بُطُونِهِمْ قَالَ فَلَا أَدْرِي هُوَ مِنْ حَدِيثِ أَنَسٍ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا إِذَا مَا اتَّقَوْا وَآمَنُوا وَعَمِلُوا الصَّالِحَاتِ }","trj":"Telah menceritakan kepadaku [Abu Ar Rabi' Sulaiman bin Daud Al 'Ataki] telah menceritakan kepada kami [Hammad] -yaitu Ibnu Zaid- telah mengabarkan kepada kami [Tsabit] dari [Anas bin Malik] dia berkata, \"Saya pernah menuangkan khamer kepada sekelompok kaum di rumah Abu Thalhah ketika khamer diharamkan, dan saat itu mereka tidak minum kecuali dari Fadlih (minuman keras yang terbuat dari perasan kurma), kurma muda dan kurma masak. Tiba-tiba ada seseorang yang berseru, lantas Abu Thalhah berkata, \"Keluarlah dan lihatlah apa yang terjadi.\" Ternyata seseorang berseru, katanya, \"Tidakkah khamer telah diharamkan.\" Anas berkata, \"Kemudian berita itu tersebar ke seluruh Kota Madinah, lantas Abu Thalhah berkata kepadaku, \"Keluar dan baunglah.\" Maka saya langsung menumpahkannya. Saat itu orang-orang berkata, atau sebagian dari mereka berkata, \"Seseorang telah meninggal, sedangkan khamer tersebut masih dalam perut mereka.\" -Tsabit berkata; \"Namun saya tidak mengetahui apakah itu termasuk dari hadits Anas- Maka Allah Azza Wa Jalla berfirman: '(Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan shalih karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa dan beriman serta beramal shalih …) ' (? Qs. Al Maidah: 93)."},{"p":"Muslim","n":4159,"ar":"حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ وَسَهْلُ بْنُ عُثْمَانَ وَعَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ الْحَضْرَمِيُّ وَسُوَيْدُ بْنُ سَعِيدٍ وَالْوَلِيدُ بْنُ شُجَاعٍ قَالَ سَهْلٌ وَمِنْجَابٌ أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا إِذَا مَا اتَّقَوْا وَآمَنُوا }إِلَى آخِرِ الْآيَةِ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لِي أَنْتَ مِنْهُمْ","trj":"Telah menceritakan kepada kami [Minjab bin Al Harits At Tamimi] dan [Sahl bin 'Utsman] dan ['Abdullah bin 'Amir bin Zurarah Al Hadhrami] dan [Suwaid bin Sa'id] serta [Walid bin Syuja']. Berkata; [Sahl] dan [Minjab]; Telah mengabarkan kepada kami. Sedangkan yang lainnya berkata; Telah menceritakan kepada kami ['Ali bin Mushir] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] dia berkata; \"ketika turun ayat; \"Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang saleh karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman, dan mengerjakan amalan-amalan yang saleh, Kemudian mereka tetap bertakwa dan beriman…\" hingga akhir ayat (QS. ALmaidah 93), Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: 'Kamu termasuk dari golongan mereka.'"},{"p":"Tirmidzi","n":2846,"ar":"حَدَّثَنَا بِذَلِكَ بُنْدَارٌ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ قَالَ الْبَرَاءُمَاتَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ يَشْرَبُونَ الْخَمْرَ فَلَمَّا نَزَلَ تَحْرِيمُهَا قَالَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَيْفَ بِأَصْحَابِنَا الَّذِينَ مَاتُوا وَهُمْ يَشْرَبُونَهَا فَنَزَلَتْ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Bundar] seperti itu, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata; [Al Barra`] berkata; \"Sebagian sahabat Nabi Shallallahu 'alahi wasallam meninggal dunia sedangkan mereka suka meminum khamr, ketika turun (ayat) yang mengharamkannya, sebagian sahabat bertanya; \"Bagaimana dengan sahabat-sahabat kami, mereka meninggal sementara mereka suka meminumnya (khamar)?\" Maka turunlah ayat Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang shalih karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman, dan mengerjakan amalan-amalan yang Shalih. QS Al Ma`idah: 93. Abu Isa mengatakan bahwa hadits ini hasan shahih."},{"p":"Tirmidzi","n":2847,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي رِزْمَةَ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالُوا يَا رَسُولَ اللَّهِ أَرَأَيْتَ الَّذِينَ مَاتُوا وَهُمْ يَشْرَبُونَ الْخَمْرَ لَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ فَنَزَلَتْ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا إِذَا مَا اتَّقَوْا وَآمَنُوا وَعَمِلُوا الصَّالِحَاتِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Abdul Aziz bin Abu Rizmah] dari [Isra`il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Para sahabat bertanya; \"Wahai Rasulullah, bagaimana menurut anda mengenai orang-orang yang telah meninggal, sementara mereka dulu meminum khamar saat pengharaman khamar belum turun?, \" Lalu turun ayat Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang shalih karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman, dan mengerjakan amalan-amalan yang Shalih QS Al Ma`idah: 93. Abu Isa berkata; Hadits ini hasan shahih."}],"5:95":[{"p":"Malik","n":823,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ عَبْدِ الْمَلِكِ بْنِ قُرَيْرٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ أَنَّ رَجُلًا جَاءَ إِلَى عُمَرَ بْنِ الْخَطَّابِفَقَالَ إِنِّي أَجْرَيْتُ أَنَا وَصَاحِبٌ لِي فَرَسَيْنِ نَسْتَبِقُ إِلَى ثُغْرَةِ ثَنِيَّةٍ فَأَصَبْنَا ظَبْيًا وَنَحْنُ مُحْرِمَانِ فَمَاذَا تَرَى فَقَالَ عُمَرُ لِرَجُلٍ إِلَى جَنْبِهِ تَعَالَ حَتَّى أَحْكُمَ أَنَا وَأَنْتَ قَالَ فَحَكَمَا عَلَيْهِ بِعَنْزٍ فَوَلَّى الرَّجُلُ وَهُوَ يَقُولُ هَذَا أَمِيرُ الْمُؤْمِنِينَ لَا يَسْتَطِيعُ أَنْ يَحْكُمَ فِي ظَبْيٍ حَتَّى دَعَا رَجُلًا يَحْكُمُ مَعَهُ فَسَمِعَ عُمَرُ قَوْلَ الرَّجُلِ فَدَعَاهُ فَسَأَلَهُ هَلْ تَقْرَأُ سُورَةَ الْمَائِدَةِ قَالَ لَا قَالَ فَهَلْ تَعْرِفُ هَذَا الرَّجُلَ الَّذِي حَكَمَ مَعِي فَقَالَ لَا فَقَالَ لَوْ أَخْبَرْتَنِي أَنَّكَ تَقْرَأُ سُورَةَ الْمَائِدَةِ لَأَوْجَعْتُكَ ضَرْبًا ثُمَّ قَالَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ فِي كِتَابِهِ{ يَحْكُمُ بِهِ ذَوَا عَدْلٍ مِنْكُمْ هَدْيًا بَالِغَ الْكَعْبَةِ }وَهَذَا عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ","trj":"Telah menceritakan kepadaku dari Malik dari [Abdul Malik bin Qurair] dari [Muhammmad bin Sirin] berkata, \"Seorang laki-laki menemui [Umar bin Khattab] dan bertanya, \"Saya dan sahabatku lomba berpacu dengan dua ekor kuda, lalu kami menambrak kijang, sementara kami dalam keadaan ihram. Lalu apa pendapatmu?\" Umar berkata kepada [seseorang] yang berada di sampingnya, \"Mari kita bermusyawarah untuk menghukumi kejadian tersebut! \" Muhammmad bin Sirin berkata; \"Kemudian keduanya menghukumi mereka dengan membayar denda satu ekor kambing. Penanya tadi pergi sambil berkata, \"Amirul mukminin kok tidak bisa memberi putusan dalam masalah seekor kijang kecuali harus bersama orang lain! \" Umar mendengar ucapan orang tadi, lalu memanggilnya dan bertanya kepadanya, \"Apakah kamu telah membaca Surat Al Maidah?\" laki-laki itu menjawab, \"Tidak.\" Umar bertanya lagi, \"Tahukah kamu siapa laki-laki tadi yang telah bermusyawarah untuk menghukumi kejadian tersebut bersamaku?\" orang tadi menjawab, \"Saya tidak tahu.\" 'Umar bin Khattab berkata; \"Seandainya kamu memberitahuku bahwa kamu telah membaca Surat Al Maidah, niscaya saya akan memukulmu.\" Kemudian Umar berkata, \"Allah Tabaraka Wa Ta'ala berfirman dalam Kitab-Nya: '(Menurut putusan dua orang yang adil di antara kamu sebagai hadyu (ialah: binatang unta, lembu, kambing, biri-biri) yang dibawa ke Ka'bah untuk mendekatkan diri kepada Allah, disembelih di tanah Haram dan dagingnya dihadiahkan kepada fakir miskin dalam rangka ibadat haji) yang dibawa sampai ke Ka'bah) ' -Qs. Al Maidah: 95- Dan orang itu adalah Abdurrahman bin Auf."}],"5:101":[{"p":"Bukhari","n":6411,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي مُوسَى بْنُ أَنَسٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَقَالَ رَجُلٌ يَا نَبِيَّ اللَّهِ مَنْ أَبِي قَالَ أَبُوكَ فُلَانٌ وَنَزَلَتْ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] Telah mengabarkan kepada kami [Rauh bin Ubadah] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Musa bin Anas] berkata, \"Aku mendengar [Anas bin Malik] berkata, \"Seseorang bertanya 'Wahai nabiyullah, siapa ayahku?\" Rasul menjawab: \"Ayahmu si A.\" Lantas turunlah ayat: '(Wahai orang-orang yang beriman, janganlah kalian bertanya tentang sesuatu…). (Qs. Al Maidah: 101) "}],"5:103":[{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."}],"5:104":[{"p":"Bukhari","n":3054,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا الْمُغِيرَةُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ مَحْشُورُونَ حُفَاةً عُرَاةً غُرْلًا ثُمَّ قَرَأَ{ كَمَا بَدَأْنَا أَوَّ��َ خَلْقٍ نُعِيدُهُ وَعْدًا عَلَيْنَا إِنَّا كُنَّا فَاعِلِينَ }وَأَوَّلُ مَنْ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ وَإِنَّ أُنَاسًا مِنْ أَصْحَابِي يُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ أَصْحَابِي أَصْحَابِي فَيَقُولُ إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ مُنْذُ فَارَقْتَهُمْ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ فَلَمَّا تَوَفَّيْتَنِي إِلَى قَوْلِهِ الْعَزِيزُ الْحَكِيمُ }","trj":"Telah bercerita kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] telah bercerita kepada kami [Al Mughirah bin an-Nu'man] berkata telah bercerita kepadaku [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian akan dikumpulkan (pada hari qiyamat) dalam keadaan telanjang dan tidak dikhitan\". Lalu Beliau membaca firman Allah QS al-Anbiya' ayat 104 yang artinya (\"Sebagaimana Kami telah memulai penciptaan yang pertama, begitulah Kami akan mengulanginya. Itulah suatu janji yang pasti dari Kami. Sesungguhnya Kamilah yang akan melaksanakannya\"). Dan orang yang pertama kali diberikan pakaian pada hari qiyamat adalah Nabi Ibrahim 'Alaihissalam dan ada segolongan orang dari sahabatku yang akan diculik dari arah kiri lalu aku katakan: \"Itu Sahabatku, Itu sahabatku\". Maka Allah Ta'ala berfirman: \"Sesungguhnya mereka menjadi murtad sepeninggal kamu\". Aku katakan sebagaimana ucapan hamba yang shalih (firman Allah dalam QS al-Maidah ayat 117 - 118 yang artinya (\"Dan aku menjadi saksi atas mereka selagi aku bersama mereka. Namun setelah Engkau mewafatkan aku…) hingga firman-Nya (….Engkau Maha Perkasa lagi Maha bijaksana\")."},{"p":"Bukhari","n":5740,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَامَ فِينَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ إِنَّكُمْ مَحْشُورُونَ حُفَاةً عُرَاةً غُرْلًا{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ }الْآيَةَ وَإِنَّ أَوَّلَ الْخَلَائِقِ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ وَإِنَّهُ سَيُجَاءُ بِرِجَالٍ مِنْ أُمَّتِي فَيُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيَقُولُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ إِلَى قَوْلِهِ الْحَكِيمُ }قَالَ فَيُقَالُ إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ","trj":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Mughirah bin Nu'man] dari [Sa'id bin Jubair] dari [Ibnu'Abbas] mengatakan, Nabi shallallahu 'alaihi wasallam pernah berdiri di tengah-tengah kami menyampaikan orasi, lantas bersabda: \"Kalian dikumpulkan dengan keadaan tidak beralas kaki, telanjang dan tidak dikhitan, sambil beliau mengutip firman Allah 'Sebagaimana kami menciptakan awal mula, begitulah kami mengembalikannya' (QS. Anbiya' 104). Manusia pertama-tama yang diberi pakaian adalah Ibrahim 'alaihissalam, dan ia didatangkan dengan beberapa orang umatku, lantas mereka diseret ke sebelah kiri, sehingga aku mengiba-iba; 'Ya rabbi, tolong sahabatku, tolong sahabatku' Namun Allah hanya menjawab; 'engkau tidak tahu, apa yang mereka perbuat setelahnya'. Maka hanya kuutarakan sebagaimana ucapan seorang hamba yang shalih (maksudnya ucapan 'isa), 'Dan aku menjadi saksi mereka ketika aku berada ditengah-tengah mereka' hingga ayat 'sesungguhnya Engkau Maha Perkasa' (QS. Almaidah 118-119). Kata Ibnu 'Abbas, ada berita bahwa mereka murtad di kemudian hari."}],"5:105":[{"p":"Ahmad","n":1,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ أَخْبَرَنَا إِسْمَاعِيلُ يَعْنِي ابْنَ أَبِي خَالِدٍ عَنْ قَيْسٍ قَالَقَامَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }وَإِنَّا سَمِعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ النَّاسَ إِذَا رَأَوْا الْمُنْكَرَ فَلَمْ يُنْكِرُوهُ أَوْشَكَ أَنْ يَعُمَّهُمْ اللَّهُ بِعِقَابِهِ","trj":"Telah menceritakan kepada kami [Abdullah Bin Numair] dia berkata; telah mengabarkan kepada kami [Isma'il] dari [Qais] dia berkata; [Abu Bakar] berdiri lalu memuji Allah dan mensucikan-Nya kemudian berkata; wahai manusia sesungguhnya kalian membaca ayat ini: \"Hai orang-orang yang beriman, jagalah dirimu; tiadalah orang yang sesat itu akan memberi mudharat kepadamu apabila kamu telah mendapat petunjuk.\" (QS Al Maidah ayat 105). Dan sesungguhnya kami mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"sesungguhnya jika manusia melihat kemungkaran kemudian mereka tidak mengingkarinya, maka hampir saja Allah akan menimpakan siksa kepada mereka semua.\""},{"p":"Ibnu Majah","n":3959,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ قَالَقَامَ أَبُو بَكْرٍ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }وَإِنَّا سَمِعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ النَّاسَ إِذَا رَأَوْا الْمُنْكَرَ لَا يُغَيِّرُونَهُ أَوْشَكَ أَنْ يَعُمَّهُمْ اللَّهُ بِعِقَابِهِ قَالَ أَبُو أُسَامَةَ مَرَّةً أُخْرَى فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dia berkata, \" [Abu Bakar] berdiri sambil bersyukur kepada Allah dan memuji-Nya, kemudian dia berkata, \"Wahai sekalian manusia, kalian membaca ayat ini '(Hai orang-orang yang beriman, jagalah dirimu, tiadalah orang yang sesat itu akan memberi mudlarat kepadamu apabila kamu telah mendapat petunjuk) ' (Qs. Al Maidah: 105), dan sesungguhnya kami mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya manusia apabila melihat kemungkaran, kemudian mereka tidak merubahnya di khawatirkan Allah akan meratakan adzab-Nya kepada mereka.\" Sekali waktu Abu Usamah menyebutkan, \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda.\""}],"5:106":[{"p":"Abu Dawud","n":3051,"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ مُحَمَّدِ بْنِ أَبِي الْقَاسِمِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ رَجُلٌ مِنْ بَنِي سَهْمٍ مَعَ تَمِيمٍ الدَّارِيِّ وَعُدَيِّ بْنِ بَدَّاءٍ فَمَاتَ السَّهْمِيُّ بِأَرْضٍ لَيْسَ بِهَا مُسْلِمٌ فَلَمَّا قَدِمَا بِتَرِكَتِهِ فَقَدُوا جَامَ فِضَّةٍ مُخَوَّصًا بِالذَّهَبِ فَأَحْلَفَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وُجِدَ الْجَامُ بِمَكَّةَ فَقَالُوا اشْتَرَيْنَاهُ مِنْ تَمِيمٍ وَعُدَيٍّ فَقَامَ رَجُلَانِ مِنْ أَوْلِيَاءِ السَّهْمِيِّ فَحَلَفَا لَشَهَادَتُنَا أَحَقُّ مِنْ شَهَادَتِهِمَا وَإِنَّ الْجَامَ لِصَاحِبِهِمْ قَالَ فَنَزَلَتْ فِيهِمْ{ يَا أَيُّهَا الَّذِينَ آمَنُوا شَهَادَةُ بَيْنِكُمْ إِذَا حَضَرَ أَحَدَكُمْ الْمَوْتُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Ibnu Abu Zaidah] dari [Muhammad bin Abu Al Qasim] dari [Abdul Malik bin Sa'id bin Jubair] dari [Ayahnya] dari [Ibnu Abbas] ia berkata, \"Seorang laki-laki Bani Sahm keluar bersama Tamim Ad Dari dan 'Udai bin Badda, kemudian orang dari Bani Sahm tersebut meninggal di negeri yang tidak ada seorang Muslim pun di dalamnya. Kemudian tatkala mereka berdua datang dengan membawa harta warisannya mereka kehilangan gelas perak yang terukir dengan emas seperti daun kurma. Lalu Rasulullah shallallahu 'alaihi wasallam meminta mereka berdua agar bersumpah, dan gelas itu kemudian ditemukan di Makkah, keduanya lalu berkata, \"Kami membelinya dari Tamim dan 'Udai.\" Dua orang dari wali laki-laki Bani As Sahm kemudian berdiri dan bersumpah, 'Sungguh persaksian kami lebih berhak dari pada persaksian mereka berdua. ' Dan sesungguhnya gelas tersebut adalah milik sahabat mereka.\" Jubair berkata, \"Kemudian turunlah ayat: '(Hai orang-orang yang beriman, apabila salah seorang kamu menghadapi kematian, sedang dia akan berwasiat, maka hendaklah (wasiat itu) disaksikan oleh dua orang yang adil di antara kamu, atau dua orang yang berlainan agama dengan kamu, jika kamu dalam perjalanan di muka bumi lalu kamu ditimpa bahaya kematian. Kamu tahan kedua saksi itu sesudah sembahyang (untuk bersumpah), lalu mereka keduanya bersumpah dengan nama Allah, jika kamu ragu-ragu: \"(Demi Allah) kami tidak akan membeli dengan sumpah ini harga yang sedikit (untuk kepentingan seseorang), walaupun dia karib kerabat, dan tidak (pula) kami menyembunyikan persaksian Allah; sesungguhnya kami kalau demikian tentulah termasuk orang-orang yang berdosa) ' (Qs. Al Maidah: 106). "},{"p":"Bukhari","n":2572,"ar":"و قَالَ لِي عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ مُحَمَّدِ بْنِ أَبِي الْقَاسِمِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَرَجَ رَجُلٌ مِنْ بَنِي سَهْمٍ مَعَ تَمِيمٍ الدَّارِيِّ وَعَدِيِّ بْنِ بَدَّاءٍ فَمَاتَ السَّهْمِيُّ بِأَرْضٍ لَيْسَ بِهَا مُسْلِمٌ فَلَمَّا قَدِمَا بِتَرِكَتِهِ فَقَدُوا جَامًا مِنْ فِضَّةٍ مُخَوَّصًا مِنْ ذَهَبٍ فَأَحْلَفَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وُجِدَ الْجَامُ بِمَكَّةَ فَقَالُوا ابْتَعْنَاهُ مِنْ تَمِيمٍ وَعَدِيٍّ فَقَامَ رَجُلَانِ مِنْ أَوْلِيَائِهِ فَحَلَفَا{ لَشَهَادَتُنَا أَحَقُّ مِنْ شَهَادَتِهِمَا }وَإِنَّ الْجَامَ لِصَاحِبِهِمْ قَالَ وَفِيهِمْ نَزَلَتْ هَذِهِ الْآيَةُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا شَهَادَةُ بَيْنِكُمْ إِذَا حَضَرَ أَحَدَكُمْ الْمَوْتُ }","trj":"Dan berkata krpadaku ['Ali bin 'Abdullah] telah bercerita kepada kami [Yahya bin Adam] telah bercerita kepada kami [Ibnu Abi Za'idah] dari [Muhammad bin Abi Al Qosim] dari ['Abdul Malik bin Sa'id bin Jubair] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Ada seorang dari Bani Sahmi pergi keluar bersama Tamim ad-Dariy dan 'Addi bin Badda'. Kemudian lelaki suku Bani Sahmi itu meninggal dunia di daerah yang penduduknya tidak ada seorang Muslim pun. Ketika keduanya tiba kembali dengan membawa harta peninggalannya, keluarganya merasa kehilangan bejana perak yang bergaris emas, lalu Rasulullah Shallallhu 'Alaihi Wasallam menyumpah keduanya. Pada kemudian hari bejana itu ditemukan di Makkah. Mereka berkata: \"Kami telah membelinya dari Tamim dan Adi\". Lalu berdirilah dua orang dari wali Bani Sahmi dan bersumpah: \"Persaksian kami lebih benar dari pada persaksian mereka berdua, dan bejana itu adalah milik sahabat mereka\". Ia (Ibnu 'Abbas) berkata: \"Dan tentang mereka itulah ayat QS Al Ma'idah 106 turun, yang artinya: (\"Wahai orang-orang beriman bersaksilah kalian ketika salah seorang dari kalian meninggal\")."}],"5:117":[{"p":"Bukhari","n":3054,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا الْمُغِيرَةُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ مَحْشُورُونَ حُفَاةً عُرَاةً غُرْلًا ثُمَّ قَرَأَ{ كَمَا بَدَأْنَا أَوَّ��َ خَلْقٍ نُعِيدُهُ وَعْدًا عَلَيْنَا إِنَّا كُنَّا فَاعِلِينَ }وَأَوَّلُ مَنْ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ وَإِنَّ أُنَاسًا مِنْ أَصْحَابِي يُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ أَصْحَابِي أَصْحَابِي فَيَقُولُ إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ مُنْذُ فَارَقْتَهُمْ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ فَلَمَّا تَوَفَّيْتَنِي إِلَى قَوْلِهِ الْعَزِيزُ الْحَكِيمُ }","trj":"Telah bercerita kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] telah bercerita kepada kami [Al Mughirah bin an-Nu'man] berkata telah bercerita kepadaku [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian akan dikumpulkan (pada hari qiyamat) dalam keadaan telanjang dan tidak dikhitan\". Lalu Beliau membaca firman Allah QS al-Anbiya' ayat 104 yang artinya (\"Sebagaimana Kami telah memulai penciptaan yang pertama, begitulah Kami akan mengulanginya. Itulah suatu janji yang pasti dari Kami. Sesungguhnya Kamilah yang akan melaksanakannya\"). Dan orang yang pertama kali diberikan pakaian pada hari qiyamat adalah Nabi Ibrahim 'Alaihissalam dan ada segolongan orang dari sahabatku yang akan diculik dari arah kiri lalu aku katakan: \"Itu Sahabatku, Itu sahabatku\". Maka Allah Ta'ala berfirman: \"Sesungguhnya mereka menjadi murtad sepeninggal kamu\". Aku katakan sebagaimana ucapan hamba yang shalih (firman Allah dalam QS al-Maidah ayat 117 - 118 yang artinya (\"Dan aku menjadi saksi atas mereka selagi aku bersama mereka. Namun setelah Engkau mewafatkan aku…) hingga firman-Nya (….Engkau Maha Perkasa lagi Maha bijaksana\")."}],"5:118":[{"p":"Bukhari","n":3054,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا الْمُغِيرَةُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ مَحْشُورُونَ حُفَاةً عُرَاةً غُرْلًا ثُمَّ قَرَأَ{ كَمَا بَدَأْنَا أَوَّ��َ خَلْقٍ نُعِيدُهُ وَعْدًا عَلَيْنَا إِنَّا كُنَّا فَاعِلِينَ }وَأَوَّلُ مَنْ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ وَإِنَّ أُنَاسًا مِنْ أَصْحَابِي يُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ أَصْحَابِي أَصْحَابِي فَيَقُولُ إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ مُنْذُ فَارَقْتَهُمْ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ فَلَمَّا تَوَفَّيْتَنِي إِلَى قَوْلِهِ الْعَزِيزُ الْحَكِيمُ }","trj":"Telah bercerita kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] telah bercerita kepada kami [Al Mughirah bin an-Nu'man] berkata telah bercerita kepadaku [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian akan dikumpulkan (pada hari qiyamat) dalam keadaan telanjang dan tidak dikhitan\". Lalu Beliau membaca firman Allah QS al-Anbiya' ayat 104 yang artinya (\"Sebagaimana Kami telah memulai penciptaan yang pertama, begitulah Kami akan mengulanginya. Itulah suatu janji yang pasti dari Kami. Sesungguhnya Kamilah yang akan melaksanakannya\"). Dan orang yang pertama kali diberikan pakaian pada hari qiyamat adalah Nabi Ibrahim 'Alaihissalam dan ada segolongan orang dari sahabatku yang akan diculik dari arah kiri lalu aku katakan: \"Itu Sahabatku, Itu sahabatku\". Maka Allah Ta'ala berfirman: \"Sesungguhnya mereka menjadi murtad sepeninggal kamu\". Aku katakan sebagaimana ucapan hamba yang shalih (firman Allah dalam QS al-Maidah ayat 117 - 118 yang artinya (\"Dan aku menjadi saksi atas mereka selagi aku bersama mereka. Namun setelah Engkau mewafatkan aku…) hingga firman-Nya (….Engkau Maha Perkasa lagi Maha bijaksana\")."},{"p":"Bukhari","n":5740,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَامَ فِينَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ إِنَّكُمْ مَحْشُورُونَ حُفَاةً عُرَاةً غُرْلًا{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ }الْآيَةَ وَإِنَّ أَوَّلَ الْخَلَائِقِ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ وَإِنَّهُ سَيُجَاءُ بِرِجَالٍ مِنْ أُمَّتِي فَيُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيَقُولُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ إِلَى قَوْلِهِ الْحَكِيمُ }قَالَ فَيُقَالُ إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ","trj":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Mughirah bin Nu'man] dari [Sa'id bin Jubair] dari [Ibnu'Abbas] mengatakan, Nabi shallallahu 'alaihi wasallam pernah berdiri di tengah-tengah kami menyampaikan orasi, lantas bersabda: \"Kalian dikumpulkan dengan keadaan tidak beralas kaki, telanjang dan tidak dikhitan, sambil beliau mengutip firman Allah 'Sebagaimana kami menciptakan awal mula, begitulah kami mengembalikannya' (QS. Anbiya' 104). Manusia pertama-tama yang diberi pakaian adalah Ibrahim 'alaihissalam, dan ia didatangkan dengan beberapa orang umatku, lantas mereka diseret ke sebelah kiri, sehingga aku mengiba-iba; 'Ya rabbi, tolong sahabatku, tolong sahabatku' Namun Allah hanya menjawab; 'engkau tidak tahu, apa yang mereka perbuat setelahnya'. Maka hanya kuutarakan sebagaimana ucapan seorang hamba yang shalih (maksudnya ucapan 'isa), 'Dan aku menjadi saksi mereka ketika aku berada ditengah-tengah mereka' hingga ayat 'sesungguhnya Engkau Maha Perkasa' (QS. Almaidah 118-119). Kata Ibnu 'Abbas, ada berita bahwa mereka murtad di kemudian hari."},{"p":"Muslim","n":294,"ar":"حَدَّثَنِي يُونُسُ بْنُ عَبْدِ الْأَعْلَى الصَّدَفِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ بَكْرَ بْنَ سَوَادَةَ حَدَّثَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلَا قَوْلَ اللَّهِ عَزَّ وَجَلَّ فِي إِبْرَاهِيمَ{ رَبِّ إِنَّهُنَّ أَضْلَلْنَ كَثِيرًا مِنْ النَّاسِ فَمَنْ تَبِعَنِي فَإِنَّهُ مِنِّي }الْآيَةَ وَقَالَ عِيسَى عَلَيْهِ السَّلَام{ إِنْ تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ وَإِنْ تَغْفِرْ لَهُمْ فَإِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ }فَرَفَعَ يَدَيْهِ وَقَالَ اللَّهُمَّ أُمَّتِي أُمَّتِي وَبَكَى فَقَالَ اللَّهُ عَزَّ وَجَلَّ يَا جِبْرِيلُ اذْهَبْ إِلَى مُحَمَّدٍ وَرَبُّكَ أَعْلَمُ فَسَلْهُ مَا يُبْكِيكَ فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَسَأَلَهُ فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا قَالَ وَهُوَ أَعْلَمُ فَقَالَ اللَّهُ يَا جِبْرِيلُ اذْهَبْ إِلَى مُحَمَّدٍ فَقُلْ إِنَّا سَنُرْضِيكَ فِي أُمَّتِكَ وَلَا نَسُوءُكَ","trj":"Telah menceritakan kepada kami [Yunus bin Abdul A'la ash-Shadafi] telah mengabarkan kepada kami [Ibnu Wahb] dia berkata, telah mengabarkan kepada kami [Amru bin al-Harits] bahwa [Bakr bin Sawadah] telah menceritakan kepadanya dari [Abdurrahman bin Jubair] dari [Abdullah bin Amr bin al-'Ash] bahwa Nabi shallallahu 'alaihi wasallam pernah membaca firman Allah mengenai Ibrahim: '(Ya Tuhanku, sesungguhnya berhala-berhala itu telah menyesatkan kebanyakan daripada manusia, maka barangsiapa yang mengikutiku, Maka Sesungguhnya orang itu termasuk golonganku) ' (Qs. Ibrahim: 36) hingga akhir ayat. Dan mengenai Isa Alaihissalam: '(Jika Engkau menyiksa mereka, maka sesungguhnya mereka adalah hamba-hamba Engkau, dan jika Engkau mengampuni mereka, maka sesungguhnya Engkaulah yang Maha Perkasa lagi Maha Bijaksana) ' (Qs. Al Maidah: 118), kemudian beliau mengangkat kedua tangannya seraya berdo'a: \"Ya Allah, selamatkanlah umatku, selamatkanlah umatku, \" dengan bercucuran air mata. Kemudian Allah 'azza wajalla berkata kepada malaikat Jibril: \"Temuilah Muhammad -dan Rabbmulah yang lebih tahu- dan tanyakan kepadanya, 'Apa yang membuatmu menangis? ' Maka malaikat Jibril pun bertanya kepada beliau, dan beliau shallallahu 'alaihi wasallam menjawabnya dengan apa yang dikatakan Allah-dan Allah lebih mengetahui hal itu-. Kemudian Allah berkata: 'Wahai Jibril, temuilah Muhammad dan katakan bahwa Kami akan membuatmu senang dengan umatmu dan tidak akan membuatmu sedih karenanya (Kami akan menyelamatkan semua umatmu-pent) '.\""}],"5:119":[{"p":"Bukhari","n":5740,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَامَ فِينَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ إِنَّكُمْ مَحْشُورُونَ حُفَاةً عُرَاةً غُرْلًا{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ }الْآيَةَ وَإِنَّ أَوَّلَ الْخَلَائِقِ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ وَإِنَّهُ سَيُجَاءُ بِرِجَالٍ مِنْ أُمَّتِي فَيُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيَقُولُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ إِلَى قَوْلِهِ الْحَكِيمُ }قَالَ فَيُقَالُ إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ","trj":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Mughirah bin Nu'man] dari [Sa'id bin Jubair] dari [Ibnu'Abbas] mengatakan, Nabi shallallahu 'alaihi wasallam pernah berdiri di tengah-tengah kami menyampaikan orasi, lantas bersabda: \"Kalian dikumpulkan dengan keadaan tidak beralas kaki, telanjang dan tidak dikhitan, sambil beliau mengutip firman Allah 'Sebagaimana kami menciptakan awal mula, begitulah kami mengembalikannya' (QS. Anbiya' 104). Manusia pertama-tama yang diberi pakaian adalah Ibrahim 'alaihissalam, dan ia didatangkan dengan beberapa orang umatku, lantas mereka diseret ke sebelah kiri, sehingga aku mengiba-iba; 'Ya rabbi, tolong sahabatku, tolong sahabatku' Namun Allah hanya menjawab; 'engkau tidak tahu, apa yang mereka perbuat setelahnya'. Maka hanya kuutarakan sebagaimana ucapan seorang hamba yang shalih (maksudnya ucapan 'isa), 'Dan aku menjadi saksi mereka ketika aku berada ditengah-tengah mereka' hingga ayat 'sesungguhnya Engkau Maha Perkasa' (QS. Almaidah 118-119). Kata Ibnu 'Abbas, ada berita bahwa mereka murtad di kemudian hari."}]},"mapping_surah":[{"p":"Abu Dawud","n":122,"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ الدِّرْهَمِيُّ حَدَّثَنَا ابْنُ دَاوُدَ عَنْ بُكَيْرِ بْنِ عَامِرٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ أَنَّ جَرِيرًابَالَ ثُمَّ تَوَضَّأَ فَمَسَحَ عَلَى الْخُفَّيْنِ وَقَالَ مَا يَمْنَعُنِي أَنْ أَمْسَحَ وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ قَالُوا إِنَّمَا كَانَ ذَلِكَ قَبْلَ نُزُولِ الْمَائِدَةِ قَالَ مَا أَسْلَمْتُ إِلَّا بَعْدَ نُزُولِ الْمَائِدَةِ","trj":"Telah menceritakan kepada kami [Ali bin Husain Ad-Dirhami] telah menceritakan kepada kami [Ibnu Dawud] dari [Bukair bin 'Amir] dari [Abu Zur'ah bin 'Amru bin Jarir] bahwasanya [Jarir] pernah buang air kecil, kemudian berwudhu, lalu mengusap bagian atas khufnya dan berkata, Apakah gerangan yang menghalangiku untuk mengusapnya, padahal aku telah melihat Rasulullah shallallahu 'alaihi wasallam mengusapnya? Para sahabat berkata, Mengusap kedua khuf itu berlaku sebelum turunnya ayat pada surat Al-Ma`idah, maka dia menjawab, Aku tidaklah masuk Islam kecuali setelah turunnya surah Al-Ma`idah tersebut. "},{"p":"Abu Dawud","n":263,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ الضَّرِيرُ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَكُنْتُ جَالِسًا بَيْنَ عَبْدِ اللَّهِ وَأَبِي مُوسَى فَقَالَ أَبُو مُوسَى يَا أَبَا عَبْدِ الرَّحْمَنِ أَرَأَيْتَ لَوْ أَنَّ رَجُلًا أَجْنَبَ فَلَمْ يَجِدْ الْمَاءَ شَهْرًا أَمَا كَانَ يَتَيَمَّمُ فَقَالَ لَا وَإِنْ لَمْ يَجِدْ الْمَاءَ شَهْرًا فَقَالَ أَبُو مُوسَى فَكَيْفَ تَصْنَعُونَ بِهَذِهِ الْآيَةِ الَّتِي فِي سُورَةِ الْمَائِدَةِ{ فَلَمْ تَجِدُوا مَاءً فَتَيَمَّمُوا صَعِيدًا طَيِّبًا }فَقَالَ عَبْدُ اللَّهِ لَوْ رُخِّصَ لَهُمْ فِي هَذَا لَأَوْشَكُوا إِذَا بَرَدَ عَلَيْهِمْ الْمَاءُ أَنْ يَتَيَمَّمُوا بِالصَّعِيدِ فَقَالَ لَهُ أَبُو مُوسَى وَإِنَّمَا كَرِهْتُمْ هَذَا لِهَذَا قَالَ نَعَمْ فَقَالَ لَهُ أَبُو مُوسَى أَلَمْ تَسْمَعْ قَوْلَ عَمَّارٍ لِعُمَرَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ فَأَجْنَبْتُ فَلَمْ أَجِدَ الْمَاءَ فَتَمَرَّغْتُ فِي الصَّعِيدِ كَمَا تَتَمَرَّغُ الدَّابَّةُ ثُمَّ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَصْنَعَ هَكَذَا فَضَرَبَ بِيَدِهِ عَلَى الْأَرْضِ فَنَفَضَهَا ثُمَّ ضَرَبَ بِشِمَالِهِ عَلَى يَمِينِهِ وَبِيَمِينِهِ عَلَى شِمَالِهِ عَلَى الْكَفَّيْنِ ثُمَّ مَسَحَ وَجْهَهُفَقَالَ لَهُ عَبْدُ اللَّهِ أَفَلَمْ تَرَ عُمَرَ لَمْ يَقْنَعْ بِقَوْلِ عَمَّارٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al-Anbari] telah menceritakan kepada kami [Abu Mu'awiyah Adl-Dlarir] dari [Al-A'masy] dari [Syaqiq] dia berkata; Saya pernah duduk di antara Abdulah dan Abu Musa. Lalu [Abu Musa] berkata; Wahai Abu Abdurrahman! Apakah kamu mengetahui, seandainya ada seseorang yang junub, kemudian dia tidak mendapatkan air selama satu bulan, bukankah dia harus bertayamum? Abdullah menjawab; Tidak, walaupun dia tidak mendapatkan air selama satu bulan. Lalu Abu Musa berkata; Bagaimanakah sikap anda terhadap ayat yang terdapat dalam surat Al- Maidah ini? Yaitu (yang artinya): \"… lalu kamu tidak mendapatkan air, maka bertayammumlah dengan debu tanah yang baik (bersih) \". (QS. Almaidah 6), Maka Abdullah menjawab; Kalau mereka diberi hukum keringanan tentang ini, dikhawatirkan mereka akan bertayammum dengan debu, kalau mereka merasa kedinginan memakai air. Kata Abu Musa kepadanya; Ternyata kamu tidak menyukai tayamum ini karena untuk alasan ini? Kata Abdullah; Ya. Kata Abu Musa kepadanya; Apakah kamu tidak pernah mendengar ucapan [Ammar] kepada Umar, yaitu Rasulullah shallallahu 'alaihi wasallam pernah mengutusku dalam suatu keperluan, lalu saya junub dan tidak mendapatkan air, sehingga saya berguling-guling di atas tanah, sebagaimana binatang yang sedang berguling-guling. Kemudian saya pergi menghadap kepada Nabi shallallahu 'alaihi wasallam dan menyampaikan hal tersebut kepada beliau, lalu beliau bersabda: \"Cukuplah kamu lakukan demikian ini.\" Lalu beliau menepukkan tangan ke tanah, lalu ditiupnya, kemudian beliau mengusap tangan kanannya dengan tangan kirinya dan tangan kirinya dengan tangan kanannya pada kedua telapak tangan, kemudian mengusap wajahnya. Maka Abdullah berkata kepada Abu Musa; Apakah kamu tidak tahu, bahwa Umar tidak puas terhadap ucapan Ammar? "},{"p":"Abu Dawud","n":676,"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ قَالَ قَالَ لِي زَيْدُ بْنُ ثَابِتٍمَا لَكَ تَقْرَأُ فِي الْمَغْرِبِ بِقِصَارِ الْمُفَصَّلِ وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِطُولَى الطُّولَيَيْنِقَالَ قُلْتُ مَا طُولَى الطُّولَيَيْنِ قَالَ الْأَعْرَافُ وَالْأُخْرَى الْأَنْعَامُ قَالَ وَسَأَلْتُ أَنَا ابْنَ أَبِي مُلَيْكَةَ فَقَالَ لِي مِنْ قِبَلِ نَفْسِهِ الْمَائِدَةُ وَالْأَعْرَافُ","trj":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazaq] dari [Ibnu Juraij] telah menceritakan kepadaku [Ibnu Abu Mulaikah] dari ['Urwah bin Zubair] dari [Marwan bin Al Hakam] dia berkata; [Zaid bin Tsabit] berkata kepadaku; \"Kenapa anda biasa membaca surat-surat pendek pada saat shalat Maghrib? Padahal aku melihat Rasulullah shallallahu 'alaihi wasallam membaca dua surat panjang dari surat-surat panjang dalam shalat Maghrib?.\" Ibnu Abu Mulaikah berkata; \"Kataku; \"Apakah dua surat panjang dari surat-surat panjang tersebut?\" Urwah menjawab; \"Yaitu Al A'raf dan Al An'am.\" Ibnu Juraij berkata; Aku bertanya kepada Ibnu Abu Mulaikah, lalu menurut dirinya adalah surat Al Maidah dan Al A'raf.\""},{"p":"Abu Dawud","n":3027,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ بْنِ أَبِي يَحْيَى الرَّمْلِيُّ حَدَّثَنَا زَيْدُ بْنُ أَبِي الزَّرْقَاءِ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ إِلَى قَوْلِهِ الْفَاسِقُونَ }هَؤُلَاءِ الْآيَاتِ الثَّلَاثِ نَزَلَتْ فِي الْيَهُودِ خَاصَّةً فِي قُرَيْظَةَ وَالنَّضِيرِ","trj":"Telah menceritakan kepada kami [Ibrahim bin Hamzah bin Abu Yahya Ar Ramli] telah menceritakan kepada kami [Zaid bin Abu Az Zarqa`] telah menceritakan kepada kami [Ibnu Az Zinad] dari [Ayahnya] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] ia membaca ayat: '(Barangsiapa yang tidak memutuskan menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang kafir) ' hingga firman Allah: '(…… orang-orang yang fasik) ' (Qs. Al Maidah: 44-47). ketiga ayat tersebut turun mengenai orang-orang Yahudi, khususnya orang-orang Bani Quraizhah dan An Nazlir.\""},{"p":"Abu Dawud","n":3039,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ فَإِنْ جَاءُوكَ فَاحْكُمْ بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ }فَنُسِخَتْ قَالَ{ فَاحْكُمْ بَيْنَهُمْ بِمَا أَنْزَلَ اللَّهُ }","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepadaku [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Ayat: '(Jika mereka (orang Yahudi) datang kepadamu (untuk meminta putusan), maka putuskanlah (perkara itu) diantara mereka, atau berpalinglah dari mereka) ' (Qs. Al Maidah: 42), dihapus dan diganti dengan ayat: '(maka putuskanlah perkara mereka menurut apa yang Allah turunkan) ' (Qs. Al Maidah: 48). "},{"p":"Abu Dawud","n":3040,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ فَإِنْ جَاءُوكَ فَاحْكُمْ بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ }{ وَإِنْ حَكَمْتَ فَاحْكُمْ بَيْنَهُمْ بِالْقِسْطِ }الْآيَةُ قَالَ كَانَ بَنُو النَّضِيرِ إِذَا قَتَلُوا مِنْ بَنِي قُرَيْظَةَ أَدَّوْا نِصْفَ الدِّيَةِ وَإِذَا قَتَلَ بَنُو قُرَيْظَةَ مِنْ بَنِي النَّضِيرِ أَدَّوْا إِلَيْهِمْ الدِّيَةَ كَامِلَةً فَسَوَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمْ","trj":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Daud bin Al Hushain] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Tatkala turun ayat ini: '(Jika mereka (orang Yahudi) datang kepadamu (untuk meminta putusan), maka putuskanlah (perkara itu) diantara mereka, atau berpalinglah dari mereka; jika kamu berpaling dari mereka maka mereka tidak akan memberi mudharat kepadamu sedikitpun. Dan jika kamu memutuskan perkara mereka, maka putuskanlah (perkara itu) diantara mereka dengan adil) ' (Qs. Al Maidah: 42), Ibnu Abbas berkata, \"Dahulu jika orang-orang Bani An Nadlir membunuh orang dari Bani Quraizhah maka mereka memberikan setengah diyat (tebusan), dan apabila Bani Quraizhah membunuh sebagian orang dari Bani An Nazlir, maka mereka menunaikan diyat secara penuh. Lalu Rasulullah shallallahu 'alaihi wasallam menyamaratakan besaran diyat di antara mereka.\""},{"p":"Abu Dawud","n":3051,"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ مُحَمَّدِ بْنِ أَبِي الْقَاسِمِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ رَجُلٌ مِنْ بَنِي سَهْمٍ مَعَ تَمِيمٍ الدَّارِيِّ وَعُدَيِّ بْنِ بَدَّاءٍ فَمَاتَ السَّهْمِيُّ بِأَرْضٍ لَيْسَ بِهَا مُسْلِمٌ فَلَمَّا قَدِمَا بِتَرِكَتِهِ فَقَدُوا جَامَ فِضَّةٍ مُخَوَّصًا بِالذَّهَبِ فَأَحْلَفَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وُجِدَ الْجَامُ بِمَكَّةَ فَقَالُوا اشْتَرَيْنَاهُ مِنْ تَمِيمٍ وَعُدَيٍّ فَقَامَ رَجُلَانِ مِنْ أَوْلِيَاءِ السَّهْمِيِّ فَحَلَفَا لَشَهَادَتُنَا أَحَقُّ مِنْ شَهَادَتِهِمَا وَإِنَّ الْجَامَ لِصَاحِبِهِمْ قَالَ فَنَزَلَتْ فِيهِمْ{ يَا أَيُّهَا الَّذِينَ آمَنُوا شَهَادَةُ بَيْنِكُمْ إِذَا حَضَرَ أَحَدَكُمْ الْمَوْتُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Ibnu Abu Zaidah] dari [Muhammad bin Abu Al Qasim] dari [Abdul Malik bin Sa'id bin Jubair] dari [Ayahnya] dari [Ibnu Abbas] ia berkata, \"Seorang laki-laki Bani Sahm keluar bersama Tamim Ad Dari dan 'Udai bin Badda, kemudian orang dari Bani Sahm tersebut meninggal di negeri yang tidak ada seorang Muslim pun di dalamnya. Kemudian tatkala mereka berdua datang dengan membawa harta warisannya mereka kehilangan gelas perak yang terukir dengan emas seperti daun kurma. Lalu Rasulullah shallallahu 'alaihi wasallam meminta mereka berdua agar bersumpah, dan gelas itu kemudian ditemukan di Makkah, keduanya lalu berkata, \"Kami membelinya dari Tamim dan 'Udai.\" Dua orang dari wali laki-laki Bani As Sahm kemudian berdiri dan bersumpah, 'Sungguh persaksian kami lebih berhak dari pada persaksian mereka berdua. ' Dan sesungguhnya gelas tersebut adalah milik sahabat mereka.\" Jubair berkata, \"Kemudian turunlah ayat: '(Hai orang-orang yang beriman, apabila salah seorang kamu menghadapi kematian, sedang dia akan berwasiat, maka hendaklah (wasiat itu) disaksikan oleh dua orang yang adil di antara kamu, atau dua orang yang berlainan agama dengan kamu, jika kamu dalam perjalanan di muka bumi lalu kamu ditimpa bahaya kematian. Kamu tahan kedua saksi itu sesudah sembahyang (untuk bersumpah), lalu mereka keduanya bersumpah dengan nama Allah, jika kamu ragu-ragu: \"(Demi Allah) kami tidak akan membeli dengan sumpah ini harga yang sedikit (untuk kepentingan seseorang), walaupun dia karib kerabat, dan tidak (pula) kami menyembunyikan persaksian Allah; sesungguhnya kami kalau demikian tentulah termasuk orang-orang yang berdosa) ' (Qs. Al Maidah: 106). "},{"p":"Abu Dawud","n":3375,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنَا يُونُسُ بْنُ يَزِيدَ عَنْ أَبِي عَلِيِّ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَالْعَيْنُ بِالْعَيْنِ }","trj":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Muhammad bin Al 'Ala] mereka berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah menceritakan kepada kami [Yunus bin Yazid] dari [Abu Ali bin Yazid] dari [Az Zuhri] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membaca ayat: '(... dan mata dengan mata) ' (Qs. Al Maidah: 45). "},{"p":"Abu Dawud","n":3682,"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ قَوْمًا مِنْ عُكْلٍ أَوْ قَالَ مِنْ عُرَيْنَةَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْتَوَوْا الْمَدِينَةَ فَأَمَرَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلِقَاحٍ وَأَمَرَهُمْ أَنْ يَشْرَبُوا مِنْ أَبْوَالِهَا وَأَلْبَانِهَا فَانْطَلَقُوا فَلَمَّا صَحُّوا قَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا النَّعَمَ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَبَرُهُمْ مِنْ أَوَّلِ النَّهَارِ فَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آثَارِهِمْ فَمَا ارْ��َفَعَ النَّهَارُ حَتَّى جِيءَ بِهِمْ فَأَمَرَ بِهِمْ فَقُطِعَتْ أَيْدِيهِمْ وَأَرْجُلُهُمْ وَسُمِرَ أَعْيُنُهُمْ وَأُلْقُوا فِي الْحَرَّةِ يَسْتَسْقُونَ فَلَا يُسْقَوْنَقَالَ أَبُو قِلَابَةَ فَهَؤُلَاءِ قَوْمٌ سَرَقُوا وَقَتَلُوا وَكَفَرُوا بَعْدَ إِيمَانِهِمْ وَحَارَبُوا اللَّهَ وَرَسُولَهُ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ بِإِسْنَادِهِ بِهَذَا الْحَدِيثِ قَالَ فِيهِ فَأَمَرَ بِمَسَامِيرَ فَأُحْمِيَتْ فَكَحَلَهُمْ وَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَمَا حَسَمَهُمْ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ قَالَ أَخْبَرَنَا ح و حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ بِهَذَا الْحَدِيثِ قَالَ فِيهِ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَلَبِهِمْ قَافَةً فَأُتِيَ بِهِمْ قَالَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى فِي ذَلِكَ{ إِنَّمَا جَزَاءُ الَّذِينَ يُحَارِبُونَ اللَّهَ وَرَسُولَهُ وَيَسْعَوْنَ فِي الْأَرْضِ فَسَادًا }الْآيَةَ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ وَقَتَادَةُ وَحُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ ذَكَرَ هَذَا الْحَدِيثَ قَالَ أَنَسٌ فَلَقَدْ رَأَيْتُ أَحَدَهُمْ يَكْدِمُ الْأَرْضَ بِفِيهِ عَطَشًا حَتَّى مَاتُوا حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ هِشَامٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ بِهَذَا الْحَدِيثِ نَحْوَهُ زَادَ ثُمَّ نَهَى عَنْ الْمُثْلَةِ وَلَمْ يَذْكُرْ مِنْ خِلَافٍ وَرَوَاهُ شُعْبَةُ عَنْ قَتَادَةَ وَسَلَّامُ بْنُ مِسْكِينٍ عَنْ ثَابِتٍ جَمِيعًا عَنْ أَنَسٍ لَمْ يَذْكُرَا مِنْ خِلَافٍ وَلَمْ أَجِدْ فِي حَدِيثِ أَحَدٍ قَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ مِنْ خِلَافٍ إِلَّا فِي حَدِيثِ حَمَّادِ بْنِ سَلَمَةَ","trj":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] berkata, \"Beberapa orang dari 'Ukl, atau ia mengatakan, \"dari Urainah datang menemui Rasulullah shallallahu 'alaihi wasallam. Namun mereka tidak cocok dengan iklim Madinah (hingga jatuh sakit). Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan untuk menyediakan liqah (unta hamil) bagi mereka. Beliau perintahkan mereka minum air kencing dan susu unta tersebut. Mereka pun pergi (menuju kandang unta), namun ketika telah sembuh mereka justru membunuh pengembala Rasulullah shallallahu 'alaihi wasallam dan membawa lari unta-unta tersebut. Menjelang siang hari, berita yang menimpa mereka sampai kepada Nabi shallallahu 'alaihi wasallam, Nabi shallallahu 'alaihi wasallam lalu mengirim (beberapa orang) untuk mengikuti jejak mereka. Matahari belum tinggi, orang-orang tersebut telah ditangkap dan dihadapkan kepada beliau. Beliau pun memberi perintah untuk memberi hukuman kepada mereka, tangan dan kaki mereka lalu dipotong, matanya dicongkel kemudian mereka dibuang ke padang pasir. Mereka minta minum namun tidak diberi.\" [Abu Qilabah] berkata, \"Orang-orang itu telah mencuri dan membunuh, murtad setelah beriman, serta memerangi Allah dan Rasul-Nya.\" Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dengan sanadnya sebagaimana dalam hadits tersebut. Namun ia menambahkan dalam haditsnya, \"Beliau memerintahkan untuk mengambil beberapa paku yang dipanaskan, lalu mereka disayat (dengan paku tersebut), tangan dan kaki mereka juga dipotong, namun beliau tidak memerintahkan untuk menghentikan darah mereka dengan menempelkan besi panas.\" Telah menceritakan kepada kami [Muhammad bin Ash Shabbah bin Sufyan] ia berkata; telah mengabarkan kepada kami. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Amru bin Utsman] berkata, telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Yahya] -maksudnya Yahya bin Abu Katsir- dari [Abu Qilabah] dari [Anas bin Malik] dengan hadits yang sama. Dalam hadits tersebut ia mengatakan, \"Rasulullah shallallahu 'alaihi wasallam lalu mengirim teliksandi untuk mencari mereka, hingga akhirnya mereka tertangkap. Anas berkata, \"Allah Tabaaraka Wa Ta'ala lalu menurunkan ayat: '(Sesungguhnya pembalasan terhadap orang-orang yang memerangi Allah dan Rasul-Nya dan membuat kerusakan..) ' -Qs. Al Maidah: 33-. Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami [Tsabit] dan [Qatadah] dan [Humaid] dari [Anas bin Malik] ia lalu menyebutkan hadits tersebut. Anas berkata, \"Aku melihat salah seorang dari mereka menjilati bumi dengan mulutnya karena haus, hingga akhirnya mati.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] dari [Hisyam] dari [Qatadah] dari [Anas bin Malik] sama dengan hadits tersebut, namun ia menambahkan, \"kemudian beliau melarang untuk melakukan mutslah (Mutilasi atau menyayat mayat). dan ia tidak menyebut kata; 'min khilaf' (secara bersilang). [Syu'bah] juga meriwayatkan dari [Qatadah] dan [Salam bin Miskin], dari [Tsabit]. Semuanya juga berasal dari [Anas], namun keduanya juga tidak menyebutkan kata; min khilaf (dipotong tangan dan kakinya secara bersilang). Aku tidak pernah mendapatkan dalam hadits seorang pun yang menyebutkan; 'beliau memotong tangan dan kaki mereka secara bersilang', kecuali hadits hadits riwayat Hammad bin Salamah.\""},{"p":"Ahmad","n":1,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ أَخْبَرَنَا إِسْمَاعِيلُ يَعْنِي ابْنَ أَبِي خَالِدٍ عَنْ قَيْسٍ قَالَقَامَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }وَإِنَّا سَمِعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ النَّاسَ إِذَا رَأَوْا الْمُنْكَرَ فَلَمْ يُنْكِرُوهُ أَوْشَكَ أَنْ يَعُمَّهُمْ اللَّهُ بِعِقَابِهِ","trj":"Telah menceritakan kepada kami [Abdullah Bin Numair] dia berkata; telah mengabarkan kepada kami [Isma'il] dari [Qais] dia berkata; [Abu Bakar] berdiri lalu memuji Allah dan mensucikan-Nya kemudian berkata; wahai manusia sesungguhnya kalian membaca ayat ini: \"Hai orang-orang yang beriman, jagalah dirimu; tiadalah orang yang sesat itu akan memberi mudharat kepadamu apabila kamu telah mendapat petunjuk.\" (QS Al Maidah ayat 105). Dan sesungguhnya kami mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"sesungguhnya jika manusia melihat kemungkaran kemudian mereka tidak mengingkarinya, maka hampir saja Allah akan menimpakan siksa kepada mereka semua.\""},{"p":"Ahmad","n":1671,"ar":"حَدَّثَنَا هِشَامُ بْنُ سَعِيدٍ حَدَّثَنَا حَسَنُ بْنُ أَيُّوبَ الْحَضْرَمِيُّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ نَاسِجٍ الْحَضْرَمِيُّ وَكَانَ قَدْ أَدْرَكَ أَبَا بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَمَنْ دُونَهُمَا عَنْ عُتْبَةَ بْنِ عَبْدٍ السُّلَمِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَصْحَابِهِ قُومُوا فَقَاتِلُوا قَالُوا نَعَمْ يَا رَسُولَ اللَّهِ وَلَا نَقُولُ كَمَا قَالَتْ بَنُو إِسْرَائِيلَ لِمُوسَى عَلَيْهِ السَّلَام انْطَلِقْ أَنْتَ وَرَبُّكَ فَقَاتِلَا إِنَّا هَاهُنَا قَاعِدُونَ وَلَكِنْ انْطَلِقْ أَنْتَ وَرَبُّكَ يَا مُحَمَّدُ فَقَاتِلَا وَإِنَّا مَعَكُمَا نُقَاتِلُ","trj":"Telah menceritakan kepada kami [Hisyam bin Sa'id] Telah menceritakan kepada kami [Hasan bin Ayyub Al Hadlrami] telah menceritakan kepadaku [Abdullah bin Nasij Al Hadlrami] -ia pernah bertemu dengan Abu Bakar dan Umar Radiallahu 'Anhuma dan orang-orang selain keduanya- dari Utbah bin Abdu As Sulami, bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: \"Berdiri dan berperanglah kalian!\" para sahabat menjawab, \"Kami siap wahai Rasulullah. Kami tidak akan mengatakan sebagaimana yang dikatakan oleh Banu Isara`il kepada Musa, '(Pergilah kamu bersama Tuhanmu, dan berperanglah kamu berdua, Sesungguhnya kami Hanya duduk menanti disini saja) ' (Qs. Al Maidah: 34). Akan tetapi, (kami akan katakan) pergilah kamu bersama Tuhanmu wahai Muhammad dan berperanglah, sesungguhnya kami bersamamu untuk berperang.\""},{"p":"Ahmad","n":2016,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا مُجَالِدٌ عَنْ عَامِرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَّمَنِي الْإِسْلَامَ وَنَعَتَ لِي الصَّلَاةَ وَكَيْفَ أُصَلِّي كُلَّ صَلَاةٍ لِوَقْتِهَا ثُمَّ قَالَ لِي كَيْفَ أَنْتَ يَا ابْنَ حَاتِمٍ إِذَا رَكِبْتَ مِنْ قُصُورِ الْيَمَنِ لَا تَخَافُ إِلَّا اللَّهَ حَتَّى تَنْزِلَ قُصُورَ الْحِيرَةِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ فَأَيْنَ مَقَانِبُ طَيِّئٍ وَرِجَالُهَا قَالَ يَكْفِيكَ اللَّهُ طَيِّئًا وَمَنْ سِوَاهَا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ نَتَصَيَّدُ بِهَذِهِ الْكِلَابِ وَالْبَزَاةِ فَمَا يَحِلُّ لَنَا مِنْهَا قَالَ يَحِلُّ لَكُمْ{ مَا عَلَّمْتُمْ مِنْ الْجَوَارِحِ مُكَلِّبِينَ تُعَلِّمُونَهُنَّ مِمَّا عَلَّمَكُمْ اللَّهُ فَكُلُوا مِمَّا أَمْسَكْنَ عَلَيْكُمْ وَاذْكُرُوا اسْمَ اللَّهِ عَلَيْهِ }فَمَا عَلَّمْتَ مِنْ كَلْبٍ أَوْ بَازٍ ثُمَّ أَرْسَلْتَ وَذَكَرْتَ اسْمَ اللَّهِ عَلَيْهِ فَكُلْ مِمَّا أَمْسَكَ عَلَيْكَ قُلْتُ وَإِنْ قَتَلَ قَالَ وَإِنْ قَتَلَ وَلَمْ يَأْكُلْ مِنْهُ شَيْئًا فَإِنَّمَا أَمْسَكَهُ عَلَيْكَ قُلْتُ أَفَرَأَيْتَ إِنْ خَالَطَ كِلَابَنَا كِلَابٌ أُخْرَى حِينَ نُرْسِلُهَا قَالَ لَا تَأْكُلْ حَتَّى تَعْلَمَ أَنَّ كَلْبَكَ هُوَ الَّذِي أَمْسَكَ عَلَيْكَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ نَرْمِي بِالْمِعْرَاضِ فَمَا يَحِلُّ لَنَا قَالَ لَا تَأْكُلْ مَا أَصَبْتَ بِالْمِعْرَاضِ إِلَّا مَا ذَكَّيْتَ","trj":"Telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami [Mujalid] dari [Amir] dari [Adi bin Hatim] ia berkata, \"Aku datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau mengajariku tentang Islam, menjelaskan sifat shalat dan bagaimana agar aku shalat tepat pada waktunya. Kemudian beliau bertanya kepadaku: \"Bagaimana denganmu wahai Ibnu Hatim, jika kamu berkendaraan dari istana Yaman, apakah kamu tidak takut selain kepada Allah hingga kamu sampai di istana Hirah?\" aku menjawab, \"Wahai Rasulullah, lalu dimanakah posisi tentara suku Thayyi?\" beliau bersabda: \"Cukuplah Allah sebagai penjagamu dari orang-orang Thayyi dan selainnya.\" Aku berkata lagi, \"Wahai Rasulullah, kami adalah kaum yang suka berburu dengan anjing-anjing ini dan burung ini. Lalu apa yang halal bagi kami dari hasil buruannya?\" Beliau menjawab: \"Dihalalkan bagimu yang baik-baik dan (buruan yang ditangkap) oleh binatang buas yang Telah kamu ajar dengan melatih nya untuk berburu; kamu mengajarnya menurut apa yang Telah diajarkan Allah kepadamu. Maka makanlah dari apa yang ditangkapnya untukmu, dan sebutlah nama Allah atas binatang buas itu (waktu melepaskannya) '. (Qs. Al Maidah: 4) Maka anjing atau burung buas yang telah kamu latih, kemudian kamu melepasnya dan menyebut nama Allah, maka makanlah hasil buruan yang ditangkapnya untukmu.\" Aku bertanya, \"Kalau ia membunuhnya?\" beliau menjawab: \"Kalau ia membunuhnya namun tidak memakan secuil pun darinya, maka sesungguhnya ia hanya berburu untukmu.\" Aku bertanya lagi, \"Bagaimanakah menurut anda, jika anjing-anjing kami berbaur dengan anjing-anjing yang lain saat kami melepaskannya?\" beliau menjawab: \"Jangan kamu makan hingga kamu memastikan bahwa anjing milikmulah yang telah menangkapnya.\" Aku berkata, \"Wahai Rasulullah, kami kadang melempar (buruan) dengan mi'rdl (bagian tombak yang tumpul), lalu mana yang halal bagi kami?\" beliau bersabda: \"Jangan kamu makan, kecuali buruan yang sempat kamu sembelih.\""},{"p":"Ahmad","n":2061,"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ قَالَكُنْتُ جَالِسًا مَعَ أَبِي مُوسَى وَعَبْدِ اللَّهِ قَالَ فَقَالَ أَبُو مُوسَى يَا أَبَا عَبْدِ الرَّحْمَنِ أَرَأَيْتَ لَوْ أَنَّ رَجُلًا لَمْ يَجِدْ الْمَاءَ وَقَدْ أَجْنَبَ شَهْرًا مَا كَانَ يَتَيَمَّمُ قَالَ لَا وَلَوْ لَمْ يَجِدْ الْمَاءَ شَهْرًا قَالَ فَقَالَ لَهُ أَبُو مُوسَى فَكَيْفَ تَصْنَعُونَ بِهَذِهِ الْآيَةِ فِي سُورَةِ الْمَائِدَةِ{ فَلَمْ تَجِدُوا مَاءً فَتَيَمَّمُوا صَعِيدًا طَيِّبًا }قَالَ فَقَالَ عَبْدُ اللَّهِ لَوْ رُخِّصَ لَهُمْ فِي هَذَا لَأَوْشَكُوا إِذَا بَرَدَ عَلَيْهِمْ الْمَاءُ أَنْ يَتَيَمَّمُوا الصَّعِيدَ ثُمَّ يُصَلُّوا قَالَ فَقَالَ لَهُ أَبُو مُوسَى إِنَّمَا كَرِهْتُمْ ذَا لِهَذَا قَالَ نَعَمْ قَالَ لَهُ أَبُو مُوسَى أَلَمْ تَسْمَعْ لِقَوْلِ عَمَّارٍ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ فَأَجْنَبْتُ فَلَمْ أَجِدْ الْمَاءَ فَتَمَرَّغْتُ فِي الصَّعِيدِ كَمَا تَمَرَّغُ الدَّابَّةُ ثُمَّ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَقُولَ وَضَرَبَ بِيَدِهِ عَلَى الْأَرْضِ ثُمَّ مَسَحَ كُلَّ وَاحِدَةٍ مِنْهُمَا بِصَاحِبَتِهَا ثُمَّ مَسَحَ بِهَا وَجْهَهُ لَمْ يُجِزْ الْأَعْمَشُ الْكَفَّيْنِ قَالَ فَقَالَ لَهُ عَبْدُ اللَّهِ أَلَمْ تَزْعُمُوا لَمْ يَقْنَعْ بِقَوْلِ عَمَّارٍ وَقَالَ أَبُو مُعَاوِيَةَ مَرَّةً قَالَ فَضَرَبَ بِيَدِهِ عَلَى الْأَرْضِ ثُمَّ نَفَضَهَا ثُمَّ ضَرَبَ بِشِمَالِهِ عَلَى يَمِينِهِ وَبِيَمِينِهِ عَلَى شِمَالِهِ عَلَى الْكَفَّيْنِ ثُمَّ مَسَحَ وَجْهَهُ","trj":"Telah menceritakan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] ia berkata, aku pernah duduk bersama [Abu Musa] dan Abdullah. Kemudian Abu Musa berkata, \"Wahai Abu Abdurrahman, bagaimana menurutmu jika ada seorang laki-laki yang tidak mendapatkan air, sementara ia telah junub selama satu bulan, bolehkah ia betayammum?\" Ia menjawab, \"Tidak, meskipun ia tidak mendapatkan air.\" Syaqiq berkata, \"Maka Abu Musa bertanya, \"Lalu apa yang kalian perbuat berkenaan dengan ayat yang terdapat dalam surat Al Maidah (ayat: 6): '(Jika kamu tidak memperoleh air, maka bertayammumlah dengan tanah yang baik (bersih)?\" Maka Abdullah berkata, \"Sekiranya mereka diberi keringanan dalam masalah ini, niscaya mereka akan segera bertayammum dan shalat disaat air sangat dingin.\" Kemudian Abu Musa bertanya kepadanya, \"Apakah hanya karena ini kalian tidak menyukainya?\" Abdullah menjawab, \"Ya.\" Abu Musa berkata lagi kepadanya, \"Tidakkah kamu mendengar ungkapan [Ammar], \"Rasulullah shallallahu 'alaihi wasallam pernah mengutusku untuk suatu keperluan. Lalu aku junub dan tidak mendapatkan air, maka aku pun berguling-guling di hamparan tanah sebagaimana bergulingnya binatang. Kemudian aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan menuturkan hal itu. Beliau bersabda: 'Cukup bagimu mengatakan, kemudian beliau menepukkan tangannya di atas tanah dan mengusapkannya pada kedua tangan dan wajahnya.\" -Al A'masy tidak membatasi pada kedua telapak tangan.- Maka Abdullah pun berkata, \"Tidakkah kalian mengira bahwa beliau belum merasa puas dengan ungkapannya Ammar?\" Sekali waktu Abu Mu'awiyah menyebutkan, \"Kemudian beliau menepukkan kedua tangannya di atas tanah lalu mengibaskannya dan mengusapkan telapak tangan kirinya ke telapak tangan kanan, kemudian telapak tangan kanannya ke atas telapak tangan kiri. Setelah itu, beliau mengusap wajahnya.\""},{"p":"Bukhari","n":43,"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ سَمِعَ جَعْفَرَ بْنَ عَوْنٍ حَدَّثَنَا أَبُو الْعُمَيْسِ أَخْبَرَنَا قَيْسُ بْنُ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّ رَجُلًا مِنْ الْيَهُودِ قَالَ لَهُ يَا أَمِيرَ الْمُؤْمِنِينَ آيَةٌ فِي كِتَابِكُمْ تَقْرَءُونَهَا لَوْ عَلَيْنَا مَعْشَرَ الْيَهُودِ نَزَلَتْ لَاتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا قَالَ أَيُّ آيَةٍ قَالَ{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمْ الْإِسْلَامَ دِينًا }قَالَ عُمَرُ قَدْ عَرَفْنَا ذَلِكَ الْيَوْمَ وَالْمَكَانَ الَّذِي نَزَلَتْ فِيهِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ قَائِمٌ بِعَرَفَةَ يَوْمَ جُمُعَةٍ","trj":"Telah menceritakan kepada kami [Al Hasan bin Ash Shabbah] bahwa dia mendengar [Ja'far bin 'Aun] berkata; Telah menceritakan kepada kami [Abu Al 'Umais], telah mengabarkan kepada kami [Qais bin Muslim] dari [Thariq bin Syihab] dari [Umar bin Al Khaththab]; Ada seorang laki-laki Yahudi berkata: \"Wahai Amirul Mu'minin, ada satu ayat dalam kitab kalian yang kalian baca, seandainya ayat itu diturunkan kepada kami Kaum Yahudi, tentulah kami jadikan (hari diturunkannya ayat itu) sebagai hari raya ('ied). Maka Umar bin Al Khaththab berkata: \"Ayat apakah itu?\" (Orang Yahudi itu) berkata: \"Pada hari ini telah Kusempurnakan untuk kalian agama kalian, dan telah Ku-cukupkan kepada kalian nikmat-Ku, dan telah Ku-ridhai Islam itu jadi agama bagi kalian\". (QS. Al Maidah ayat 3). Maka Umar bin Al Khaththab menjawab: \"Kami tahu hari tersebut dan dimana tempat diturunkannya ayat tersebut kepada Nabi shallallahu 'alaihi wasallam, yaitu pada hari Jum'at ketika Beliau shallallahu 'alaihi wasallam berada di 'Arafah. "},{"p":"Bukhari","n":334,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَكُنْتُ جَالِسًا مَعَ عَبْدِ اللَّهِ وَأَبِي مُوسَى الْأَشْعَرِيِّ فَقَالَ لَهُ أَبُو مُوسَى لَوْ أَنَّ رَجُلًا أَجْنَبَ فَلَمْ يَجِدْ الْمَاءَ شَهْرًا أَمَا كَانَ يَتَيَمَّمُ وَيُصَلِّي فَكَيْفَ تَصْنَعُونَ بِهَذِهِ الْآيَةِ فِي سُورَةِ الْمَائِدَةِ{ فَلَمْ تَجِدُوا مَاءً فَتَيَمَّمُوا صَعِيدًا طَيِّبًا }فَقَالَ عَبْدُ اللَّهِ لَوْ رُخِّصَ لَهُمْ فِي هَذَا لَأَوْشَكُوا إِذَا بَرَدَ عَلَيْهِمْ الْمَاءُ أَنْ يَتَيَمَّمُوا الصَّعِيدَ قُلْتُ وَإِنَّمَا كَرِهْتُمْ هَذَا لِذَا قَالَ نَعَمْ فَقَالَ أَبُو مُوسَى أَلَمْ تَسْمَعْ قَوْلَ عَمَّارٍ لِعُمَرَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ ف��أَجْنَبْتُ فَلَمْ أَجِد الْمَاءَ فَتَمَرَّغْتُ فِي الصَّعِيدِ كَمَا تَمَرَّغُ الدَّابَّةُ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَصْنَعَ هَكَذَا فَضَرَبَ بِكَفِّهِ ضَرْبَةً عَلَى الْأَرْضِ ثُمَّ نَفَضَهَا ثُمَّ مَسَحَ بِهِمَا ظَهْرَ كَفِّهِ بِشِمَالِهِ أَوْ ظَهْرَ شِمَالِهِ بِكَفِّهِ ثُمَّ مَسَحَ بِهِمَا وَجْهَهُ فَقَالَ عَبْدُ اللَّهِ أَفَلَمْ تَرَ عُمَرَ لَمْ يَقْنَعْ بِقَوْلِ عَمَّارٍوَزَادَ يَعْلَى عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ كُنْتُ مَعَ عَبْدِ اللَّهِ وَأَبِي مُوسَى فَقَالَ أَبُو مُوسَى أَلَمْ تَسْمَعْ قَوْلَ عَمَّارٍ لِعُمَرَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَنِي أَنَا وَأَنْتَ فَأَجْنَبْتُ فَتَمَعَّكْتُ بِالصَّعِيدِ فَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْنَاهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ هَكَذَا وَمَسَحَ وَجْهَهُ وَكَفَّيْهِ وَاحِدَةً","trj":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] ia berkata; Aku pernah duduk bersama 'Abdullah bin Mas'ud dan [Abu Musa Al Asy'ari]. Lalu Abu Musa berkata kepadanya, \"Seandainya ada seseorang mengalami junub dan tidak mendapatkan air selama satu bulan, apakah dia bertayamum dan shalat? Dan bagaimana pendapatmu dengan ayat ini di dalam Surah Al Maidah ayat 6: '(Lalu kamu tidak memperaleh air, maka bertayammumlah dengan tanah yang baik (bersih) '? 'Abdullah, \"Seandainya mereka diberi keringanan dalam masalah ini, bisa jadi nantinya bila ada seseorang dari mereka yang kedinginan dengan air dia akan bertayamum dengan tanah.\" Syaqiq bertanya, \"Apakah kalian tidak suka masalah ini karena faktor itu?\" Dia menjawab, \"Ya.\" Kemudian Abu Musa berkata, \"Tidakkah kamu pernah mendengar ucapan ['Ammar] kepada Umar, 'Rasulullah shallallahu 'alaihi wasallam mengutusku dalam suatu urusan, aku lalu junub dan tidak mendapatkan air. Maka aku pun berguling-guling di atas tanah seperti berguling-gulingnya hewan. Kemudian aku ceritakan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Sebenarnya cukup buatmu bila kamu melakukan begini.\" Nabi shallallahu 'alaihi wasallam kemudian memukulkan telapak tangannya ke permukaan tanah dan mengibaskannya, lalu mengusap punggung tangan kanannya dengan telapak tangan kirinya, atau punggung telapak kirinya dengan telapak tangan kanannya, kemudian beliau mengusap wajahnya.\" Abdullah berkata, \"Apakah kamu tidak tahu kalau 'Umar tidak menerima pendapat 'Ammar?\" [Ya'la] menambahkan dari [Al A'masy] dari [Syaqiq], \"Aku pernah bersama 'Abdullah dan Abu Musa. [Abu Musa] lalu berkata, \"Tidakkah kamu mendengar perkataan ['Ammar] kepada 'Umar 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam mengutus aku dan kamu, lalu aku mengalami junub dan aku bergulingan di atas tanah. Kemudian kita temui Rasulullah shallallahu 'alaihi wasallam menceritakan hal itu kepada beliau. Beliau lalu bersabda: \"Sebenarnya kamu cukup melakukan begini.\" Beliau lalu memukulkan telapak tangannya ke tanah, lalu mengusap muka dan kedua telapak tangannya sekali.\""},{"p":"Bukhari","n":2572,"ar":"و قَالَ لِي عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ مُحَمَّدِ بْنِ أَبِي الْقَاسِمِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَرَجَ رَجُلٌ مِنْ بَنِي سَهْمٍ مَعَ تَمِيمٍ الدَّارِيِّ وَعَدِيِّ بْنِ بَدَّاءٍ فَمَاتَ السَّهْمِيُّ بِأَرْضٍ لَيْسَ بِهَا مُسْلِمٌ فَلَمَّا قَدِمَا بِتَرِكَتِهِ فَقَدُوا جَامًا مِنْ فِضَّةٍ مُخَوَّصًا مِنْ ذَهَبٍ فَأَحْلَفَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وُجِدَ الْجَامُ بِمَكَّةَ فَقَالُوا ابْتَعْنَاهُ مِنْ تَمِيمٍ وَعَدِيٍّ فَقَامَ رَجُلَانِ مِنْ أَوْلِيَائِهِ فَحَلَفَا{ لَشَهَادَتُنَا أَحَقُّ مِنْ شَهَادَتِهِمَا }وَإِنَّ الْجَامَ لِصَاحِبِهِمْ قَالَ وَفِيهِمْ نَزَلَتْ هَذِهِ الْآيَةُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا شَهَادَةُ بَيْنِكُمْ إِذَا حَضَرَ أَحَدَكُمْ الْمَوْتُ }","trj":"Dan berkata krpadaku ['Ali bin 'Abdullah] telah bercerita kepada kami [Yahya bin Adam] telah bercerita kepada kami [Ibnu Abi Za'idah] dari [Muhammad bin Abi Al Qosim] dari ['Abdul Malik bin Sa'id bin Jubair] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Ada seorang dari Bani Sahmi pergi keluar bersama Tamim ad-Dariy dan 'Addi bin Badda'. Kemudian lelaki suku Bani Sahmi itu meninggal dunia di daerah yang penduduknya tidak ada seorang Muslim pun. Ketika keduanya tiba kembali dengan membawa harta peninggalannya, keluarganya merasa kehilangan bejana perak yang bergaris emas, lalu Rasulullah Shallallhu 'Alaihi Wasallam menyumpah keduanya. Pada kemudian hari bejana itu ditemukan di Makkah. Mereka berkata: \"Kami telah membelinya dari Tamim dan Adi\". Lalu berdirilah dua orang dari wali Bani Sahmi dan bersumpah: \"Persaksian kami lebih benar dari pada persaksian mereka berdua, dan bejana itu adalah milik sahabat mereka\". Ia (Ibnu 'Abbas) berkata: \"Dan tentang mereka itulah ayat QS Al Ma'idah 106 turun, yang artinya: (\"Wahai orang-orang beriman bersaksilah kalian ketika salah seorang dari kalian meninggal\")."},{"p":"Bukhari","n":3054,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا الْمُغِيرَةُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ مَحْشُورُونَ حُفَاةً عُرَاةً غُرْلًا ثُمَّ قَرَأَ{ كَمَا بَدَأْنَا أَوَّ��َ خَلْقٍ نُعِيدُهُ وَعْدًا عَلَيْنَا إِنَّا كُنَّا فَاعِلِينَ }وَأَوَّلُ مَنْ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ وَإِنَّ أُنَاسًا مِنْ أَصْحَابِي يُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ أَصْحَابِي أَصْحَابِي فَيَقُولُ إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ مُنْذُ فَارَقْتَهُمْ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ فَلَمَّا تَوَفَّيْتَنِي إِلَى قَوْلِهِ الْعَزِيزُ الْحَكِيمُ }","trj":"Telah bercerita kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] telah bercerita kepada kami [Al Mughirah bin an-Nu'man] berkata telah bercerita kepadaku [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian akan dikumpulkan (pada hari qiyamat) dalam keadaan telanjang dan tidak dikhitan\". Lalu Beliau membaca firman Allah QS al-Anbiya' ayat 104 yang artinya (\"Sebagaimana Kami telah memulai penciptaan yang pertama, begitulah Kami akan mengulanginya. Itulah suatu janji yang pasti dari Kami. Sesungguhnya Kamilah yang akan melaksanakannya\"). Dan orang yang pertama kali diberikan pakaian pada hari qiyamat adalah Nabi Ibrahim 'Alaihissalam dan ada segolongan orang dari sahabatku yang akan diculik dari arah kiri lalu aku katakan: \"Itu Sahabatku, Itu sahabatku\". Maka Allah Ta'ala berfirman: \"Sesungguhnya mereka menjadi murtad sepeninggal kamu\". Aku katakan sebagaimana ucapan hamba yang shalih (firman Allah dalam QS al-Maidah ayat 117 - 118 yang artinya (\"Dan aku menjadi saksi atas mereka selagi aku bersama mereka. Namun setelah Engkau mewafatkan aku…) hingga firman-Nya (….Engkau Maha Perkasa lagi Maha bijaksana\")."},{"p":"Bukhari","n":3488,"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ مُخَارِقٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَ سَمِعْتُ ابْنَ مَسْعُودٍ يَقُولُشَهِدْتُ مِنْ الْمِقْدَادِ بْنِ الْأَسْوَدِ مَشْهَدًا لَأَنْ أَكُونَ صَاحِبَهُ أَحَبُّ إِلَيَّ مِمَّا عُدِلَ بِهِ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَدْعُو عَلَى الْمُشْرِكِينَ فَقَالَ لَا نَقُولُ كَمَا قَالَ قَوْمُ مُوسَى{ اذْهَبْ أَنْتَ وَرَبُّكَ فَقَاتِلَا }وَلَكِنَّا نُقَاتِلُ عَنْ يَمِينِكَ وَعَنْ شِمَالِكَ وَبَيْنَ يَدَيْكَ وَخَلْفَكَ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْرَقَ وَجْهُهُ وَسَرَّهُ يَعْنِي قَوْلَهُ","trj":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Isra'il] dari [Mukhariq] dari [Thariq bin Syihab] berkata, aku mendengar [Ibnu Mas'ud] berkata; \"Aku menyaksikan dari Al Miqdad bin Al Aswad suatu peristiwa dimana jika aku menjadi pelaku peristiwa tersebut lebih aku sukai daripada apapun yang dibandingkan dengannya. Yaitu ketika Nabi shallallahu 'alaihi wasallam datang (pada perang Badar) dan memohonkan kebinasaan bagi orang-orang musyrik, Al Miqdad berkata; \"Kami tidak akan mengatakan seperti yang dikatakan kaumnya Musa: \"Pergilah kamu dan Rabbmu untuk berperang...\" (QS al Maidah ayat). Akan tetapi kami akan berperang dari samping kananmu, samping kirimu, di hadapanmu dan di belakangmu\". Maka aku melihat Nabi shallallahu 'alaihi wasallam wajahnya berseri-seri, yaitu karena ucapan Al Miqdad tadi\"."},{"p":"Bukhari","n":3935,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ قَيْسٍ عَنْ طَارِقِ بْنِ شِهَابٍقَالَتْ الْيَهُودُ لِعُمَرَ إِنَّكُمْ تَقْرَءُونَ آيَةً لَوْ نَزَلَتْ فِينَا لَاتَّخَذْنَاهَا عِيدًا فَقَالَ عُمَرُ إِنِّي لَأَعْلَمُ حَيْثُ أُنْزِلَتْ وَأَيْنَ أُنْزِلَتْ وَأَيْنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُنْزِلَتْ يَوْمَ عَرَفَةَ وَإِنَّا وَاللَّهِ بِعَرَفَةَ قَالَ سُفْيَانُ وَأَشُكُّ كَانَ يَوْمَ الْجُمُعَةِ أَمْ لَا{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ }","trj":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami ['Abdur Rahman] Telah menceritakan kepada kami [Sufyan] dari [Qais] dari [Thariq bin Syihab] dia berkata; Orang-orang Yahudi mengatakan kepada Umar; \"Sesungguhnya kalian membaca satu ayat, seandainya ayat itu diturunkan kepada kami, maka hari turunnya ayat tersebut pasti akan kami jadikan hari raya.\" lalu [Umar] menjawab; \"sesungguhnya aku sangat tahu dimana ayat tersebut diturunkan, pada hari apa diturunkan, dan di mana Rasulullah shallallahu 'alaihi wasallam berada ketika ayat tersebut diturunkan, bahwa ayat tersebut diturunkan pada hari Arafah dan kami demi Allah pada waktu itu sedang melaksanakan wukuf di Arafah.\" Sufyan berkata; aku ragu tentang; \"hari Jum'at atau bukan.\" yaitu ayat; \"Pada hari Ini telah Kusempurnakan untuk kamu agamamu, dan telah Ku-cukupkan kepadamu nikmat-Ku, dan telah Ku-ridhai Islam itu jadi agama bagimu.\"(QS Al Ma'idah ayat: 3)."},{"p":"Bukhari","n":4381,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ قَالَ قَالَ عَبْدُ اللَّهِكُنَّا نَغْزُو مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ لَنَا شَيْءٌ فَقُلْنَا أَلَا نَسْتَخْصِي فَنَهَانَا عَنْ ذَلِكَ ثُمَّ رَخَّصَ لَنَا أَنْ نَنْكِحَ الْمَرْأَةَ بِالثَّوْبِ ثُمَّ قَرَأَ عَلَيْنَا{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُحَرِّمُوا طَيِّبَاتِ مَا أَحَلَّ اللَّهُ لَكُمْ وَلَا تَعْتَدُوا إِنَّ اللَّهَ لَا يُحِبُّ الْمُعْتَدِينَ }وَقَالَ أَصْبَغُ أَخْبَرَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ شَابٌّ وَأَنَا أَخَافُ عَلَى نَفْسِي الْعَنَتَ وَلَا أَجِدُ مَا أَتَزَوَّجُ بِهِ النِّسَاءَ فَسَكَتَ عَنِّي ثُمَّ قُلْتُ مِثْلَ ذَلِكَ فَسَكَتَ عَنِّي ثُمَّ قُلْتُ مِثْلَ ذَلِكَ فَسَكَتَ عَنِّي ثُمَّ قُلْتُ مِثْلَ ذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا هُرَيْرَةَ جَفَّ الْقَلَمُ بِمَا أَنْتَ لَاقٍ فَاخْتَصِ عَلَى ذَلِكَ أَوْ ذَرْ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Isma'il] dari [Qais] ia berkata; [Abdullah] berkata; Kami pernah berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam, dan saat itu kami tak punya apa-apa. Kemudian kami pun berkata, \"Apakah kami harus mengebiri?\" Dan ternyata beliau pun melarang kami untuk melakukannya, lalu beliau memberikan rukhshah kepada kami, yakni menikahi wanita meskipun dengan mahar kain. Kemudian membacakan ayat: \"Wahai orang-orang yang beriman, janganlah kamu mengharamkan sesuatu yang baik yang dihalalkan Allah untuk kalian, dan janganlah kalian melampau batas, sesungguhnya Allah tidak menyukai orang yang melampaui batas.\" (QS. Almaidah 87). [Ashbagh] berkata; Telah mengabarkan kepadaku [Ibnu Wahb] dari [Yunus bin Yazid] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Aku berkata, \"Wahai Rasulullah, aku adalah seorang pemuda, dan aku khawatir terhadap diriku bila terjerumus dalam kekejian, namun aku tidak memiliki sesuatu untuk menikahi wanita.\" Beliau terdiam. Aku pun berkata lagi seperti itu, beliau masih terdiam. Aku pun mengulanginya kembali, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Hurairah, qalam telah mengering (takdir telah ditetapkan) atas semua yang harus kamu hadapi, bolehlah kamu mengebiri, atau silahkan tinggalkan.\""},{"p":"Bukhari","n":5580,"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُسَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَحْفَوْهُ الْمَسْأَلَةَ فَغَضِبَ فَصَعِدَ الْمِنْبَرَ فَقَالَ لَا تَسْأَلُونِي الْيَوْمَ عَنْ شَيْءٍ إِلَّا بَيَّنْتُهُ لَكُمْ فَجَعَلْتُ أَنْظُرُ يَمِينًا وَشِمَالًا فَإِذَا كُلُّ رَجُلٍ لَافٌّ رَأْسَهُ فِي ثَوْبِهِ يَبْكِي فَإِذَا رَجُلٌ كَانَ إِذَا لَاحَى الرِّجَالَ يُدْعَى لِغَيْرِ أَبِيهِ فَقَالَ يَا رَسُولَ اللَّهِ مَنْ أَبِي قَالَ حُذَافَةُ ثُمَّ أَنْشَأَ عُمَرُ فَقَالَ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَسُولًا نَعُوذُ بِاللَّهِ مِنْ الْفِتَنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا رَأَيْتُ فِي الْخَيْرِ وَالشَّرِّ كَالْيَوْمِ قَطُّ إِنَّهُ صُوِّرَتْ لِي الْجَنَّةُ وَالنَّارُ حَتَّى رَأَيْتُهُمَا وَرَاءَ الْحَائِطِوَكَانَ قَتَادَةُ يَذْكُرُ عِنْدَ هَذَا الْحَدِيثِ هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }","trj":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] radliallahu 'anhu; bahwa para sahabat banyak bertanya kepada Rasulullah shallallahu 'alaihi wasallam sehingga mereka setengah memaksa dengan pertanyaan-pertanyaan itu. Maka beliau marah dan langsung naik mimbar sambil bersabda: 'Tidaklah kalian bertanya kepadaku mengenai sesuatu, melainkan aku selalu jelaskan kepada kalian', lantas aku melihat kanan-kiri, tak tahunya setiap orang menutupi kepalanya dengan pakaiannya sambil menangis, Secara spontan muncullah seseorang yang jika bermusuhan, ia dipanggil dengan nasab selain ayahnya, maka orang itu berujar 'Wahai nabiyullah siapakah ayahku? Beliau menjawab: 'ayahmu adalah Hudzafah.\" Umarpun bergegas mengucapkan RADHIINA BILLAHI RABBAN WABIL ISLAAMI DIINAN WABI MUHAMMADIN shallallahu 'alaihi wasallam RASUULAN NA'UUDZU BILLAH MINAL FITANI (Kami ridha Allah sebagai Tuhan, Islam sebagai agama, dan Muhammad sebagai utusan, kami berlindung kepada Allah dari fitnah), lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku belum pernah melihat keburukan dan kebaikan sama sekali seperti hari ini, sebab hari ini neraka dan surga digambarkan bagiku hingga aku melihat kedua-duanya berada dibalik dinding ini. Dan Qatadah selalu menyebutkan hadits ini ketika membaca ayat 'Wahai orang-orang yang beriman, janganlah kalian bertanya tentang sesuatu yang sekiranya diungkapkan kepada kalian, justru malah menyusahkan kalian.\" (QS. Al Maidah; 101)."},{"p":"Bukhari","n":5740,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَامَ فِينَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ إِنَّكُمْ مَحْشُورُونَ حُفَاةً عُرَاةً غُرْلًا{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ }الْآيَةَ وَإِنَّ أَوَّلَ الْخَلَائِقِ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ وَإِنَّهُ سَيُجَاءُ بِرِجَالٍ مِنْ أُمَّتِي فَيُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيَقُولُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ إِلَى قَوْلِهِ الْحَكِيمُ }قَالَ فَيُقَالُ إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ","trj":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Mughirah bin Nu'man] dari [Sa'id bin Jubair] dari [Ibnu'Abbas] mengatakan, Nabi shallallahu 'alaihi wasallam pernah berdiri di tengah-tengah kami menyampaikan orasi, lantas bersabda: \"Kalian dikumpulkan dengan keadaan tidak beralas kaki, telanjang dan tidak dikhitan, sambil beliau mengutip firman Allah 'Sebagaimana kami menciptakan awal mula, begitulah kami mengembalikannya' (QS. Anbiya' 104). Manusia pertama-tama yang diberi pakaian adalah Ibrahim 'alaihissalam, dan ia didatangkan dengan beberapa orang umatku, lantas mereka diseret ke sebelah kiri, sehingga aku mengiba-iba; 'Ya rabbi, tolong sahabatku, tolong sahabatku' Namun Allah hanya menjawab; 'engkau tidak tahu, apa yang mereka perbuat setelahnya'. Maka hanya kuutarakan sebagaimana ucapan seorang hamba yang shalih (maksudnya ucapan 'isa), 'Dan aku menjadi saksi mereka ketika aku berada ditengah-tengah mereka' hingga ayat 'sesungguhnya Engkau Maha Perkasa' (QS. Almaidah 118-119). Kata Ibnu 'Abbas, ada berita bahwa mereka murtad di kemudian hari."},{"p":"Bukhari","n":6001,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الشَّيْبَانِيُّ سَأَلْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَىعَنْ الرَّجْمِ فَقَالَ رَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَقَبْلَ النُّورِ أَمْ بَعْدَهُ قَالَ لَا أَدْرِيتَابَعَهُ عَلِيُّ بْنُ مُسْهِرٍ وَخَالِدُ بْنُ عَبْدِ اللَّهِ وَالْمُحَارِبِيُّ وَعَبِيدَةُ بْنُ حُمَيْدٍ عَنْ الشَّيْبَانِيِّ وَقَالَ بَعْضُهُمْ الْمَائِدَةِ وَالْأَوَّلُ أَصَحُّ","trj":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Asy Syaibani], aku bertanya kepada ['Abdullah bin bin Abi Awfa] tentang rajam, ia menjawab; Nabi shallallahu 'alaihi wasallam pernah merajam. Kemudian saya bertanya lagi; 'Itu terjadi sebelum diturunkan surat An Nur ataukah sesudahnya? ' Ia menjawab; 'Saya tidak tahu'. hadits ini diperkuat oleh ['Ali bin Mushir], [Khalid bin Abdullah], [Al Muharibi], [Abidah bin Humaid] dari [Asy Syaibani] dan mengatakan; 'Sebagian mereka mengatakan surat almaidah, dan yang pertama (surat An nur) lebih sahih.'"},{"p":"Bukhari","n":6228,"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَحْفَوْهُ بِالْمَسْأَلَةِ فَصَعِدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ الْمِنْبَرَ فَقَالَ لَا تَسْأَلُونِي عَنْ شَيْءٍ إِلَّا بَيَّنْتُ لَكُمْ فَجَعَلْتُ أَنْظُرُ يَمِينًا وَشِمَالًا فَإِذَا كُلُّ رَجُلٍ لَافٌّ رَأْسَهُ فِي ثَوْبِهِ يَبْكِي فَأَنْشَأَ رَجُلٌ كَانَ إِذَا لَاحَى يُدْعَى إِلَى غَيْرِ أَبِيهِ فَقَالَ يَا نَبِيَّ اللَّهِ مَنْ أَبِي فَقَالَ أَبُوكَ حُذَافَةُ ثُمَّ أَنْشَأَ عُمَرُ فَقَالَ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ رَسُولًا نَعُوذُ بِاللَّهِ مِنْ سُوءِ الْفِتَنِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا رَأَيْتُ فِي الْخَيْرِ وَالشَّرِّ كَالْيَوْمِ قَطُّ إِنَّهُ صُوِّرَتْ لِي الْجَنَّةُ وَالنَّارُ حَتَّى رَأَيْتُهُمَا دُونَ الْحَائِطِ فَكَانَ قَتَادَةُ يَذْكُرُ هَذَا الْحَدِيثَ عِنْدَ هَذِهِ الْآيَةِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }وَقَالَ عَبَّاسٌ النَّرْسِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ حَدَّثَنَا قَتَادَةُ أَنَّ أَنَسًا حَدَّثَهُمْ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَقَالَ كُلُّ رَجُلٍ لَافًّا رَأْسَهُ فِي ثَوْبِهِ يَبْكِي وَقَالَ عَائِذًا بِاللَّهِ مِنْ سُوءِ الْفِتَنِ أَوْ قَالَ أَعُوذُ بِاللَّهِ مِنْ سَوْأَى الْفِتَنِ و قَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ وَمُعْتَمِرٌ عَنْ أَبِيهِ عَنْ قَتَادَةَ أَنَّ أَنَسًا حَدَّثَهُمْ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَقَالَ عَائِذًا بِاللَّهِ مِنْ شَرِّ الْفِتَنِ","trj":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Hisyam] dari [Qotadah] dari [Anas] radliallahu 'anhu mengatakan, para sahabat banyak bertanya kepada Nabi shallallahu 'alaihi wasallam sehingga mereka setengah memaksa dengan pertanyaan-pertanyaan. Maka Nabi shallallahu 'alaihi wasallam suatu hari naik ke mimbar dan bersabda: \"Tidaklah kalian bertanya kepadaku mengenai sesuatu, selain kujelaskan kepada kalian, \" lantas aku melihat ke kanan-kiri, tak tahunya setiap orang membungkus kepalanya di pakaiannya sambil menangis, muncullah seseorang yang jika berdebat dia dipanggil dengan nasab selain ayahnya, orang itu berujar; 'Wahai Nabiyullah siapakah ayahku? ' Nabi menjawab: \"ayahmu adalah Hudzafah.\" Kontan Umar bergegas mengucapkan; 'RADHIINA BILLAHI RABBAN WABIL ISLAAMI DIINAN WABI MUHAMMADIN RASUULAN NA'UUDZU BILLAH MIN SUUIL FITANI (Kami ridha Allah sebagai rabb, Islam sebagai agama, dan Muhammad sebagai utusan, kami berlindung kepada Allah dari keburukan fitnah), \" Nabi shallallahu 'alaihi wasallam bersabda; \"Sama sekali belum pernah kulihat keburukan dan kebaikan seperti hari ini, sebab hari ini surga dan neraka digambarkan kepadaku sehingga aku melihat kedua-duanya dibalik dinding ini.\" Dan Qatadah selalu menyebutkan hadits ini berkaitan dengan ayat: 'Wahai orang-orang yang beriman, janganlah kalian bertanya tentang sesuatu yang sekiranya diungkapkan kepada kalian, justru malah menyusahkan kalian (QS. Almaidah; 101). [Abbas An Narsi] mengatakan, Telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] telah menceritakan kepada kami [Qotadah], bahwasanya [Anas] menceritakan kepada mereka; bahwa Nabiyullah Shallallahu'alaihiwasallam besabda masalah ini dengan redaksi: Setiap orang membungkus kepalanya dalam bajunya sambil menangis, dan ia mengatakan dengan redaksi: 'aaidzan billah min suu'il fitan (aku berlindung kepada Allah dari keburukan fitnah) atau ia mengatakan; 'a'uudzu billah min sau`atil fitan (Saya berlindung kepada Allah dari keburukan-keburukan fitnah). Sedang [Khalifah] mengatakan kepadaku Telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dan [Mu'tamir] dari [ayahnya] dari [Qotadah], bahwasanya [Anas] menceritakan kepada mereka, dari Nabi shallallahu 'alaihi wasallam dengan Hadits ini dan dia mengatakan dengan redaksi; 'aaidzan billah min syarril fitan (berlindung kepada Allah dari keburukan fitnah)."},{"p":"Bukhari","n":6388,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ عَنْ مِسْعَرٍ وَغَيْرِهِ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَق��الَ رَجُلٌ مِنْ الْيَهُودِ لِعُمَرَ يَا أَمِيرَ الْمُؤْمِنِينَ لَوْ أَنَّ عَلَيْنَا نَزَلَتْ هَذِهِ الْآيَةُ{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمْ الْإِسْلَامَ دِينًا }لَاتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا فَقَالَ عُمَرُ إِنِّي لَأَعْلَمُ أَيَّ يَوْمٍ نَزَلَتْ هَذِهِ الْآيَةُ نَزَلَتْ يَوْمَ عَرَفَةَ فِي يَوْمِ جُمُعَةٍسَمِعَ سُفْيَانُ مِنْ مِسْعَرٍ وَمِسْعَرٌ قَيْسًا وَقَيْسٌ طَارِقًا","trj":"Telah menceritakan kepada kami [Abdullah bin Zubair Al Humaidi] telah menceritakan kepada kami [Sufyan] dari [Mis'ar] dan lainnya dari [Qais bin Muslim] dari [Thariq bin Syihab] ia berkata, \"Seorang laki-laki Yahudi berkata kepada [Umar], \"Wahai Amirul Mukminin, kalaulah ayat ini diturunkan kepada kami, yaitu ayat: '(Hari ini telah Aku sempurnakan untk kalian agama kalian, dan Aku semurkan bagi kalian Nikmat-Ku dan Aku ridhai Islam sebagai agama kalian) ' (Qs. Al Maidah: 2), niscaya telah kami jadikan hari itu sebagai hari raya.\" Lantas Umar berkata, \"Sungguh, aku tahu hari apa ayat itu diturunkan. Ayat itu diturunkan di hari Arafah pada hari jumat.\" Sufyan mendengar dari Mis'ar, Mis'ar mendengar dari Qais, dan Qais mendengar dari Thariq."},{"p":"Bukhari","n":6411,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي مُوسَى بْنُ أَنَسٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَقَالَ رَجُلٌ يَا نَبِيَّ اللَّهِ مَنْ أَبِي قَالَ أَبُوكَ فُلَانٌ وَنَزَلَتْ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] Telah mengabarkan kepada kami [Rauh bin Ubadah] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Musa bin Anas] berkata, \"Aku mendengar [Anas bin Malik] berkata, \"Seseorang bertanya 'Wahai nabiyullah, siapa ayahku?\" Rasul menjawab: \"Ayahmu si A.\" Lantas turunlah ayat: '(Wahai orang-orang yang beriman, janganlah kalian bertanya tentang sesuatu…). (Qs. Al Maidah: 101) "},{"p":"Bukhari","n":6607,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ مَنْ حَدَّثَكَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا وَقَالَ مُحَمَّدٌ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْمَنْ حَدَّثَكَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ الْوَحْيِ فَلَا تُصَدِّقْهُ إِنَّ اللَّهَ تَعَالَى يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ismail] dari [Asy Sya'bi] dari [Masruq] dari [Aisyah] radliyallahu'anhuma, ia berkata, \"Siapa saja yang menceritakan kepadamu bahwa Muhammad shallallahu 'alaihi wasallam menyembunyikan sesuatu…sedang [Muhammad] berkata, telah menceritakan kepada kami [Abu Amir Al 'Aqadi] telah menceritakan kepada kami [Syu'bah] dari [Ismail bin Abu Khalid] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] berkata, \"Siapa saja yang menceritakan kepadamu bahwa Nabi shallallahu 'alaihi wasallam menyembunyikan sesuatu dari wahyu, maka janganlah kamu mempercayainya, sebab Allah Ta'ala berfirman: '(Wahai rasul, sampaikan yang diturunkan kepadamu dari Tuhanmu, jika kamu tidak mengerjakan lantas tidak kau sampaikan risalah….) ' (Qs. Al Maidah: 67)."},{"p":"Darimi","n":422,"ar":" حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مَسْعُودُ بْنُ عَلِيٍّ عَنْ عِكْرِمَةَ أَنَّ سَعْدًا كَانَ يُصَلِّي الصَّلَوَاتِ كُلَّهَا بِوُضُوءٍ وَاحِدٍ وَأَنَّ عَلِيًّا كَانَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ وَتَلَا هَذِهِ الْآيَةَ { إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ وَأَيْدِيَكُمْ } الْآيَةَ","trj":"Telah menceritakan kepada kami [Abdus Shamad bin Abdul Warits] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Mas'ud bin Ali] dari ['Ikrimah]. Bahwasanya [Sa'ad] menunaikan beberapa shalat dengan satu wudhu, sedangkan [Ali] selalu berwudhu untuk setiap shalat, dan ia membaca ayat ini: \"IDZAA QUMTUM ILAS SHALATI FAGHSILUU WUJUUHAKUM WA AIDIYAKUM...\" (Apabila kalian hendak menunaikan shalat basuhlah wajah dan kedua tanganmu...) -Qs. Al Ma`idah: 6-\"."},{"p":"Darimi","n":424,"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ حَتَّى كَانَ يَوْمُ فَتْحِ مَكَّةَ صَلَّى الصَّلَوَاتِ بِوُضُوءٍ وَاحِدٍ وَمَسَحَ عَلَى خُفَّيْهِ فَقَالَ لَهُ عُمَرُ رَأَيْتُكَ صَنَعْتَ شَيْئًا لَمْ تَكُنْ تَصْنَعُهُ قَالَ إِنِّي عَمْدًا صَنَعْتُ يَا عُمَرُ قَالَ أَبُو مُحَمَّد فَدَلَّ فِعْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ مَعْنَى قَوْلِ اللَّهِ تَعَالَى { إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ } الْآيَةَ لِكُلِّ مُحْدِثٍ لَيْسَ لِلطَّاهِرِ وَمِنْهُ قَوْلُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وُضُوءَ إِلَّا مِنْ حَدَثٍ وَاللَّهُ أَعْلَمُ","trj":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Ibnu Buraidah] dari [ayahnya] ia berkata: \"Rasulullah shallallahu 'alaihi wasallam selalu berwudhu untuk setiap shalatnya hingga hari fathu Makkah (penaklukan kota Makkah), beliau shalat beberapa waktu shalat dengan satu wudhu, dan beliau (cukup) mengusap kedua khufnya, lalu Umar bertanya kepada beliau: 'Aku melihat kamu melakukan sesuatu yang belum pernah kamu lakukan sebelumnya? ', beliau menjawab: 'Aku melakukan itu dengan sengaja wahai Umar', Abu Muhammad berkata: 'Perbuatan Rasulullah shallallahu 'alaihi wasallam ini (menunjukkan) bahwa makna firman Allah subhanallahu wa ta'aa: \"IDZAA QUMTUM ILASSHALATI FAGHSILUU WUJUHAKUM\" (Apabila kalian hendak menunaikan shalat, hendaklah ia membasuh wajah kalian) -Qs. Al Ma`idah: 6- itu untuk setiap orang yang berhadats dan bukan untuk orang yang masih suci, (yang semakna) diantaranya sabdanya: 'Tidaklah wajib wudhu itu melainkan untuk orang yang berhadats.\""},{"p":"Darimi","n":1644,"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَ كُنْتُ سَاقِيَ الْقَوْمِ فِي مَنْزِلِ أَبِي طَلْحَةَ قَالَ فَنَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ فَأَمَرَ مُنَادِيًا فَنَادَى فَقَالَ أَبُو طَلْحَةَ اخْرُجْ فَانْظُرْ مَا هَذَا فَخَرَجْتُ فَقُلْتُ هَذَا مُنَادٍ يُنَادِي أَلَا إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ فَقَالَ لِيَ اذْهَبْ فَأَهْرِقْهَا قَالَ فَجَرَتْ فِي سِكَكِ الْمَدِينَةِ قَالَ وَكَانَتْ خَمْرُهُمْ يَوْمَئِذٍ الْفَضِيخَ فَقَالَ بَعْضُ الْقَوْمِ قُتِلَ قَوْمٌ وَهِيَ فِي بُطُونِهِمْ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ { لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا إِذَا مَا اتَّقَوْا وَآمَنُوا } الْآيَةَ","trj":"Telah mengabarkan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Tsabit] dari [Anas], ia berkata; Ketika aku menuangkan minuman di rumah Abu Thalhah. Anas melanjutkan; tiba-tiba turunlah (ayat) yang mengharamkan khamer. Kemudian beliau memerintahkan seseorang untuk menyeru, ia pun menyeru. Lalu Abu Thalhah berkata; \"Keluarlah dan lihatlah ada apa itu?, \" Akupun keluar, setelah itu aku berkata; \"Itu adalah orang yang menyeru, ketahuilah bahwa khamer telah diharamkan.\" Abu Thalhah berkata kepadaku; \"Pergi dan tumpahkanlah khamer tersebut.\" Anas berkata; \"Berita itu kemudian tersebar ke seantero penjuru Madinah, khamer mereka saat itu adalah fadikh (khmer yang terbuat dari rendaman kurma pentil). Kemudian sebagian orang mengatakan; \"Beberapa orang telah meninggal, sementara perut mereka masih terisi khamer.\" Maka Allah 'azza wajalla menurunkan ayat: Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang saleh karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman. QS Al Ma`idah; 93."},{"p":"Ibnu Majah","n":504,"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ قَالَبَالَ جَرِيرُ بْنُ عَبْدِ اللَّهِ ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقِيلَ لَهُ أَتَفْعَلُ هَذَا قَالَ وَمَا يَمْنَعُنِي وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُقَالَ إِبْرَاهِيمُ كَانَ يُعْجِبُهُمْ حَدِيثُ جَرِيرٍ لِأَنَّ إِسْلَامَهُ كَانَ بَعْدَ نُزُولِ الْمَائِدَةِ","trj":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Ibrahim] dari [Hammam Ibnul Harits] ia berkata; [Jarir bin Abdullah kencing], kemudian ia berwudlu dan mengusap khufnya. Lalu ditanyakan kepadanya; \"Kenapa engkau melakukan ini?\" ia menjawab; \"Apa yang menghalangiku! Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam melakukan seperti itu.\" Ibrahim berkata; \"Orang-orang merasa ta'ajub dengan hadits Jarir, sebab ia masuk Islam setelah turunnya surat Al Maidah.\""},{"p":"Ibnu Majah","n":2069,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سُلَيْمَانَ بْنِ أَبِي الْمُغِيرَةِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ الرَّجُلُ يَقُوتُ أَهْلَهُ قُوتًا فِيهِ سَعَةٌ وَكَانَ الرَّجُلُ يَقُوتُ أَهْلَهُ قُوتًا فِيهِ شِدَّةٌ فَنَزَلَتْ{ مِنْ أَوْسَطِ مَا تُطْعِمُونَ أَهْلِيكُمْ }","trj":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Sulaiman bin Abul Mughirah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Seorang lelaki memberi makanan pokok pada keluarganya dengan berlebihan, dan ada juga yang memberi makanan pokok pada keluarganya dengan kekurangan, lalu turunlah ayat: ' Yaitu dari makanan yang biasa kamu berikan kepada keluargamu'.\" (QS. Al Maidah; 89)."},{"p":"Ibnu Majah","n":3959,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ قَالَقَامَ أَبُو بَكْرٍ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }وَإِنَّا سَمِعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ النَّاسَ إِذَا رَأَوْا الْمُنْكَرَ لَا يُغَيِّرُونَهُ أَوْشَكَ أَنْ يَعُمَّهُمْ اللَّهُ بِعِقَابِهِ قَالَ أَبُو أُسَامَةَ مَرَّةً أُخْرَى فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dia berkata, \" [Abu Bakar] berdiri sambil bersyukur kepada Allah dan memuji-Nya, kemudian dia berkata, \"Wahai sekalian manusia, kalian membaca ayat ini '(Hai orang-orang yang beriman, jagalah dirimu, tiadalah orang yang sesat itu akan memberi mudlarat kepadamu apabila kamu telah mendapat petunjuk) ' (Qs. Al Maidah: 105), dan sesungguhnya kami mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya manusia apabila melihat kemungkaran, kemudian mereka tidak merubahnya di khawatirkan Allah akan meratakan adzab-Nya kepada mereka.\" Sekali waktu Abu Usamah menyebutkan, \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda.\""},{"p":"Ibnu Majah","n":3960,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَنِي إِسْرَائِيلَ لَمَّا وَقَعَ فِيهِمْ النَّقْصُ كَانَ الرَّجُلُ يَرَى أَخَاهُ عَلَى الذَّنْبِ فَيَنْهَاهُ عَنْهُ فَإِذَا كَانَ الْغَدُ لَمْ يَمْنَعْهُ مَا رَأَى مِنْهُ أَنْ يَكُونَ أَكِيلَهُ وَشَرِيبَهُ وَخَلِيطَهُ فَضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ وَنَزَلَ فِيهِمْ الْقُرْآنُ فَقَالَ{ لُعِنَ الَّذِينَ كَفَرُوا مِنْ بَنِي إِسْرَائِيلَ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ حَتَّى بَلَغَ وَلَوْ كَانُوا يُؤْمِنُونَ بِاللَّهِ وَالنَّبِيِّ وَمَا أُنْزِلَ إِلَيْهِ مَا اتَّخَذُوهُمْ أَوْلِيَاءَ وَلَكِنَّ كَثِيرًا مِنْهُمْ فَاسِقُونَ }قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا فَجَلَسَ وَقَالَ لَا حَتَّى تَأْخُذُوا عَلَى يَدَيْ الظَّالِمِ فَتَأْطِرُوهُ عَلَى الْحَقِّ أَطْرًاحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ أَمْلَاهُ عَلَيَّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْوَضَّاحِ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika terjadi krisis moral di tengah-tengah Bani Israil, ada seorang laki-laki melihat saudaranya berbuat dosa, maka dia pun melarangnya. Namun di esok harinya dia tidak mencegahnya dari apa yang dia lihat dari saudaranya supaya dia menjadi teman makan, teman minum dan teman bergaul. Maka Allah menutup hati mereka dengan sebagian yang lain, dan turunlah ayat Al Quran mengenai diri mereka, Allah berfirman: '(Telah dilaknati orang-orang kafir dari Bani Israil dengan lisan Daud dan 'Isa putera Maryam...) ' sampai pada ayat '(Sekiranya mereka beriman kepada Allah, kepada Nabi (Musa) dan kepada apa yang diturunkan kepadanya (Nabi), niscaya mereka tidak akan mengambil orang-orang musyrikin itu menjadi penolong-penolong, tapi kebanyakan dari mereka adalah orang-orang yang fasik) ' (Qs. Al Maidah: 78-81). Abu 'Ubaidah berkata, \"Rasulullah shallallahu 'alaihi wasallam pada saat itu bersandar kemudian duduk seraya bersabda: \"Tidak, sehingga kalian mengambil dari kedua tangan orang yang zhalim, kemudian kalian benar-benar meletakkannya kepada jalan yang benar.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud] yang ia diktekan kepadaku, telah menceritakan kepada kami [Muhammad bin Abu Al Waddlah] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},{"p":"Ibnu Majah","n":3968,"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنِي عُتْبَةُ بْنُ أَبِي حَكِيمٍ حَدَّثَنِي عَنْ عَمِّهِ عَمْرِو بْنِ جَارِيَةَ عَنْ أَبِي أُمَيَّةَ الشَّعْبَانِيِّ قَالَأَتَيْتُ أَبَا ثَعْلَبَةَ الْخُشَنِيَّ قَالَ قُلْتُ كَيْفَ تَصْنَعُ فِي هَذِهِ الْآيَةِ قَالَ أَيَّةُ آيَةٍ قُلْتُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }قَالَ سَأَلْتَ عَنْهَا خَبِيرًا سَأَلْتُ عَنْهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَلْ ائْتَمِرُوا بِالْمَعْرُوفِ وَتَنَاهَوْا عَنْ الْمُنْكَرِ حَتَّى إِذَا رَأَيْتَ شُحًّا مُطَاعًا وَهَوًى مُتَّبَعًا وَدُنْيَا مُؤْثَرَةً وَإِعْجَابَ كُلِّ ذِي رَأْيٍ بِرَأْيِهِ وَرَأَيْتَ أَمْرًا لَا يَدَانِ لَكَ بِهِ فَعَلَيْكَ خُوَيْصَةَ نَفْسِكَ فَإِنَّ مِنْ وَرَائِكُمْ أَيَّامَ الصَّبْرِ الصَّبْرُ فِيهِنَّ عَلَى مِثْلِ قَبْضٍ عَلَى الْجَمْرِ لِلْعَامِلِ فِيهِنَّ مِثْلُ أَجْرِ خَمْسِينَ رَجُلًا يَعْمَلُونَ بِمِثْلِ عَمَلِهِ","trj":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Shadaqah bin Khalid] telah menceritakan kepadaku ['Utbah bin Abu Hakim] telah menceritakan kepadaku dari pamannya ['Amru bin Jariyah] dari [Abu Umayyah As Sya'bani] dia berkata; Saya pernah mendatangi [Abu Tsa'labah Al Khusyani] dan bertanya, \"Apa yang kamu perbuat dengan ayat ini?\" Abu Tsa'labah ganti bertanya, \"Ayat yang mana?\" aku lalu membaca: '(Hai orang-orang yang beriman, jagalah dirimu; tiadalah orang yang sesat itu akan memberi mudharat kepadamu apabila kamu telah mendapat petunjuk) ' (Qs. Al Maidah; 105). Abu Tsa'labah lalu berkata, \"Kamu bertanya kepada orang yang tahu, aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang itu, dan beliau menjawab: \"Yaitu mereka saling memerintahkan kepada kebaikan dan saling melarang pada yang mungkar, sehingga jika kamu melihat bakhil ditaati, hawa nafsu diikuti, dunia yang diprioritaskan, setiap orang bangga dengan pendapatnya, dan kamu melihat perkara tidak sesuai denganmu, maka kamu harus kembalikan kepada mata hatimu. Karena sesungguhnya di belakang kalian adalah hari-hari kesabaran, kesabaran saat itu seperti seseorang menggenggam bara api, bagi orang yang beramal pada saat itu seperti pahala lima puluh orang yang mengamalkan seperti amalannya.\""},{"p":"Malik","n":823,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ عَبْدِ الْمَلِكِ بْنِ قُرَيْرٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ أَنَّ رَجُلًا جَاءَ إِلَى عُمَرَ بْنِ الْخَطَّابِفَقَالَ إِنِّي أَجْرَيْتُ أَنَا وَصَاحِبٌ لِي فَرَسَيْنِ نَسْتَبِقُ إِلَى ثُغْرَةِ ثَنِيَّةٍ فَأَصَبْنَا ظَبْيًا وَنَحْنُ مُحْرِمَانِ فَمَاذَا تَرَى فَقَالَ عُمَرُ لِرَجُلٍ إِلَى جَنْبِهِ تَعَالَ حَتَّى أَحْكُمَ أَنَا وَأَنْتَ قَالَ فَحَكَمَا عَلَيْهِ بِعَنْزٍ فَوَلَّى الرَّجُلُ وَهُوَ يَقُولُ هَذَا أَمِيرُ الْمُؤْمِنِينَ لَا يَسْتَطِيعُ أَنْ يَحْكُمَ فِي ظَبْيٍ حَتَّى دَعَا رَجُلًا يَحْكُمُ مَعَهُ فَسَمِعَ عُمَرُ قَوْلَ الرَّجُلِ فَدَعَاهُ فَسَأَلَهُ هَلْ تَقْرَأُ سُورَةَ الْمَائِدَةِ قَالَ لَا قَالَ فَهَلْ تَعْرِفُ هَذَا الرَّجُلَ الَّذِي حَكَمَ مَعِي فَقَالَ لَا فَقَالَ لَوْ أَخْبَرْتَنِي أَنَّكَ تَقْرَأُ سُورَةَ الْمَائِدَةِ لَأَوْجَعْتُكَ ضَرْبًا ثُمَّ قَالَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ فِي كِتَابِهِ{ يَحْكُمُ بِهِ ذَوَا عَدْلٍ مِنْكُمْ هَدْيًا بَالِغَ الْكَعْبَةِ }وَهَذَا عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ","trj":"Telah menceritakan kepadaku dari Malik dari [Abdul Malik bin Qurair] dari [Muhammmad bin Sirin] berkata, \"Seorang laki-laki menemui [Umar bin Khattab] dan bertanya, \"Saya dan sahabatku lomba berpacu dengan dua ekor kuda, lalu kami menambrak kijang, sementara kami dalam keadaan ihram. Lalu apa pendapatmu?\" Umar berkata kepada [seseorang] yang berada di sampingnya, \"Mari kita bermusyawarah untuk menghukumi kejadian tersebut! \" Muhammmad bin Sirin berkata; \"Kemudian keduanya menghukumi mereka dengan membayar denda satu ekor kambing. Penanya tadi pergi sambil berkata, \"Amirul mukminin kok tidak bisa memberi putusan dalam masalah seekor kijang kecuali harus bersama orang lain! \" Umar mendengar ucapan orang tadi, lalu memanggilnya dan bertanya kepadanya, \"Apakah kamu telah membaca Surat Al Maidah?\" laki-laki itu menjawab, \"Tidak.\" Umar bertanya lagi, \"Tahukah kamu siapa laki-laki tadi yang telah bermusyawarah untuk menghukumi kejadian tersebut bersamaku?\" orang tadi menjawab, \"Saya tidak tahu.\" 'Umar bin Khattab berkata; \"Seandainya kamu memberitahuku bahwa kamu telah membaca Surat Al Maidah, niscaya saya akan memukulmu.\" Kemudian Umar berkata, \"Allah Tabaraka Wa Ta'ala berfirman dalam Kitab-Nya: '(Menurut putusan dua orang yang adil di antara kamu sebagai hadyu (ialah: binatang unta, lembu, kambing, biri-biri) yang dibawa ke Ka'bah untuk mendekatkan diri kepada Allah, disembelih di tanah Haram dan dagingnya dihadiahkan kepada fakir miskin dalam rangka ibadat haji) yang dibawa sampai ke Ka'bah) ' -Qs. Al Maidah: 95- Dan orang itu adalah Abdurrahman bin Auf."},{"p":"Malik","n":924,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّهُ سُئِلَ عَنْ ذَبَائِحِ نَصَارَى الْعَرَبِ فَقَالَ لَا بَأْسَ بِهَا وَتَلَا هَذِهِ الْآيَةَ{ وَمَنْ يَتَوَلَّهُمْ مِنْكُمْ فَإِنَّهُ مِنْهُمْ }و حَدَّثَنِي عَنْ مَالِك أَنَّهُ بَلَغَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ كَانَ يَقُولُ مَا فَرَى الْأَوْدَاجَ فَكُلُوهُ","trj":"Telah menceritakan kepadaku dari Malik dari [Tsaur bin Zaid Ad-Dili] dari [Abdullah bin Abbas] Bahwasanya ia pernah ditanya tentang sembelihan orang Nasrani Arab. Ibnu Abbas lalu menjawab, \"Itu tidak apa-apa.\" kemudian dia membaca ayat ini: '(Barangsiapa yang menjadikan mereka (orang-orang Nasrani) sebagai wali bagi kalian maka sesungguhnya dia bagian dari mereka) ' (Qs. Al Maidah: 51) Telah menceritakan kepadaku dari Malik telah sampai kepadanya bahwa Abdullah bin Abbas berkata; \"Sesuatu yang dapat memutuskan urat leher binatang, maka makanlah dagingnya.\""},{"p":"Malik","n":1308,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ زُرَيْقِ بْنِ حَكِيمٍ أَنَّهُ أَخْبَرَهُ أَنَّهُ أَخَذَ عَبْدًا آبِقًا قَدْ سَرَقَ قَالَ فَأَشْكَلَ عَلَيَّ أَمْرُهُ قَالَ فَكَتَبْتُ فِيهِ إِلَى عُمَرَ بْنِ عَبْدِ الْعَزِيزِأَسْأَلُهُ عَنْ ذَلِكَ وَهُوَ الْوَالِي يَوْمَئِذٍ قَالَ فَأَخْبَرْتُهُ أَنَّنِي كُنْتُ أَسْمَعُ أَنَّ الْعَبْدَ الْآبِقَ إِذَا سَرَقَ وَهُوَ آبِقٌ لَمْ تُقْطَعْ يَدُهُ قَالَ فَكَتَبَ إِلَيَّ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ نَقِيضَ كِتَابِي يَقُولُ كَتَبْتَ إِلَيَّ أَنَّكَ كُنْتَ تَسْمَعُ أَنَّ الْعَبْدَ الْآبِقَ إِذَا سَرَقَ لَمْ تُقْطَعْ يَدُهُ وَإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ فِي كِتَابِهِ{ وَالسَّارِقُ وَالسَّارِقَةُ فَاقْطَعُوا أَيْدِيَهُمَا جَزَاءً بِمَا كَسَبَا نَكَالًا مِنْ اللَّهِ وَاللَّهُ عَزِيزٌ حَكِيمٌ }فَإِنْ بَلَغَتْ سَرِقَتُهُ رُبُعَ دِينَارٍ فَصَاعِدًا فَاقْطَعْ يَدَهُو حَدَّثَنِي عَنْ مَالِك أَنَّهُ بَلَغَهُ أَنَّ الْقَاسِمَ بْنَ مُحَمَّدٍ وَسَالِمَ بْنَ عَبْدِ اللَّهِ وَعُرْوَةَ بْنَ الزُّبَيْرِ كَانُوا يَقُولُونَ إِذَا سَرَقَ الْعَبْدُ الْآبِقُ مَا يَجِبُ فِيهِ الْقَطْعُ قُطِعَ قَالَ مَالِك وَذَلِكَ الْأَمْرُ الَّذِي لَا اخْتِلَافَ فِيهِ عِنْدَنَا أَنَّ الْعَبْدَ الْآبِقَ إِذَا سَرَقَ مَا يَجِبُ فِيهِ الْقَطْعُ قُطِعَ","trj":"Telah menceritakan kepadaku dari Malik dari [Zuraiq bin Hakim] ia mengabarkan kepadanya, bahwa ia menemukan seorang budak yang kabur setelah mencuri. Zuraiq melanjutkan; \"Hal ini mengundang masalah bagiku. Maka aku menulis surat kepada Umar bin Abdul Aziz yang saat itu menjadi gubernur, untuk menanyakan hal tersebut. Aku kabarkan kepadanya bahwa aku mendengar seorang hamba yang melarikan diri jika mencuri dan kabur, maka tangannya tidak dipotong.\" Zuraiq melanjutkan, \" [Umar bin Abdul Aziz] lalu membalas suratku dan mengatakan; 'Kamu menulis surat kepadaku bahwasanya kamu telah mendengar, jika seorang hamba yang melarikan diri mencuri lalu dia kabur, maka tidak dipotong tangannya, sedangkan Allah Tabaraka Wa Ta'ala dalam kitab-Nya berfirman; \"Seorang pencuri baik laki-laki maupun perempuan maka potonglah tangannya sebagai balasan dari perbuatannya dan hukuman dari Allah, dan Allah Maha Mulia dan Maha Bijaksana) ' (Qs. Al Maidah: 38) jika barang curiannya mencapai seperempat dinar atau lebih, maka potonglah tangannya.\" Telah menceritakan kepadaku dari Malik, bahwasanya telah sampai kepadanya, bahwa Al Qasim bin Muhammad dan Salim bin Abdullah dan 'Urwah bin Zubair mereka mengatakan; \"Jika budak yang melarikan diri mencuri sesuatu yang mencapai kewajiban untuk dipotong, maka tangannya dipotong.\" Malik berkata; \"Itu adalah perkara yang tidak ada perbedaan pendapat di antara kami, yaitu jika seorang hamba yang kabur mencuri barang yang mencapai kewajiban potonga tangan, maka tangannya harus dipotong.\""},{"p":"Muslim","n":256,"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَكُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْ يَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قُلْتُ مَا هُنَّ قَالَتْ مَنْ زَعَمَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ قَالَ وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِي��َ أَنْظِرِينِي وَلَا تَعْجَلِينِي أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }فَقَالَتْ أَنَا أَوَّلُ هَذِهِ الْأُمَّةِ سَأَلَ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ جِبْرِيلُ لَمْ أَرَهُ عَلَى صُورَتِهِ الَّتِي خُلِقَ عَلَيْهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ فَقَالَتْ أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }أَوَ لَمْ تَسْمَعْ أَنَّ اللَّهَ يَقُولُ{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِيَ بِإِذْنِهِ مَا يَشَاءُ إِنَّهُ عَلِيٌّ حَكِيمٌ }قَالَتْ وَمَنْ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ كِتَابِ اللَّهِ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }قَالَتْ وَمَنْ زَعَمَ أَنَّهُ يُخْبِرُ بِمَا يَكُونُ فِي غَدٍ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا دَاوُدُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَزَادَ قَالَتْ وَلَوْ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا مِمَّا أُنْزِلَ عَلَيْهِ لَكَتَمَ هَذِهِ الْآيَةَ{ وَإِذْ تَقُولُ لِلَّذِي أَنْعَمَ اللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَاتَّقِ اللَّهَ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ وَاللَّهُ أَحَقُّ أَنْ تَخْشَاهُ }حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ سُبْحَانَ اللَّهِ لَقَدْ قَفَّ شَعَرِي لِمَا قُلْتَ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَحَدِيثُ دَاوُدَ أَتَمُّ وَأَطْوَلُ","trj":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Dawud] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Ketika aku duduk bersandar di samping [Aisyah], maka dia berkata, 'Wahai Abu Aisyah (Masruq)! Ada tiga perkara, barangsiapa yang memperbincangkan salah satu darinya, berarti dia telah melakukan pembohongan yang amat besar terhadap Allah.' Aku bertanya, 'Apakah tiga perkara itu? ' Aisyah menjawab, 'Pertama, barangsiapa mengklaim bahwa Muhammad shallallahu 'alaihi wasallam melihat Tuhannya maka sungguh dia telah membesarkan kebohongannya terhadap Allah.' Aku yang duduk bersandar dari tadi, maka aku mulai duduk dengan baik, lalu aku berkata, 'Wahai Ummul Mukminin! Berilah aku tempo, dan janganlah kamu membuatku terburu-buru, (dengarlah kata-kataku ini terlebih dahulu), bukankah Allah telah berfirman: '(Dan sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain) ' (Qs. Al Takwir: 23). Dan Firman Allah lagi: '(Dan sungguh Muhammad telah melihat 'dia' dalam bentuk rupanya yang asal sekali lagi) ' (Qs. An Najm: 13). Maka Aisyah menjawab, 'Aku adalah orang yang pertama bertanya kepada Rasulullah shallallahu 'alaihi wasallam. mengenai perkara ini dari kalangan umat ini. Beliau telah menjawab dengan bersabda: \"Yang dimaksud 'dia' dalam ayat itu adalah Jibril (bukan Allah), aku tidak pernah melihat Jibril dalam bentuk asalnya kecuali dua kali saja, yaitu semasa dia turun dari langit dalam keadaan yang terlalu besar sehingga memenuhi di antara lagit dan bumi.' Kemudian Aisyah berkata lagi, 'Apakah kamu tidak pernah mendengar bahwa Allah: '(Dia tidak dapat dilihat oleh penglihatan mata, sedangkan Dia dapat melihat dan mengetahui hakikat segala penglihatan mata, dan Dialah Yang Maha Bersifat Lemah Lembut lagi Maha Mendalam pengetahuannya) ' (Qs. Al An'am: 103). Atau, apakah kamu tidak pernah mendengar firman Allah: '(Dan tidaklah layak bagi seorang manusia, bahwa Allah mengajaknya berbicara kecuali berupa wahyu (dengan diberi mimpi) atau dari balik dinding (dengan mendengar suara saja) atau dengan mengutuskan utusan (Malaikat), lalu utusan itu menyampaikan wahyu kepadanya dengan izin Allah sesuatu yang dikehendaki-Nya. Sesungguhnya Allah Maha Tinggi, lagi Maha Bijaksana) '. (Qs. Asy Syura: 51). Kemudian Aisyah berkata lagi, 'Barangsiapa yang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam telah menyembunyikan sebagian dari kitab Allah, maka sungguh dia telah membesarkan pendustaan terhadap Allah, sebagaimana firman Allah: '(Wahai Rasulullah, sampaikanlah sesuatu yang diturunkan kepadamu, dan jika kamu tidak melakukannya, maka berarti kamu tidak menyampaikan risalah-Nya) ' (Qs. Al Maidah: 67). Kemudian Aisyah berkata, \"Barangsiapa mengklaim bahwa dia mampu mengabarkan tentang takdir yang akan terjadi besok, maka sungguh dia telah membesarkan kebohongan terhadap Allah. Allah berfirman: '(Katakanlah (hai Muhammad), tidak satu pun makhluk yang di langit dan bumiyang mengetahui kegaiban kecuali Allah) '. (Qs. An Naml: 65). Dan telah menceritakan kepada kami [Muhammad bin al-Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Dawud] dengan sanad ini semisal hadits Ibnu Ulayyah, dan dia menambahkan, \"Aisyah berkata, 'Kalau seandainya Muhammad telah menyembunyikan sebagian dari wahyu yang diturunkan kepadanya, niscaya dia menyembunyikan ayat ini: '(Dan (ingatlah), ketika kamu berkata kepada orang yang mana Allah telah melimpahkan nikmat kepadanya dan kamu (juga) telah memberi nikmat kepadanya, 'Tahanlah terus isterimu dan bertaqwalah kepada Allah', sedang kamu menyembunyikan di dalam hatimu sesuatu yang mana Allah akan menyatakannya, dan kamu takut kepada manusia, sedang Allah-lah yang lebih berhak untuk kamu takuti) ' (Qs. al-Ahzab: 37). Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ismail] dari [asy-Sya'bi] dari [Masruq] dia berkata, \"Aku bertanya kepada [Aisyah], 'Apakah Muhammad shallallahu 'alaihi wasallam melihat Rabbnya? ' Dia menjawab, 'Mahasuci Allah, sungguh bulu kuduku merinding karena perkataan yang kamu ucapkan tadi'.\" Lalu dia membawakan hadits tersebut dengan kisahnya. Dan hadits Dawud lebih sempurna dan panjang.\""},{"p":"Muslim","n":294,"ar":"حَدَّثَنِي يُونُسُ بْنُ عَبْدِ الْأَعْلَى الصَّدَفِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ بَكْرَ بْنَ سَوَادَةَ حَدَّثَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلَا قَوْلَ اللَّهِ عَزَّ وَجَلَّ فِي إِبْرَاهِيمَ{ رَبِّ إِنَّهُنَّ أَضْلَلْنَ كَثِيرًا مِنْ النَّاسِ فَمَنْ تَبِعَنِي فَإِنَّهُ مِنِّي }الْآيَةَ وَقَالَ عِيسَى عَلَيْهِ السَّلَام{ إِنْ تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ وَإِنْ تَغْفِرْ لَهُمْ فَإِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ }فَرَفَعَ يَدَيْهِ وَقَالَ اللَّهُمَّ أُمَّتِي أُمَّتِي وَبَكَى فَقَالَ اللَّهُ عَزَّ وَجَلَّ يَا جِبْرِيلُ اذْهَبْ إِلَى مُحَمَّدٍ وَرَبُّكَ أَعْلَمُ فَسَلْهُ مَا يُبْكِيكَ فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَسَأَلَهُ فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا قَالَ وَهُوَ أَعْلَمُ فَقَالَ اللَّهُ يَا جِبْرِيلُ اذْهَبْ إِلَى مُحَمَّدٍ فَقُلْ إِنَّا سَنُرْضِيكَ فِي أُمَّتِكَ وَلَا نَسُوءُكَ","trj":"Telah menceritakan kepada kami [Yunus bin Abdul A'la ash-Shadafi] telah mengabarkan kepada kami [Ibnu Wahb] dia berkata, telah mengabarkan kepada kami [Amru bin al-Harits] bahwa [Bakr bin Sawadah] telah menceritakan kepadanya dari [Abdurrahman bin Jubair] dari [Abdullah bin Amr bin al-'Ash] bahwa Nabi shallallahu 'alaihi wasallam pernah membaca firman Allah mengenai Ibrahim: '(Ya Tuhanku, sesungguhnya berhala-berhala itu telah menyesatkan kebanyakan daripada manusia, maka barangsiapa yang mengikutiku, Maka Sesungguhnya orang itu termasuk golonganku) ' (Qs. Ibrahim: 36) hingga akhir ayat. Dan mengenai Isa Alaihissalam: '(Jika Engkau menyiksa mereka, maka sesungguhnya mereka adalah hamba-hamba Engkau, dan jika Engkau mengampuni mereka, maka sesungguhnya Engkaulah yang Maha Perkasa lagi Maha Bijaksana) ' (Qs. Al Maidah: 118), kemudian beliau mengangkat kedua tangannya seraya berdo'a: \"Ya Allah, selamatkanlah umatku, selamatkanlah umatku, \" dengan bercucuran air mata. Kemudian Allah 'azza wajalla berkata kepada malaikat Jibril: \"Temuilah Muhammad -dan Rabbmulah yang lebih tahu- dan tanyakan kepadanya, 'Apa yang membuatmu menangis? ' Maka malaikat Jibril pun bertanya kepada beliau, dan beliau shallallahu 'alaihi wasallam menjawabnya dengan apa yang dikatakan Allah-dan Allah lebih mengetahui hal itu-. Kemudian Allah berkata: 'Wahai Jibril, temuilah Muhammad dan katakan bahwa Kami akan membuatmu senang dengan umatmu dan tidak akan membuatmu sedih karenanya (Kami akan menyelamatkan semua umatmu-pent) '.\""},{"p":"Muslim","n":394,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَأَبُو كُرَيْبٍ جَمِيعًا عَنْ أَبِي مُعَاوِيَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ وَاللَّفْظُ لِيَحْيَى قَالَ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ قَالَبَالَ جَرِيرٌ ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقِيلَ تَفْعَلُ هَذَا فَقَالَ نَعَمْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِقَالَ الْأَعْمَشُ قَالَ إِبْرَاهِيمُ كَانَ يُعْجِبُهُمْ هَذَا الْحَدِيثُ لِأَنَّ إِسْلَامَ جَرِيرٍ كَانَ بَعْدَ نُزُولِ الْمَائِدَةِ و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ خَشْرَمٍ قَالَا أَخْبَرَنَا عِيسَى بْنُ يُونُسَ ح و حَدَّثَنَاه مُحَمَّدُ بْنُ أَبِي عُمَرَ قَالَ حَدَّثَنَا سُفْيَانُ ح و حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ أَخْبَرَنَا ابْنُ مُسْهِرٍ كُلُّهُمْ عَنْ الْأَعْمَشِ فِي هَذَا الْإِسْنَادِ بِمَعْنَى حَدِيثِ أَبِي مُعَاوِيَةَ غَيْرَ أَنَّ فِي حَدِيثِ عِيسَى وَسُفْيَانَ قَالَ فَكَانَ أَصْحَابُ عَبْدِ اللَّهِ يُعْجِبُهُمْ هَذَا الْحَدِيثُ لِأَنَّ إِسْلَامَ جَرِيرٍ كَانَ بَعْدَ نُزُولِ الْمَائِدَةِ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya al-Tamimi] dan [Ishaq bin Ibrahim] serta [Abu Kuraib] semuanya dari [Abu Muawiyah]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dan [Waki'] dan lafazh tersebut milik Yahya, dia berkata, telah mengabarkan kepada kami [Abu Mu'awiyah] dari [al-A' masy] dari [Ibrahim] dari [Hammam] dia berkata, \"Suatu ketika [Jarir] kencing kemudian berwudlu dengan menyapu sepasang khufnya. Lalu Jarir ditegur, 'Begini kamu lakukan? ' Jarir menjawab, \"Ya, aku pernah melihat Rasulullah shallallahu 'alaihi wasallam kencing, kemudian berwudlu dan menyapu sepasang khuf beliau.\" [Al-A'masy] berkata, [Ibrahim] berkata, \"Hadits ini membuat kaget mereka, sebab keIslaman Jarir terjadi setelah turunnya surat al-Maidah.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ali bin Khasyram] keduanya berkata, telah mengabarkan kepada kami [Isa bin Yunus]. (dalam riwayat lain disebutkan) Dan telah mengabarkan kepada kami [Muhammad bin Abu Umar] dia berkata, telah menceritakan kepada kami [Sufyan]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Minjab bin al-Harits at-Tamimi] telah mengabarkan kepada kami [Ibnu Mushir] setiap mereka dari [al-A'masy] dalam sanad ini dengan makna hadits Abu Muawiyah, hanya saja dalam hadits Isa dan Sufyan dia berkata, \"Sahabat Abdullah dibuat kaget oleh hadits ini karena keIslaman Jarir setelah turunnya surat al-Ma'idah.\""},{"p":"Muslim","n":540,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ جَمِيعًا عَنْ أَبِي مُعَاوِيَةَ قَالَ أَبُو بَكْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَ كُنْتُ جَالِسًا مَعَ عَبْدِ اللَّهِ وَأَبِي مُوسَى فَقَالَ أَبُو مُوسَىيَا أَبَا عَبْدِ الرَّحْمَنِ أَرَأَيْتَ لَوْ أَنَّ رَجُلًا أَجْنَبَ فَلَمْ يَجِدْ الْمَاءَ شَهْرًا كَيْفَ يَصْنَعُ بِالصَّلَاةِ فَقَالَ عَبْدُ اللَّهِ لَا يَتَيَمَّمُ وَإِنْ لَمْ يَجِدْ الْمَاءَ شَهْرًا فَقَالَ أَبُو مُوسَى فَكَيْفَ بِهَذِهِ الْآيَةِ فِي سُورَةِ الْمَائِدَةِ{ فَلَمْ تَجِدُوا مَاءً فَتَيَمَّمُوا صَعِيدًا طَيِّبًا }فَقَالَ عَبْدُ اللَّهِ لَوْ رُخِّصَ لَهُمْ فِي هَذِهِ الْآيَةِ لَأَوْشَكَ إِذَا بَرَدَ عَلَيْهِمْ الْمَاءُ أَنْ يَتَيَمَّمُوا بِالصَّعِيدِ فَقَالَ أَبُو مُوسَى لِعَبْدِ اللَّهِ أَلَمْ تَسْمَعْ قَوْلَ عَمَّارٍ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ فَأَجْنَبْتُ فَلَمْ أَجِدْ الْمَاءَ فَتَمَرَّغْتُ فِي الصَّعِيدِ كَمَا تَمَرَّغُ الدَّابَّةُ ثُمَّ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَقُولَ بِيَدَيْكَ هَكَذَا ثُمَّ ضَرَبَ بِيَدَيْهِ الْأَرْضَ ضَرْبَةً وَاحِدَةً ثُمَّ مَسَحَ الشِّمَالَ عَلَى الْيَمِينِ وَظَاهِرَ كَفَّيْهِ وَوَجْهَهُفَقَالَ عَبْدُ اللَّهِ أَوَلَمْ تَرَ عُمَرَ لَمْ يَقْنَعْ بِقَوْلِ عَمَّارٍ و حَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ قَالَ قَالَ أَبُو مُوسَى لِعَبْدِ اللَّهِ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ نَحْوَ حَدِيثِ أَبِي مُعَاوِيَةَ غَيْرَ أَنَّهُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَقُولَ هَكَذَا وَضَرَبَ بِيَدَيْهِ إِلَى الْأَرْضِ فَنَفَضَ يَدَيْهِ فَمَسَحَ وَجْهَهُ وَكَفَّيْهِ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya], [Abu Bakar bin Abi Syaibah] dan [Ibnu Numair] semuanya meriwayatkan dari [Abu Muawiyah] [Abu Bakar] berkata, telah menceritakan kepada kami [Abu Muawiyah] dari [al-A'masy] dari [Syaqiq] dia berkata, dia berkata, \"Aku duduk bersama Abdullah dan Abu Musa al-Asy'ari. Kemudian [Abu Musa] berkata kepada [Abdullah], 'Wahai ayah Abdurrahman, seandainya seorang lelaki berjunub lalu dia tidak mendapatkan air selama sebulan, bagaimanakah yang harus dia lakukan dengan shalatnya? ' Maka Abdullah berkata, 'Dia tidak boleh bertayamum, sekalipun dia tidak mendapati air selama sebulan'. Abu Musa berkata, 'Bagaimana dengan ayat di dalam surah al-Maidah, \"Lalu kamu tidak mendapat air (untuk berwudhu dan mandi) maka hendaklah kamu bertayamum dengan tanah yang suci.\" (QS. Almaidah; 6), Abdullah berkata, 'Andai mereka diberi keringanan dengan ayat tersebut, niscaya apabila mereka merasakan air itu dingin maka mereka akan bertayamum dengan tanah.' Maka Abu Musa berkata kepada Abdullah, 'Tidakkah kamu telah mendengar kata-kata Ammar, 'Rasulullah Shallallahu'alaihiwasallam telah mengutusku untuk suatu keperluan kemudian aku berjunub, lalu aku tidak mendapati air, maka aku menggulingkan badan ke tanah sebagaimana binatang melata menggulingkan badannya?. Kemudian kutemui Nabi Shallallahu'alaihiwasallam dan kuceritakan perkara tersebut kepada beliau Shallallahu'alaihiwasallam. Maka Beliau bersabda, 'Sudah cukup memadai bagi kamu dengan kamu menepukkan tangan kamu begini, kemudian beliau menepukkan tangan beliau ke tanah dengan satu tepukan, kemudian beliau menyapu tangan kiri beliau pada tangan kanan dan belakang kedua tapak tangan serta wajah beliau.\" Abdullah berkata, \"Apakah kamu tidak melihat bahwa Umar tidak puas dengan perkataan [Ammar]?.\" Dan telah menceritakan kepada kami [Abu Kamil al-Jahdari] telah menceritakan kepada kami [Abdu Wahid] telah menceritakan kepada kami [al-A'masy] dari [Syaqiq] dia berkata, [Abu Musa] berkata kepada Abdullah, dan ia menggiring hadits tersebut dengan kisahnya semisal hadits Abu Mu'awiyah, hanya saja dia berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam bersabda, 'Cukup memadai bagi kamu untuk mengatakan demikian, lalu beliau memukulkan kedua tangannya pada tanah, lalu mengibaskan kedua tangannya, lalu dia mengusap wajah dan kedua telapak tangannya'.\""},{"p":"Muslim","n":2331,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ الْهَمْدَانِيُّ حَدَّثَنَا أَبِي وَوَكِيعٌ وَابْنُ بِشْرٍ عَنْ إِسْمَعِيلَ عَنْ قَيْسٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ يَقُولُاكُنَّا نَغْزُو مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لَنَا نِسَاءٌ فَقُلْنَا أَلَا نَسْتَخْصِي فَنَهَانَا عَنْ ذَلِكَ ثُمَّ رَخَّصَ لَنَا أَنْ نَنْكِحَ الْمَرْأَةَ بِالثَّوْبِ إِلَى أَجَلٍ ثُمَّ قَرَأَ عَبْدُ اللَّهِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُحَرِّمُوا طَيِّبَاتِ مَا أَحَلَّ اللَّهُ لَكُمْ وَلَا تَعْتَدُوا إِنَّ اللَّهَ لَا يُحِبُّ الْمُعْتَدِينَ }و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَقَالَ ثُمَّ قَرَأَ عَلَيْنَا هَذِهِ الْآيَةَ وَلَمْ يَقُلْ قَرَأَ عَبْدُ اللَّهِ و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَعِيلَ بِهَذَا الْإِسْنَادِ قَالَ كُنَّا وَنَحْنُ شَبَابٌ فَقُلْنَا يَا رَسُولَ اللَّهِ أَلَا نَسْتَخْصِي وَلَمْ يَقُلْ نَغْزُو","trj":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair Al Hamdani] telah menceritakan kepada kami [bapakku] dan [Waki'] dan [Ibnu Bisyr] dari [Isma'il] dari [Qais] ia berkata, saya mendengar [Abdullah] berkata; Kami pernah berperang bersama Rasulullah shallallahu 'alaihi wasallam tanpa membawa isteri, lalu kami berkata, \"Apakah sebaiknya kita mengebiri kemaluan kita?\" Rasulullah shallallahu 'alaihi wasallam melarang kami berbuat demikian, dan beliau memberikan keringanan pada kami untuk menikahi perempuan sampai pada batas waktu tertentu dengan mas kawin pakaian. Kemudian Abdullah bin Mas'ud membaca ayat: \"Hai orang-orang yang beriman, janganlah kamu haramkan apa-apa yang baik yang Telah Allah halalkan bagi kamu, dan janganlah kamu melampaui batas. Sesungguhnya Allah tidak menyukai orang-orang yang melampaui batas.\" (QS. Almaidah; 87). Dan Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Isma'il bin Abu Khalid] dengan isnad ini, semisalnya. Dan ia menyebutkan; \"Kemudian ia membacakan ayat ini kepada kami.\" Ia tidak menyebutkan; (Abdullah) membaca..\" Dan Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dan [Isma'il] dengan isnad ini. ia berkata; Dulu kami adalah para pemuda, dan kami pun bertanya, \"Wahai Rasulullah bolehkan kami mengebiri?\" Namun ia tidak menyebutkan; \"NAGHZUU (kami berperang).\""},{"p":"Muslim","n":2979,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ كِلَاهُمَا عَنْ أَبِي مُعَاوِيَةَ قَالَ يَحْيَى أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَهُودِيٍّ مُحَمَّمًا مَجْلُودًا فَدَعَاهُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالُوا نَعَمْ فَدَعَا رَجُلًا مِنْ عُلَمَائِهِمْ فَقَالَ أَنْشُدُكَ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى أَهَكَذَا تَجِدُونَ حَدَّ الزَّانِي فِي كِتَابِكُمْ قَالَ لَا وَلَوْلَا أَنَّكَ نَشَدْتَنِي بِهَذَا لَمْ أُخْبِرْكَ نَجِدُهُ الرَّجْمَ وَلَكِنَّهُ كَثُرَ فِي أَشْرَافِنَا فَكُنَّا إِذَا أَخَذْنَا الشَّرِيفَ تَرَكْنَاهُ وَإِذَا أَخَذْنَا الضَّعِيفَ أَقَمْنَا عَلَيْهِ الْحَدَّ قُلْنَا تَعَالَوْا فَلْنَجْتَمِعْ عَلَى شَيْءٍ نُقِيمُهُ عَلَى الشَّرِيفِ وَالْوَضِيعِ فَجَعَلْنَا التَّحْمِيمَ وَالْجَلْدَ مَكَانَ الرَّجْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَوَّلُ مَنْ أَحْيَا أَمْرَكَ إِذْ أَمَاتُوهُ فَأَمَرَ بِهِ فَرُجِمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَا أَيُّهَا الرَّسُولُ لَا يَحْزُنْكَ الَّذِينَ يُسَارِعُونَ فِي الْكُفْرِ }إِلَى قَوْلِهِ{ إِنْ أُوتِيتُمْ هَذَا فَخُذُوهُ }يَقُولُ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ أَمَرَكُمْ بِالتَّحْمِيمِ وَالْجَلْدِ فَخُذُوهُ وَإِنْ أَفْتَاكُمْ بِالرَّجْمِ فَاحْذَرُوا فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الظَّالِمُونَ }{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْفَاسِقُونَ }فِي الْكُفَّارِ كُلُّهَاحَدَّثَنَا ابْنُ نُمَيْرٍ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَى قَوْلِهِ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ وَلَمْ يَذْكُرْ مَا بَعْدَهُ مِنْ نُزُولِ الْآيَةِ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] keduanya dari [Abu Mu'awiyah], [Yahya] berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Al Barra` bin 'Azib] dia berkata, \"Suatu ketika seorang Yahudi yang dicat hitam dan didera lewat di hadapan Nabi shallallahu 'alaihi wasallam, kemudian beliau memanggil mereka seraya bersabda: \"Beginikah hukuman zina yang kalian dapati dalam kitab Taurat kalian?\" mereka menjawab, \"Ya benar.\" Lalu beliau memanggil seorang laki-laki yang tergolong dari ulama mereka, beliau bertanya: \"Aku mengharap kamu mau bersumpah dengan nama Allah yang telah menurunkan kitab Taurat kepada Musa, betulkah begini caranya hukuman zina yang kalian dapati dalam kitab tauratmu?\" dia menjawab, \"Tidak, seandainya anda tidak menyumpahku dengan nama Allah, aku tidak akan mengatakan yang sebenarnya kepada anda. Dan yang kami ketahui dalam kitab Taurat, hukumannya adalah rajam, akan tetapi biasanya hukuman itu tidak berlaku bagi pembesar-pembesar kami, jika yang tertangkap itu dari pembesar, maka kami biarkan begitu saja, akan tetapi jika yang tertangkap rakyat kecil maka kami tegakkan hukum sesuai Taurat. Akhirnya kami bermusyawarah, membicarakan hukum yang dapat kami tegakkan bagi pembesar dan rakyat biasa. Lalu kami putuskan untuk membuat hitam tubuh dan mendera pelaku zina sebagai pengganti hukum rajam.\" Setelah laki-laki itu selesai bicara, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sesungguhnya akulah orang yang pertama-tama menghidupkan kembali sunnah-Mu setelah mereka hapus perintah tersebut.\" Setelah itu, beliau memerintahkan supaya Yahudi yang berzina itu dihukum rajam, lalu Allah 'azza wajalla menurunkan ayat: '(Wahai rasul, janganlah kamu merasa sedih, karena orang-orang yang bersegera menuju kekafiran -hingga firman-Nya- Jika diberikan ini kepadamu, maka terimalah) ' (Qs. Al Maidah: 41). Orang-orang Yahudi berkata, \"Datanglah kalian kepada Muhammad shallallahu 'alaihi wasallam, jika beliau memutuskan hukuman kepadamu dengan menghitamkan tubuh dan didera, maka terimalah, namun jika dia berfatwa kepadamu dengan hukuman rajam, maka waspadalah. Maka Allah Ta'ala menurunkan ayat: '(Barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang kafir. Dan barangsiapa tidak berhukum dengan sesuatu yang telah diturunkan Allah, maka mereka itu adalah orang-orang yang Zhalim. Dan barangsiapa tidak berhukum dengan sesuatu yang telah di turunkan Allah, maka mereka itu adalah orang-orang yang fasik' (Qs. Al Maidah: 44- 47). Hal ini juga berlaku kepada orang-orang kafir semuanya.\" Telah menceritakan kepada kami [Ibnu Numair] dan [Abu Sa'id Al Asyaj] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dengan isnad seperti ini sampai kepada perkataannya, \"Lalu Nabi shallallahu 'alaihi wasallam memerintahkan untuk merajmanya, akhirnya dia pun dirajam.\" Dan tidak menyebutkan sesuatu setelahnya seperti turunnya ayat.\""},{"p":"Muslim","n":3413,"ar":"حَدَّثَنِي أَبُو الرَّبِيعِ سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ سَاقِيَ الْقَوْمِ يَوْمَ حُرِّمَتْ الْخَمْرُ فِي بَيْتِ أَبِي طَلْحَةَ وَمَا شَرَابُهُمْ إِلَّا الْفَضِيخُ الْبُسْرُ وَالتَّمْرُ فَإِذَا مُنَادٍ يُنَادِي فَقَالَ اخْرُجْ فَانْظُرْ فَخَرَجْتُ فَإِذَا مُنَادٍ يُنَادِي أَلَا إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ قَالَ فَجَرَتْ فِي سِكَكِ الْمَدِينَةِ فَقَالَ لِي أَبُو طَلْحَةَ اخْرُجْ فَاهْرِقْهَا فَهَرَقْتُهَا فَقَالُوا أَوْ قَالَ بَعْضُهُمْ قُتِلَ فُلَانٌ قُتِلَ فُلَانٌ وَهِيَ فِي بُطُونِهِمْ قَالَ فَلَا أَدْرِي هُوَ مِنْ حَدِيثِ أَنَسٍ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا إِذَا مَا اتَّقَوْا وَآمَنُوا وَعَمِلُوا الصَّالِحَاتِ }","trj":"Telah menceritakan kepadaku [Abu Ar Rabi' Sulaiman bin Daud Al 'Ataki] telah menceritakan kepada kami [Hammad] -yaitu Ibnu Zaid- telah mengabarkan kepada kami [Tsabit] dari [Anas bin Malik] dia berkata, \"Saya pernah menuangkan khamer kepada sekelompok kaum di rumah Abu Thalhah ketika khamer diharamkan, dan saat itu mereka tidak minum kecuali dari Fadlih (minuman keras yang terbuat dari perasan kurma), kurma muda dan kurma masak. Tiba-tiba ada seseorang yang berseru, lantas Abu Thalhah berkata, \"Keluarlah dan lihatlah apa yang terjadi.\" Ternyata seseorang berseru, katanya, \"Tidakkah khamer telah diharamkan.\" Anas berkata, \"Kemudian berita itu tersebar ke seluruh Kota Madinah, lantas Abu Thalhah berkata kepadaku, \"Keluar dan baunglah.\" Maka saya langsung menumpahkannya. Saat itu orang-orang berkata, atau sebagian dari mereka berkata, \"Seseorang telah meninggal, sedangkan khamer tersebut masih dalam perut mereka.\" -Tsabit berkata; \"Namun saya tidak mengetahui apakah itu termasuk dari hadits Anas- Maka Allah Azza Wa Jalla berfirman: '(Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan shalih karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa dan beriman serta beramal shalih …) ' (? Qs. Al Maidah: 93)."},{"p":"Muslim","n":4159,"ar":"حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ وَسَهْلُ بْنُ عُثْمَانَ وَعَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ الْحَضْرَمِيُّ وَسُوَيْدُ بْنُ سَعِيدٍ وَالْوَلِيدُ بْنُ شُجَاعٍ قَالَ سَهْلٌ وَمِنْجَابٌ أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا إِذَا مَا اتَّقَوْا وَآمَنُوا }إِلَى آخِرِ الْآيَةِ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لِي أَنْتَ مِنْهُمْ","trj":"Telah menceritakan kepada kami [Minjab bin Al Harits At Tamimi] dan [Sahl bin 'Utsman] dan ['Abdullah bin 'Amir bin Zurarah Al Hadhrami] dan [Suwaid bin Sa'id] serta [Walid bin Syuja']. Berkata; [Sahl] dan [Minjab]; Telah mengabarkan kepada kami. Sedangkan yang lainnya berkata; Telah menceritakan kepada kami ['Ali bin Mushir] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] dia berkata; \"ketika turun ayat; \"Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang saleh karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman, dan mengerjakan amalan-amalan yang saleh, Kemudian mereka tetap bertakwa dan beriman…\" hingga akhir ayat (QS. ALmaidah 93), Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: 'Kamu termasuk dari golongan mereka.'"},{"p":"Nasa'i","n":4436,"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ أَخْبَرَنِي دَاوُدُ بْنُ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ الْآيَاتِ الَّتِي فِي الْمَائِدَةِ الَّتِي قَالَهَا اللَّهُ عَزَّ وَجَلَّ{ فَاحْكُمْ بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ إِلَى الْمُقْسِطِينَ }إِنَّمَا نَزَلَتْ فِي الدِّيَةِ بَيْنَ النَّضِيرِ وَبَيْنَ قُرَيْظَةَ وَذَلِكَ أَنَّ قَتْلَى النَّضِيرِ كَانَ لَهُمْ شَرَفٌ يُودَوْنَ الدِّيَةَ كَامِلَةً وَأَنَّ بَنِي قُرَيْظَةَ كَانُوا يُودَوْنَ نِصْفَ الدِّيَةِ فَتَحَاكَمُوا فِي ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ ذَلِكَ فِيهِمْ فَحَمَلَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْحَقِّ فِي ذَلِكَ فَجَعَلَ الدِّيَةَ سَوَاءً","trj":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd] telah menceritakan kepada kami [pamanku] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq], telah mengabarkan kepadaku [Daud bin Al Hushain] dari [Ikrimah] dari [Ibnu Abbas] bahwa ayat-ayat yang turun dalam Surat Al Maidah yang Allah 'azza wajalla firmankan yaitu: (Maka putuskanlah (perkara itu) di antara mereka, atau berpalinglah dari mereka) hingga firmanNya: (orang-orang yang adil) ayat tersebut turun mengenai diyat antara Bani Nadhir dan Bani Quraizhah yang demikian itu yaitu bahwa orang-orang yang dibunuh dari Bani Nazhir memiliki kemuliaan, mereka dibayar diyat dengan sempurna, sedang Bani Quraizhah mereka dibayar setengah diyat. Kemudian mereka berhukum kepada Rasulullah shallallahu 'alaihi wasallam, maka Allah 'azza wajalla menurunkan ayat tersebut mengenai mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam membawa mereka di atas kebenaran dalam hal tersebut dan menjadikan diyat sama. "},{"p":"Nasa'i","n":5180,"ar":"أَخْبَرَنَا أَبُو بَكْرٍ أَحْمَدُ بْنُ مُحَمَّدِ بْنِ إِسْحَقَ السُّنِّيُّ قِرَاءَةً عَلَيْهِ فِي بَيْتِهِ قَالَ أَنْبَأَنَا الْإِمَامُ أَبُو عَبْدِ الرَّحْمَنِ أَحْمَدُ بْنُ شُعَيْبٍ النَّسَائِيُّ رَحِمَهُ اللَّهُ تَعَالَى قَالَ أَنْبَأَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَكَانَ مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقَامَ الصَّلَاةَ نَادَى لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْمَائِدَةِ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَلَمَّا بَلَغَ فَهَلْ أَنْتُمْ مُنْتَهُونَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ انْتَهَيْنَا انْتَهَيْنَا","trj":"Telah mengabarkan kepada kami Abu Bakr Ahmad bin Muhammad bin Ishaq As Sunni -dengan membaca dihadapannya di rumah miliknya- ia berkata; telah memberitakan kepada kami Imam Abu Abdurrahman Ahmad bin Syu'aib An Nasa`i rahimahullahu Ta'ala, ia berkata; telah memberitakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Ubaidullah bin Musa] ia berkata; telah memberitakan kepada kami [Isra'il] dari [Abu Ishaq] dari [Abu Maisarah] dari [Umar radliallahu 'anhu] ia berkata; \"Ketika turun ayat yang mengharamkan khamer, Umar berdoa; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat Al Baqarah. Lalu Umar dipanggil dan ayat tersebut dibacakan kepadanya. Umar lalu berdoa lagi; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat An Nisa`: 'Hai orang-orang yang beriman, janganlah kamu shalat sedang kamu dalam keadaan mabuk…'. Jika waktu shalat tiba, penyeru Rasulullah shallallahu 'alaihi wasallam biasa menyerukan 'Janganlah kamu shalat, sedangkan kami dalam keadaan mabuk'. Lalu Umar dipanggil dan ayat tersebut dibacakan kepadanya. Setelah itu Umar berdoa lagi; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat Al Maidah. Umar pun dipanggil dan ayat tersebut dibacakan kepadanya, ketika sampai, Maka berhentilah kamu (dari mengerjakan pekerjaan itu, Lantas Umar radliallahu 'anhu berkata; \"Kami berhenti, kami berhenti!.\""},{"p":"Tirmidzi","n":86,"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ قَالَبَالَ جَرِيرُ بْنُ عَبْدِ اللَّهِ ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقِيلَ لَهُ أَتَفْعَلُ هَذَا قَالَ وَمَا يَمْنَعُنِي وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُقَالَ إِبْرَاهِيمُ وَكَانَ يُعْجِبُهُمْ حَدِيثُ جَرِيرٍ لِأَنَّ إِسْلَامَهُ كَانَ بَعْدَ نُزُولِ الْمَائِدَةِ هَذَا قَوْلُ إِبْرَاهِيمَ يَعْنِي كَانَ يُعْجِبُهُمْ قَالَ وَفِي الْبَاب عَنْ عُمَرَ وَعَلِيٍّ وَحُذَيْفَةَ وَالْمُغِيرَةِ وَبِلَالٍ وَسَعْدٍ وَأَبِي أَيُّوبَ وَسَلْمَانَ وَبُرَيْدَةَ وَعَمْرِو بْنِ أُمَيَّةَ وَأَنَسٍ وَسَهْلِ بْنِ سَعْدٍ وَيَعْلَى بْنِ مُرَّةَ وَعُبَادَةَ بْنِ الصَّامِتِ وَأُسَامَةَ بْنِ شَرِيكٍ وَأَبِي أُمَامَةِ وَجَابِرٍ وَأُسَامَةَ بْنِ زَيْدٍ وَابْنِ عُبَادَةَ وَيُقَالُ ابْنُ عِمَارَةَ وَأُبَيُّ بْنُ عِمَارَةَ قَالَ أَبُو عِيسَى وَحَدِيثُ جَرِيرٍ حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Ibrahim] dari [Hammam Ibnul Harits] ia berkata; [Jarir bin Abdullah] buang air kecil, lalu berwudlu dan mengusap keduan khufnya. Lalu dikatakan kepadanya, \"kenapa engkau melakukan ini?\" ia berkata; \"Apa yang menghalangiku untuk melakukan ini? aku pernah melihat Rasulullah shallallahu 'alaihi wasallam melakukannya.\" Ibrahim berkata; \"Hadits Jarir ini membuat orang-orang merasa ta'ajub, karena Jarir masuk Islam setelah turunnya surat Al Maidah.\" Ini adalah perkataan Ibrahim, yakni perkataan, \"Hadits ini membuat orang-orang merasa ta'ajub.\" Ia berkata; \"Dalam bab ini juga ada riwayat dari Umar, Ali, Hudzaifah, Al Mughirah, Bilal, Sa'd, Abu Ayyub, Salman, Buraidah, 'Amru bin Umayyah, Anas, Sahl bin Sa'd, Ya'la bin Murrah, Ubadah Ibnu Shamid, Usamah bin Syarik, Abu Umamah, Jabir, Usamah bin Zaid dan Ibnu Ubadah, ada juga yang mengatakan, Ibnu Umarah dan Ubai bin Imarah.\" Abu Isa berkata; \"Hadits Jarir ini derajatnya adalah hasan shahih.\""},{"p":"Tirmidzi","n":87,"ar":"وَيُرْوَى عَنْ شَهْرِ بْنِ حَوْشَبٍ قَالَرَأَيْتُ جَرِيرَ بْنَ عَبْدِ اللَّهِ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقُلْتُ لَهُ فِي ذَلِكَ فَقَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقُلْتُ لَهُ أَقَبْلَ الْمَائِدَةِ أَمْ بَعْدَ الْمَائِدَةِ فَقَالَ مَا أَسْلَمْتُ إِلَّا بَعْدَ الْمَائِدَةِحَدَّثَنَا بِذَلِكَ قُتَيْبَةُ حَدَّثَنَا خَالِدُ بْنُ زِيَادٍ التِّرْمِذِيُّ عَنْ مُقَاتِلِ بْنِ حَيَّانَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ جَرِيرٍ قَالَ وَرَوَى بَقِيَّةُ عَنْ إِبْرَاهِيمَ بْنِ أَدْهَمَ عَنْ مُقَاتِلِ بْنِ حَيَّانَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ جَرِيرٍ وَهَذَا حَدِيثٌ مُفَسَّرٌ لِأَنَّ بَعْضَ مَنْ أَنْكَرَ الْمَسْحَ عَلَى الْخُفَّيْنِ تَأَوَّلَ أَنَّ مَسْحَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْخُفَّيْنِ كَانَ قَبْلَ نُزُولِ الْمَائِدَةِ وَذَكَرَ جَرِيرٌ فِي حَدِيثِهِ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَى الْخُفَّيْنِ بَعْدَ نُزُولِ الْمَائِدَةِ","trj":"Diriwayatkan dari [Syahr bin Hausyab], ia berkata; \"Aku melihat [Jarir bin Abdullah] berwudlu, lalu ia mengusap sepasang khufnya. Maka aku pun bertanya kepadanya tentang hal itu, ia menjawab, \"Aku melihat Nabi shallallahu 'alaihi wasallam berwudlu lalu mengusap kedua khufnya.\" Maka aku pun bertanya kepadanya, \"Apakah itu sebelum turunnya surat Al Maidah atau sesudahnya?\" Ia menjawab, \"Aku belum masuk Islam kecuali setelah turunnya surat Al Maidah.\" [Qutaibah] menceritakan hal itu kepada kami, ia berkata; \"Telah menceritakan kepada kami [Khalid bin Ziyad At Tirmidzi], dari [Muqatil bin Hayyan], dari [Syahr bin Hausyab], dari [Jarir].\" Perawi berkata; \" [Baqiyyah] meriwayatkan dari [Ibrahim bin Adham], dari [Muqatil bin Hayyan], dari [Syahr bin Hausyab], dari [Jarir]. Dan ini adalah hadits yang telah jelas, karena sebagian orang yang mengingkari tentang mengusap khuf mentakwilkan bahwa Nabi shallallahu 'alaihi wasallam mengusap khuf sebelum turunnya surat Al Maidah. Dan Jarir menyebutkan dalam haditsnya bahwa ia melihat Nabi shallallahu 'alaihi wasallam mengusap khufnya setelah turunnya surat Al Maidah.\""},{"p":"Tirmidzi","n":514,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاسِ فَأَطَالَ الْقِرَاءَةَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ رَأْسَهُ فَأَطَالَ الْقِرَاءَةَ هِيَ دُونَ الْأُولَى ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الْأَوَّلِ ثُمَّ رَفَعَ رَأْسَهُ فَسَجَدَ ثُمَّ فَعَلَ مِثْلَ ذَلِكَ فِي الرَّكْعَةِ الثَّانِيَةِقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَبِهَذَا الْحَدِيثِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ يَرَوْنَ صَلَاةَ الْكُسُوفِ أَرْبَعَ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍ قَالَ الشَّافِعِيُّ يَقْرَأُ فِي الرَّكْعَةِ الْأُولَى بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ سُورَةِ الْبَقَرَةِ سِرًّا إِنْ كَانَ بِالنَّهَارِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ بِتَكْبِيرٍ وَثَبَتَ قَائِمًا كَمَا هُوَ وَقَرَأَ أَيْضًا بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ آلِ عِمْرَانَ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ سَجَدَ سَجْدَتَيْنِ تَامَّتَيْنِ وَيُقِيمُ فِي كُلِّ سَجْدَةٍ نَحْوًا مِمَّا أَقَامَ فِي رُكُوعِهِ ثُمَّ قَامَ فَقَرَأَ بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ سُورَةِ النِّسَاءِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ بِتَكْبِيرٍ وَثَبَتَ قَائِمًا ثُمَّ قَرَأَ نَحْوًا مِنْ سُورَةِ الْمَائِدَةِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ تَشَهَّدَ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] bahwa dia berkata, telah terjadi gerhana pada masa Rasulullah shallallahu 'alaihi wasallam, kemudian Rasulullah shallallahu 'alaihi wasallam shalat bersama manusia dengan memanjangkan bacaan shalat, beliau kemudian ruku' dan memanjangkan ruku'nya, lalu beliau mengangkat kepala dan memanjangkan bacaan shalat, namun tidak seperti (lebih singkat) dari yang pertama. Kemudian beliau ruku' dan memanjangkan ruku'nya namun tidak seperti yang pertama. Kemudian beliau mengangkat kepala lalu sujud, kemudian beliau melakukan seperti itu diraka'at kedua. Abu Isa berkata, ini adalah hadits hasan shahih, dengan hadits ini pula Syafi'i, Ahamad dan Ishaq berpendapat bahwa shalat gerhana itu empat kali ruku' dan empat kali sujud. Syafi'i berkata, pada raka'at pertama membaca surat Al Fatehah dan surat yang sepadan dengan surat Al Baqarah. Beliau membaca dengan suara pelan jika di siang hari (gerhana matahari), kemudian ruku' yang panjang seperti membaca bacaan, kemudian mengangkat kepala dengan mengucapkan takbir dan berdiri sebagaimana mestinya, kemudian membaca surat Al Fatihah lagi dan membaca surat yang sepadan dengan surat Ali Imran, lalu memanjangkan ruku'nya seperti ketika membaca bacaan. Kemudian mengangat kepala, lantas membaca sami'allahu liman hamidah, kemudian sujud dua kali dengan sempurna. Setiap sujud beliau berhenti sebagaimana berhenti ketika ruku', kemudian berdiri sambil membaca Al Fatehah dan surat yang sepadan dengan surat An Nisaa', kemudian memanjangan ruku' seperti membaca bacaan. Kemudian mengangkat kepala dengan mengucapkan takbir, lantas berdiri dengan membaca bacaan yang sepadan dengan surat Al Maidah, kemudian memanjangkan ruku'nya seperti ketika membaca bacaan. Kemudian mengangkat kepala dan membaca sami'allahu liman hamidah, kemudian sujud dua kali lalu membaca tahiyyat dan salam."},{"p":"Tirmidzi","n":556,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا خَالِدُ بْنُ زِيَادٍ عَنْ مُقَاتِلِ بْنِ حَيَّانَ عَنْ شَهْرِ بْنِ حَوْشَبٍ قَالَرَأَيْتُ جَرِيرَ بْنَ عَبْدِ اللَّهِ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ قَالَ فَقُلْتُ لَهُ فِي ذَلِكَ فَقَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَمَسَحَ عَلَى خُفَّيْهِ فَقُلْتُ لَهُ أَقَبْلَ الْمَائِدَةِ أَمْ بَعْدَ الْمَائِدَةِ قَالَ مَا أَسْلَمْتُ إِلَّا بَعْدَ الْمَائِدَةِحَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ قَالَ حَدَّثَنَا نُعَيْمُ بْنُ مَيْسَرَةَ النَّحْوِيُّ عَنْ خَالِدِ بْنِ زِيَادٍ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِثْلَ هَذَا إِلَّا مِنْ حَدِيثِ مُقَاتِلِ بْنِ حَيَّانَ عَنْ شَهْرِ بْنِ حَوْشَبٍ","trj":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Khalid bin Ziyad] dari [Muqatil bin Hayyan] dari [Syahr bin Hausyab] dia berkata, saya melihat [Jarir bin Abdullah] berwudlu' lalu dia mengusap kedua sandalnya, dia (Syahr radliallahu 'anhu) berkata, saya bertanya kepadanya mengenai hal itu, dia menjawab, saya telah melihat Nabi Shallallaahu 'alaihi wasallam berwudlu lalu mengusap kedua sandalnya, saya bertanya kepadanya, sebelum turun surat Al Maidah ataukah sesudahnya? Dia menjawab, tidaklah saya masuk Islam kecuali setelah turunnya surat Al Maidah. Telah menceritakan kepada kami [Muhammad bin Humaid Al Razi] dia berkata, telah menceritakan kepada kami [Nu'aim bin Maisarah Al Nahwi] dari [Khalid bin Ziyad] seperti hadits diatas. Abu 'Isa berkata, ini adalah hadits gharib, kami tidak mengetahui yang semisal dengan ini kecuali dari haditsnya Muqatil bin Hayyan dari Syahr bin Hausyab."},{"p":"Tirmidzi","n":1184,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ مُجَالِدٍ عَنْ أَبِي الْوَدَّاكِ عَنْ أَبِي سَعِيدٍ قَالَكَانَ عِنْدَنَا خَمْرٌ لِيَتِيمٍ فَلَمَّا نَزَلَتْ الْمَائِدَةُ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُ وَقُلْتُ إِنَّهُ لِيَتِيمٍ فَقَالَ أَهْرِيقُوهُقَالَ وَفِي الْبَاب عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي سَعِيدٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوُ هَذَا و قَالَ بِهَذَا بَعْضُ أَهْلِ الْعِلْمِ وَكَرِهُوا أَنْ تُتَّخَذَ الْخَمْرُ خَلَّا وَإِنَّمَا كُرِهَ مِنْ ذَلِكَ وَاللَّهُ أَعْلَمُ أَنْ يَكُونَ الْمُسْلِمُ فِي بَيْتِهِ خَمْرٌ حَتَّى يَصِيرَ خَلَّا وَرَخَّصَ بَعْضُهُمْ فِي خَلِّ الْخَمْرِ إِذَا وُجِدَ قَدْ صَارَ خَلًّا أَبُو الْوَدَّاكِ اسْمُهُ جَبْرُ بْنُ نَوْفٍ","trj":"telah menceritakan kepada kami [Ali bin Khasyram] telah mengabarkan kepada kami [Isa bin Yunus] dari [Mujalid] dari [Abu Al Waddak] dari [Abu Sa'id] ia berkata; Kami pernah memiliki khamr milik anak yatim, ketika turun surat Al Ma`idah, aku menanyakannya Rasulullah Shlallahu 'Alaihi Wasallam, aku katakan; Bahwa itu milik anak yatim. Beliau pun bersabda: \"Tumpahkanlah ia.\" Ia mengatakan; Dalam hal ini ada hadits serupa dari Anas bin Malik. Abu Isa berkata; Hadits Abu Sa'id adalah hadits hasan shahih dan telah diriwayatkan dari jalur yang banyak dari Nabi Shlallahu 'Alaihi Wasallam seperti ini. Sebagian ulama berpendapat dengan hadits ini, mereka memakruhkan jika khamr dijadikan sebagai cuka, dimakruhkannya hal tersebut hanya karena (dan Allah maha mengetahui) bagaimana mungkin seorang muslim membiarkan khamr ada dirumahnya hingga berubah menjadi cuka. Namun sebagian mereka membolehkan cuka dari khamr jika seseorang mendapatinya telah berubah menjadi cuka. Abul Waddak nama aslinya adalah Jabr bin Nauf."},{"p":"Tirmidzi","n":1336,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ عَنْ شُعْبَةَ عَنْ قَتَادَةَ قَال سَمِعْتُ زُرَارَةَ بْنَ أَوْفَى يُحَدِّثُ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا عَضَّ يَدَ رَجُلٍ فَنَزَعَ يَدَهُ فَوَقَعَتْ ثَنِيَّتَاهُ فَاخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَعَضُّ أَحَدُكُمْ أَخَاهُ كَمَا يَعَضُّ الْفَحْلُ لَا دِيَةَ لَكَ فَأَنْزَلَ اللَّهُ{ وَالْجُرُوحَ قِصَاصٌ }قَالَ وَفِي الْبَاب عَنْ يَعْلَى بْنِ أُمَيَّةَ وَسَلَمَةَ بْنِ أُمَيَّةَ وَهُمَا أَخَوَانِ قَالَ أَبُو عِيسَى حَدِيثُ عِمْرَانَ بْنِ حُصَيْنٍ حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khasyram], telah memberitakan kepada kami [Isa bin Yunus] dari [Syu'bah] dari [Qatadah] ia berkata; Aku mendengar [Zurarah bin Aufa] menceritakan dari [Imran bin Hushain] bahwa ada seseorang yang menggigit tangan orang lain, maka orang yang digigit tangannya itu menarik kedua tangannya sehingga tanggallah kedua gigi depan si penggigit tersebut. Maka keduanya saling mengadu kepada Nabi shallallahu 'alaihi wasallam, dan beliau menjawab, \"Salah seorang dari kalian menggigit saudaranya, seperti halnya unta yang menggigit (temannya), maka tidak ada diyat bagimu.\" Kemudian turunlah ayat, \"WAL JURUHA QISHAH\" (dan luka-luka pun ada qishasnya) (QS. Al Maidah: 45) Ia mengatakan; Dalam hal ini ada hadits serupa dari Ya'la bin Umayyah dan Salamah bin Umayyah keduanya bersaudara. Abu 'Isa berkata; Hadits Imran bin Hushain adalah hadits hasan shahih."},{"p":"Tirmidzi","n":2842,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينُ الرَّحْمَنِ مَلْأَى سَحَّاءُ لَا يُغِيضُهَا اللَّيْلُ وَالنَّهَارُ قَالَ أَرَأَيْتُمْ مَا أَنْفَقَ مُنْذُ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ فَإِنَّهُ لَمْ يَغِضْ مَا فِي يَمِينِهِ وَعَرْشُهُ عَلَى الْمَاءِ وَبِيَدِهِ الْأُخْرَى الْمِيزَانُ يَرْفَعُ وَيَخْفِضُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَتَفْسِيرُ هَذِهِ الْآيَةِ{ وَقَالَتْ الْيَهُودُ يَدُ اللَّهِ مَغْلُولَةٌ غُلَّتْ أَيْدِيهِمْ وَلُعِنُوا بِمَا قَالُوا بَلْ يَدَاهُ مَبْسُوطَتَانِ يُنْفِقُ كَيْفَ يَشَاءُ }وَهَذَا حَدِيثٌ قَدْ رَوَتْهُ الْأَئِمَّةُ نُؤْمِنُ بِهِ كَمَا جَاءَ مِنْ غَيْرِ أَنْ يُفَسَّرَ أَوْ يُتَوَهَّمَ هَكَذَا قَالَ غَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ مِنْهِمْ سُفْيَانُ الثَّوْرِيُّ وَمَالِكُ بْنُ أَنَسٍ وَابْنُ عُيَيْنَةَ وَابْنُ الْمُبَارَكِ أَنَّهُ تُرْوَى هَذِهِ الْأَشْيَاءُ وَيُؤْمَنُ بِهَا وَلَا يُقَالُ كَيْفَ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] ia berkata; Rasulullah Shallallahu 'alahi wasallam bersabda: \"Tangan kanan Ar Rahman kaya dengan rizki dan berkah yang tak akan pernah berkurang karena siang maupun malam. Tahukah kalian apa saja yang telah didinfakanNya sejak pertama kali langit dan bumi ini diciptakan? sesungguhnya semua yang berada di tangan kananNya tidak berkurang, 'Arsy Nya diatas air dan tangan lainnya terdapat timbangan (rizki) yang sesekali naik dan terkadang turun.\" Abu Isa mengatakan; Hadit ini Hadits ini hasan shahih, dan tafsir dari ayat Orang-orang Yahudi berkata; 'Tangan Allah terbelenggu, sebenarnya tangan merekalah yang dibelenggu dan merekalah yang dila'nat disebabkan apa yang telah mereka katakan itu. (Tidak demikian), tetapi kedua-dua tangan Allah terbuka; Dia menafkahkan sebagaimana Dia kehendaki QS Al Ma`idah: 64. Hadits ini diriwayatkan oleh para imam, kami mengimaninya apa adanya, tanpa ditafsirkan atau diperkirakan. Demikianlah yang di riwayatkan dari beberapa imam seperti Sufyan Ats Tsauri, Malik bin Anas, Ibnu 'Uyainah dan Ibnu Al Mubarak, mereka berkata; \"Semua itu diriwayatkan dan di imani tanpa ditanyakan bagaimananya.\""},{"p":"Tirmidzi","n":2843,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا وَقَعَتْ بَنُو إِسْرَائِيلَ فِي الْمَعَاصِي نَهَتْهُمْ عُلَمَاؤُهُمْ فَلَمْ يَنْتَهُوا فَجَالَسُوهُمْ فِي مَجَالِسِهِمْ وَوَاكَلُوهُمْ وَشَارَبُوهُمْ فَضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ وَلَعَنَهُمْ{ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ ذَلِكَ بِمَا عَصَوْا وَكَانُوا يَعْتَدُونَ }قَالَ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ مُتَّكِئًا فَقَالَ لَا وَالَّذِي نَفْسِي بِيَدِهِ حَتَّى تَأْطُرُوهُمْ عَلَى الْحَقِّ أَطْرًاقَالَ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ قَالَ يَزِيدُ وَكَانَ سُفْيَانُ الثَّوْرِيُّ لَا يَقُولُ فِيهِ عَنْ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ مُحَمَّدِ بْنِ مُسْلِمِ بْنِ أَبِي الْوَضَّاحِ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَبَعْضُهُمْ يَقُولُ عَنْ أَبِي عُبَيْدَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syarik] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah bin Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saat Bani Isra`il bergelimang dengan kemaksiatan-kemaksiatan, maka para ulama mereka melarang mereka, namun mereka tidak juga jera. Lalu para ulama mereka menemani mereka di majlis-majlis mereka, turut makan dan minum bersama mereka, lalu Allah mencampur adukkan hati mereka satu sama lain dan melaknat mereka melalui lisan Dawud dan Isa putra Maryam, itu karena mereka durhaka dan melanggar QS Al Ma`idah; 78. Ibnu Mas'ud berkata; Lalu Rasulullah shallallahu 'alaihi wasallam duduk bersandar kemudian bersabda: \"Demi Dzat yang jiwaku berada ditanganNya, hingga mereka benar-benar membelot di atas kebenaran.\" Abdullah bin Abdurrahman berkata; Yazid berkata; Sufyan Ats Tsauri tidak mengatakan; \"Dari Abdullah.\" Abu Isa berkata; Hadits ini hasan gharib. Hadits ini juga diriwayatkan dari [Muhammad bin Muslim bin Abu Al Wadlah] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas. Sebagian dari mereka berkata; Dari 'Ubaidah dari Nabi shallallahu 'alaihi wasallam secara mursal."},{"p":"Tirmidzi","n":2844,"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَنِي إِسْرَائِيلَ لَمَّا وَقَعَ فِيهِمْ النَّقْصُ كَانَ الرَّجُلُ فِيهِمْ يَرَى أَخَاهُ عَلَى الذَّنْبِ فَيَنْهَاهُ عَنْهُ فَإِذَا كَانَ الْغَدُ لَمْ يَمْنَعْهُ مَا رَأَى مِنْهُ أَنْ يَكُونَ أَكِيلَهُ وَشَرِيبَهُ وَخَلِيطَهُ فَضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ وَنَزَلَ فِيهِمْ الْقُرْآنُ فَقَالَ{ لُعِنَ الَّذِينَ كَفَرُوا مِنْ بَنِي إِسْرَائِيلَ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ ذَلِكَ بِمَا عَصَوْا وَكَانُوا يَعْتَدُونَ فَقَرَأَ حَتَّى بَلَغَ وَلَوْ كَانُوا يُؤْمِنُونَ بِاللَّهِ وَالنَّبِيِّ وَمَا أُنْزِلَ إِلَيْهِ مَا اتَّخَذُوهُمْ أَوْلِيَاءَ وَلَكِنَّ كَثِيرًا مِنْهُمْ فَاسِقُونَ }قَالَ وَكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا فَجَلَسَ فَقَالَ لَا حَتَّى تَأْخُذُوا عَلَى يَدِ الظَّالِمِ فَتَأْطُرُوهُ عَلَى الْحَقِّ أَطْرًاحَدَّثَنَا بُنْدَارٌ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ وَأَمْلَاهُ عَلَيَّ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمِ بْنِ أَبِي الْوَضَّاحِ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","trj":"Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Ali bin Badzimah] dari [Abu Ubaidah] ia berkata; Rasulullah Shallallahu 'alahi wasallam bersabda: \"Ketika Bani Israil ditimpa kekurangan, salah seorang di antara mereka melihat saudaranya melakukan dosa, lalu ia mencegahnya, akan tetapi keesokan harinya ia tidak melarang dari apa yang telah dilihatnya (kemarin), bahkan ia menemaninya makan, minum, dan bergaul. Lalu Allah mencampur adukkan hati mereka satu sama lain, dan Allah menurunkan ayat tentang mereka: Telah dila'nati orang-orang kafir dari Bani Israil dengan lisan Daud dan 'Isa putra Maryam. Yang demikian itu, disebabkan mereka durhaka dan selalu melampaui batas Beliau membaca hingga sampai firmanNya: Sekiranya mereka beriman kepada Allah, kepada nabi (Musa) dan kepada apa yang diturunkan kepadanya (Nabi), niscaya mereka tidak akan mengambil orang-orang musyrikin itu menjadi penolong-penolong, tapi kebanyakan dari mereka adalah orang-orang yang fasik. QS Al Ma`idah; 78-81. Rasulullah Shallallahu 'alahi wasallam yang tadinya bersandar, kemudian beliau duduk dan bersabda: \"Tidak, (kalian tidak akan luput dari apa yang mereka alami) sehingga kalian mangarahkan orang dzalim lalu kalian benar-benar membelokkannya di atas kebenaran.\" Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] dan ia mengimlakkannya kepadaku. Telah menceritakan kepada kami [Muhammad bin Muslim bin Abu Al Wadlah] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},{"p":"Tirmidzi","n":2845,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."},{"p":"Tirmidzi","n":2846,"ar":"حَدَّثَنَا بِذَلِكَ بُنْدَارٌ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ قَالَ الْبَرَاءُمَاتَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ يَشْرَبُونَ الْخَمْرَ فَلَمَّا نَزَلَ تَحْرِيمُهَا قَالَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَيْفَ بِأَصْحَابِنَا الَّذِينَ مَاتُوا وَهُمْ يَشْرَبُونَهَا فَنَزَلَتْ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Bundar] seperti itu, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata; [Al Barra`] berkata; \"Sebagian sahabat Nabi Shallallahu 'alahi wasallam meninggal dunia sedangkan mereka suka meminum khamr, ketika turun (ayat) yang mengharamkannya, sebagian sahabat bertanya; \"Bagaimana dengan sahabat-sahabat kami, mereka meninggal sementara mereka suka meminumnya (khamar)?\" Maka turunlah ayat Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang shalih karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman, dan mengerjakan amalan-amalan yang Shalih. QS Al Ma`idah: 93. Abu Isa mengatakan bahwa hadits ini hasan shahih."},{"p":"Tirmidzi","n":2847,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي رِزْمَةَ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالُوا يَا رَسُولَ اللَّهِ أَرَأَيْتَ الَّذِينَ مَاتُوا وَهُمْ يَشْرَبُونَ الْخَمْرَ لَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ فَنَزَلَتْ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا إِذَا مَا اتَّقَوْا وَآمَنُوا وَعَمِلُوا الصَّالِحَاتِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Abdul Aziz bin Abu Rizmah] dari [Isra`il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Para sahabat bertanya; \"Wahai Rasulullah, bagaimana menurut anda mengenai orang-orang yang telah meninggal, sementara mereka dulu meminum khamar saat pengharaman khamar belum turun?, \" Lalu turun ayat Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang shalih karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman, dan mengerjakan amalan-amalan yang Shalih QS Al Ma`idah: 93. Abu Isa berkata; Hadits ini hasan shahih."},{"p":"Tirmidzi","n":2851,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ قُلْ هُوَ الْقَادِرُ عَلَى أَنْ يَبْعَثَ عَلَيْكُمْ عَذَابًا مِنْ فَوْقِكُمْ أَوْ مِنْ تَحْتِ أَرْجُلِكُمْ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعُوذُ بِوَجْهِكَ فَلَمَّا نَزَلَتْ{ أَوْ يَلْبِسَكُمْ شِيَعًا وَيُذِيقَ بَعْضَكُمْ بَأْسَ بَعْضٍ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَاتَانِ أَهْوَنُ أَوْ هَاتَانِ أَيْسَرُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dia mendengar [Jabir bin Abdullah] ia berkata: \"Ketika turun ayat ini Katakanlah: 'Dialah yang berkuasa untuk mengirimkan azab kepadamu dari atas kamu atau dari bawah kakimu QS Al Ma`idah: 65, Rasulullah Shallallahu 'alahi wasallam berdoa: \"Ya Allah aku berlindung dengan wajah-Mu, \" akan tetapi ketika turun Atau dia mencampurkan kamu dalam golongan-golongan (yang saling bertentangan) dan merasakan kepada sebahagian kamu keganasan sebahagian yang lain QS Al An'aam: 65, beliau bersabda: \"Dua ayat ini lebih ringan atau dua ayat ini lebih mudah.\" Abu Isa mengatakan bahwa hadits ini hasan shahih."},{"p":"Tirmidzi","n":2852,"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ الْغَسَّانِيِّ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذِهِ الْآيَةِ{ قُلْ هُوَ الْقَادِرُ عَلَى أَنْ يَبْعَثَ عَلَيْكُمْ عَذَابًا مِنْ فَوْقِكُمْ أَوْ مِنْ تَحْتِ أَرْجُلِكُمْ }فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهَا كَائِنَةٌ وَلَمْ يَأْتِ تَأْوِيلُهَا بَعْدُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","trj":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Abu Bakr bin Abu Maryam Al Ghassani] dari [Rasyid bin Sa'd] dari [Sa'd bin Abu Waqqash] dari Nabi shallallahu 'alaihi wasallam berkenaan dengan ayat ini Katakanlah: 'Dialah yang berkuasa untuk mengirimkan azab kepadamu, dari atas kamu atau dari bawah kakimu QS Al Ma`idah: 65, beliau bersabda: \"Ingatlah, sesungguhnya itu akan terjadi, sementara penjelasannya belum tiba sama sekali.\" Abu Isa mengatakan bahwa hadits ini hasan gharib."},{"p":"Tirmidzi","n":2854,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ كُنْتُ مُتَّكِئًا عِنْدَ عَائِشَةَ فَقَالَتْيَا أَبَا عَائِشَةَ ثَلَاثٌ مَنْ تَكَلَّمَ بِوَاحِدَةٍ مِنْهُنَّ فَقَدْ أَعْظَمَ عَلَى اللَّهِ الْفِرْيَةَ مَنْ زَعَمَ أَنَّ مُحَمَّدًا رَأَى رَبَّهُ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَكُنْتُ مُتَّكِئًا فَجَلَسْتُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْظِرِينِي وَلَا تُعْجِلِينِي أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ وَلَقَدْ رَآهُ نَزْلَةً أُخْرَى }{ وَلَقَدْ رَآهُ بِالْأُفُقِ الْمُبِينِ }قَالَتْ أَنَا وَاللَّهِ أَوَّلُ مَنْ سَأَلَ عَنْ هَذَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا ذَاكَ جِبْرِيلُ مَا رَأَيْتُهُ فِي الصُّورَةِ الَّتِي خُلِقَ فِيهَا غَيْرَ هَاتَيْنِ الْمَرَّتَيْنِ رَأَيْتُهُ مُنْهَبِطًا مِنْ السَّمَاءِ سَادًّا عِظَمُ خَلْقِهِ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَمَنْ زَعَمَ أَنَّ مُحَمَّدًا كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ يَقُولُ اللَّهُ{ يَا أَيُّهَا الرَّسُولَ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }وَمَنْ زَعَمَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ أَعْظَمَ الْفِرْيَةَ عَلَى اللَّهِ وَاللَّهُ يَقُولُ{ قُلْ لَا يَعْلَمُ مَنْ فِي السَّمَوَاتِ وَالْأَرْضِ الْغَيْبَ إِلَّا اللَّهُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَسْرُوقُ بْنُ الْأَجْدَعِ يُكْنَى أَبَا عَائِشَةَ وَهُوَ مَسْرُوقُ بْنُ عَبْدِ الرَّحْمَنِ وَكَذَا كَانَ اسْمُهُ فِي الدِّيوَانِ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] ia berkata; \"Aku bersandar didekat 'Aisyah lalu ['Aisyah] berkata; \"Wahai Abu Aisyah, tiga hal yang barangsiapa mengucapkan salah satunya, berarti ia telah dusta besar atas nama Allah, yaitu; barangsiapa mengira Muhammad pernah melihat Rabbnya berarti ia berdusta atas nama Allah, sementara Allah berfirman Dia tidak dapat dicapai oleh penglihatan mata, sedang dia dapat melihat segala yang kelihatan; dan dialah yang Maha halus lagi Maha Mengetahui QS Al An`am: 103, Dan tidak mungkin bagi seorang pun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir QS Asy Syura: 51.\" Tadinya aku bersandar, lalu aku duduk, aku berkata; \"Wahai Ummul Mukminin, tunggulah aku, jangan tergesa-gesa, bukankah Allah Ta'ala berfirman Dan Sesungguhnya Muhammad telah melihat Jibril itu (dalam rupanya yang asli) pada waktu yang lain QS An Najm: 13 Dan Sesungguhnya Muhammad itu melihat Jibril di ufuk yang terang QS At Takwiir: 23. 'Aisyah berkata; \"Demi Allah, aku adalah orang pertama kali menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau menjawab: \"Sesungguhnya dia itu adalah Jibril, aku tidak pernah melihatnya dalam wujud (asli) ciptaannya kecuali pada kedua kali itu, aku melihatnya turun dari langit, besarnya wujud dia menutupi (jarak) antara langit dan bumi dan barangsiapa mengira Muhammad menyembunyikan sesuatu yang diturunkan Allah padanya, berarti dia telah dusta besar atas nama Allah. Allah berfirman Hai rasul, sampaikanlah apa yang diturunkan kepadamu dari Rabbmu. QS Al Ma`idah: 67, Dan barangsiapa mengira bahwa ia mengetahui sesuatu dikeesokan harinya, berarti ia telah dusta besar atas nama Allah. Allah berfirman Katakanlah: 'Tidak ada seorangpun di langit dan di bumi yang mengetahui perkara yang ghaib, kecuali Allah QS An Naml: 65. Abu Isa berkata; Hadits ini hasan shahih. Masruq bin Al Ajda' kun-yahnya (julukan) adalah Abu Aisyah, ia adalah Masruq bin Abdurrahman. Seperti itulah namanya disebut dalam Ad Diiwaan."}]};
